_SQLITE_CONNECT_ORIGINAL = sqlite3.connect


class _AutoClosingSQLiteConnection(sqlite3.Connection):
    """Ensure `with sqlite3.connect(...)` also closes the file descriptor."""

    def __exit__(self, exc_type, exc_val, exc_tb):
        try:
            return super().__exit__(exc_type, exc_val, exc_tb)
        finally:
            try:
                self.close()
            except sqlite3.Error:
                pass


def _sqlite_connect_autoclose(*args, **kwargs):
    kwargs.setdefault("factory", _AutoClosingSQLiteConnection)
    kwargs.setdefault("timeout", SQLITE_BUSY_TIMEOUT_SECONDS)
    conn = _SQLITE_CONNECT_ORIGINAL(*args, **kwargs)
    try:
        # Per-connection settings that improve throughput for mixed read-heavy workloads.
        conn.execute(f"PRAGMA busy_timeout = {int(SQLITE_BUSY_TIMEOUT_SECONDS * 1000)}")
        conn.execute("PRAGMA journal_mode=WAL")
        conn.execute("PRAGMA synchronous=NORMAL")
        conn.execute("PRAGMA temp_store=MEMORY")
        conn.execute(f"PRAGMA cache_size = -{int(SQLITE_CACHE_SIZE_MIB * 1024)}")
        conn.execute(f"PRAGMA mmap_size = {int(SQLITE_MMAP_SIZE_MIB * 1024 * 1024)}")
    except sqlite3.Error:
        # Keep runtime compatibility on environments with limited PRAGMA support.
        pass
    return conn


def _read_cache_get(cache_key: str) -> object | None:
    if READ_ENDPOINT_CACHE_TTL_SECONDS <= 0:
        return None
    now_ts = datetime.now(timezone.utc).timestamp()
    with _read_endpoint_cache_lock:
        cached = _read_endpoint_cache.get(cache_key)
        if not cached:
            return None
        expires_at_ts, value = cached
        if expires_at_ts <= now_ts:
            _read_endpoint_cache.pop(cache_key, None)
            return None
        return value


def _read_cache_set(cache_key: str, value: object, ttl_seconds: float | None = None) -> None:
    ttl = READ_ENDPOINT_CACHE_TTL_SECONDS if ttl_seconds is None else max(0.0, float(ttl_seconds))
    if ttl <= 0:
        return
    now_ts = datetime.now(timezone.utc).timestamp()
    expires_at_ts = now_ts + ttl
    with _read_endpoint_cache_lock:
        _read_endpoint_cache[cache_key] = (expires_at_ts, value)
        if len(_read_endpoint_cache) <= READ_ENDPOINT_CACHE_MAX_ENTRIES:
            return
        # Trim oldest-expiring entries first to keep cache bounded.
        for key, _ in sorted(_read_endpoint_cache.items(), key=lambda item: item[1][0])[: max(1, len(_read_endpoint_cache) // 8)]:
            _read_endpoint_cache.pop(key, None)


def _invalidate_alert_mutation_caches() -> None:
    _read_cache_invalidate_prefix("alerts-list:")
    _read_cache_invalidate_prefix("alerts-summary:")


def _invalidate_hosts_related_read_cache() -> None:
    global _identity_maps_invalidate_scheduled_at
    with _identity_maps_invalidate_lock:
        _identity_maps_invalidate_scheduled_at = 0.0
    _invalidate_identity_maps_cache()
    _read_cache_invalidate_prefix("hosts:")
    _read_cache_invalidate_prefix("inactive-hosts:")
    _read_cache_invalidate_prefix("system-overview:")
    _read_cache_invalidate_prefix("customer-overview:")
    _read_cache_invalidate_prefix("host-reports:")
    _read_cache_invalidate_prefix("host-reports-meta:")


def _schedule_read_cache_invalidation(prefix: str) -> None:
    safe_prefix = str(prefix or "").strip()
    if not safe_prefix:
        return
    now_ts = datetime.now(timezone.utc).timestamp()
    with _read_cache_debounce_lock:
        _read_cache_debounce_pending[safe_prefix] = now_ts


def _flush_due_read_cache_invalidations() -> None:
    now_ts = datetime.now(timezone.utc).timestamp()
    due_prefixes: list[str] = []
    with _read_cache_debounce_lock:
        for prefix, marked_at in list(_read_cache_debounce_pending.items()):
            if now_ts - marked_at >= READ_CACHE_DEBOUNCE_SECONDS:
                due_prefixes.append(prefix)
                _read_cache_debounce_pending.pop(prefix, None)
    for prefix in due_prefixes:
        _read_cache_invalidate_prefix(prefix)


def _schedule_identity_maps_cache_invalidation() -> None:
    global _identity_maps_invalidate_scheduled_at
    with _identity_maps_invalidate_lock:
        _identity_maps_invalidate_scheduled_at = time.monotonic()


def _flush_due_identity_maps_cache_invalidation() -> None:
    global _identity_maps_invalidate_scheduled_at
    scheduled_at = 0.0
    with _identity_maps_invalidate_lock:
        if _identity_maps_invalidate_scheduled_at <= 0.0:
            return
        if time.monotonic() - _identity_maps_invalidate_scheduled_at < READ_CACHE_DEBOUNCE_SECONDS:
            return
        scheduled_at = _identity_maps_invalidate_scheduled_at
        _identity_maps_invalidate_scheduled_at = 0.0
    if scheduled_at > 0.0:
        _invalidate_identity_maps_cache()
        _read_cache_invalidate_prefix("hosts:")
        _read_cache_invalidate_prefix("inactive-hosts:")
        _read_cache_invalidate_prefix("system-overview:")
