def _read_cache_invalidate_prefix(prefix: str) -> None:
    safe_prefix = str(prefix or "").strip()
    if not safe_prefix:
        return
    with _read_endpoint_cache_lock:
        for key in list(_read_endpoint_cache.keys()):
            if str(key).startswith(safe_prefix):
                _read_endpoint_cache.pop(key, None)


def _new_endpoint_timer(endpoint: str) -> dict[str, object]:
    now = time.perf_counter()
    return {
        "endpoint": str(endpoint or ""),
        "start": now,
        "last": now,
        "steps": [],
    }


def _mark_endpoint_timer(timer: dict[str, object], step_name: str) -> None:
    now = time.perf_counter()
    last = float(timer.get("last") or now)
    timer["last"] = now
    steps = timer.get("steps")
    if not isinstance(steps, list):
        return
    steps.append((str(step_name or "step"), max(0.0, (now - last) * 1000.0)))


def _finish_endpoint_timer(timer: dict[str, object], meta: str = "") -> None:
    if not ENDPOINT_TIMING_LOG_ENABLED:
        return
    endpoint = str(timer.get("endpoint") or "")
    start = float(timer.get("start") or time.perf_counter())
    total_ms = max(0.0, (time.perf_counter() - start) * 1000.0)
    if total_ms < ENDPOINT_TIMING_LOG_MIN_MS:
        return
    steps = timer.get("steps")
    step_text = ""
    if isinstance(steps, list) and steps:
        step_text = " | " + " | ".join(f"{name}:{duration:.1f}ms" for name, duration in steps)
    meta_text = f" | {meta}" if str(meta or "").strip() else ""
    line = f"[perf] {endpoint} total={total_ms:.1f}ms{step_text}{meta_text}"
    print(line)
    _append_endpoint_timing_file_log(line)


def _append_endpoint_timing_file_log(line: str) -> None:
    if not ENDPOINT_TIMING_FILE_LOG_ENABLED:
        return
    path = ENDPOINT_TIMING_FILE_LOG_PATH
    try:
        path.parent.mkdir(parents=True, exist_ok=True)
    except OSError:
        return

    timestamp = datetime.now(timezone.utc).strftime("%Y-%m-%dT%H:%M:%SZ")
    payload_line = f"{timestamp} {str(line or '').strip()}\n"

    with _endpoint_timing_file_log_lock:
        try:
            if path.exists() and path.stat().st_size >= ENDPOINT_TIMING_FILE_LOG_MAX_BYTES:
                _rotate_endpoint_timing_file_logs(path)
            with path.open("a", encoding="utf-8") as handle:
                handle.write(payload_line)
        except OSError:
            return


def _rotate_endpoint_timing_file_logs(path: Path) -> None:
    backup_count = int(ENDPOINT_TIMING_FILE_LOG_BACKUPS or 0)
    if backup_count <= 0:
        try:
            if path.exists():
                path.unlink()
        except OSError:
            pass
        return

    for idx in range(backup_count - 1, 0, -1):
        src = Path(f"{path}.{idx}")
        dst = Path(f"{path}.{idx + 1}")
        try:
            if src.exists():
                if dst.exists():
                    dst.unlink()
                src.replace(dst)
        except OSError:
            pass

    first_backup = Path(f"{path}.1")
    try:
        if path.exists():
            if first_backup.exists():
                first_backup.unlink()
            path.replace(first_backup)
    except OSError:
        pass


