def parse_int(query: dict, key: str, default: int, min_value: int, max_value: int) -> int:
    raw = query.get(key, [str(default)])[0]
    try:
        value = int(raw)
    except ValueError:
        return default
    return max(min_value, min(value, max_value))


def parse_query_flag(query: dict, key: str) -> bool:
    raw = str((query.get(key) or [""])[0] or "").strip().lower()
    return raw in {"1", "true", "yes", "on"}


def parse_positive_int(value: object, default: int = 0, max_value: int = 365) -> int:
    try:
        parsed = int(str(value or "").strip())
    except (TypeError, ValueError):
        return default
    if parsed <= 0:
        return default
    return min(parsed, max_value)


def parse_startup_rebuild_days(value: object, *, default: int = 18, max_value: int = 365) -> int:
    raw = str(value or "").strip()
    if raw == "0":
        return 0
    return parse_positive_int(raw, default=default, max_value=max_value)


def sqlite_connect() -> sqlite3.Connection:
    return sqlite3.connect(DB_PATH, timeout=DB_CONNECT_TIMEOUT_SECONDS)


def sqlite_connect_interactive() -> sqlite3.Connection:
    """Short busy timeout for login/session paths (avoid proxy/browser timeouts)."""
    conn = sqlite_connect()
    try:
        conn.execute(f"PRAGMA busy_timeout = {WEB_AUTH_BUSY_TIMEOUT_MS}")
    except sqlite3.Error:
        pass
    return conn


def sqlite_connect_read() -> sqlite3.Connection:
    """Moderate busy timeout for read-heavy API paths (fail before proxy/nginx timeout)."""
    conn = sqlite_connect()
    try:
        conn.execute(f"PRAGMA busy_timeout = {READ_ENDPOINT_BUSY_TIMEOUT_MS}")
    except sqlite3.Error:
        pass
    return conn


def sqlite_connect_maintenance() -> sqlite3.Connection:
    """Longer busy timeout for manual/scheduled DB maintenance snapshots."""
    conn = sqlite_connect()
    try:
        conn.execute(f"PRAGMA busy_timeout = {_maintenance_sqlite_busy_timeout_ms()}")
    except sqlite3.Error:
        pass
    return conn


def _sqlite_operational_error_is_lock(exc: sqlite3.OperationalError) -> bool:
    text = str(exc).lower()
    return "locked" in text or "busy" in text


def _web_login_database_locked_message() -> str:
    maintenance_hint = " (Wartungsjob aktiv)" if _changelog_maintenance_active() else ""
    return (
        "Datenbank kurz schreibgesperrt"
        f"{maintenance_hint} — z. B. Report-Ingest oder DB-Wartung, nicht Systemüberlastung. "
        "Bitte 10–20 Sekunden warten und erneut anmelden."
    )


def _purge_expired_web_sessions(conn: sqlite3.Connection) -> None:
    global _web_session_purge_last_monotonic
    now = time.monotonic()
    if now - _web_session_purge_last_monotonic < _WEB_SESSION_PURGE_INTERVAL_SECONDS:
        return
    _web_session_purge_last_monotonic = now
    session_cutoff_iso = web_session_cutoff_iso()
    conn.execute(
        "DELETE FROM web_sessions WHERE last_activity_at_utc <= ?",
        (session_cutoff_iso,),
    )


def reports_host_key_sql(alias: str = "") -> str:
    alias_text = str(alias or "").strip()
    if alias_text.endswith("."):
        alias_text = alias_text[:-1]
    prefix = f"{alias_text}." if alias_text else ""
    # No implicit hostname merge: missing host_uid gets a unique legacy key per report row.
    return (
        f"CASE WHEN COALESCE({prefix}host_uid, '') <> '' "
        f"THEN {prefix}host_uid "
        f"ELSE '__legacy_report__:' || CAST({prefix}id AS TEXT) END"
    )


def alert_host_key(hostname: object, host_uid: object = "") -> str:
    host_uid_value = str(host_uid or "").strip()
    if host_uid_value:
        return host_uid_value
    return str(hostname or "").strip()


def _hostname_cluster_key(hostname: object) -> str:
    safe = str(hostname or "").strip().lower()
    if not safe:
        return ""
    return safe.split(".", 1)[0]


def _mountpoint_keys_from_filesystems(filesystems: object) -> set[str]:
    keys: set[str] = set()
    if not isinstance(filesystems, list):
        return keys
    for fs in filesystems:
        if not isinstance(fs, dict):
            continue
        mountpoint = str(fs.get("mountpoint", "") or "").strip()
        if mountpoint:
            keys.add(normalize_mountpoint_key(mountpoint))
    return keys


def _previous_report_mountpoint_keys(
    conn: sqlite3.Connection,
    hostname: str,
    host_uid: str,
    before_report_id: int,
) -> set[str]:
    safe_hostname = str(hostname or "").strip()
    safe_host_uid = str(host_uid or "").strip()
    if not safe_hostname or before_report_id <= 0:
        return set()

    host_key_expr = reports_host_key_sql()
    row = conn.execute(
        f"""
        SELECT payload_json
        FROM reports
        WHERE hostname = ?
          AND {host_key_expr} = ?
          AND id < ?
        ORDER BY id DESC
        LIMIT 1
        """,
        (safe_hostname, safe_host_uid, before_report_id),
    ).fetchone()
    if not row:
        return set()

    payload = parse_payload_json(str(row[0] or "{}"))
    return _mountpoint_keys_from_filesystems(payload.get("filesystems", []))


def _report_filesystems_look_incomplete(
    conn: sqlite3.Connection,
    hostname: str,
    host_uid: str,
    report_id: int,
    mountpoints_seen: set[str],
) -> bool:
    if not mountpoints_seen:
        return True

    previous_keys = _previous_report_mountpoint_keys(conn, hostname, host_uid, report_id)
    if not previous_keys:
        return False
    if len(mountpoints_seen) >= len(previous_keys):
        return False
    return len(mountpoints_seen) < max(1, int(len(previous_keys) * 0.75))


def _resolve_cross_identity_open_alerts(
    conn: sqlite3.Connection,
    *,
    hostname: str,
    canonical_host_uid: str,
    now_utc: str,
    report_id: int | None = None,
    mountpoint: str | None = None,
) -> int:
    cluster_key = _hostname_cluster_key(hostname)
    canonical_key = alert_host_key(hostname, canonical_host_uid)
    if not cluster_key or not canonical_key:
        return 0

    safe_mountpoint = str(mountpoint or "").strip()
    has_open_cluster_alerts = conn.execute(
        """
        SELECT 1
        FROM alerts
        WHERE status = 'open'
          AND (
            LOWER(hostname) = ?
            OR LOWER(hostname) LIKE ?
          )
        LIMIT 1
        """,
        (cluster_key, f"{cluster_key}.%"),
    ).fetchone()
    if not has_open_cluster_alerts:
        return 0

    open_rows = conn.execute(
        """
        SELECT id, hostname, COALESCE(host_uid, ''), mountpoint
        FROM alerts
        WHERE status = 'open'
          AND (
            LOWER(hostname) = ?
            OR LOWER(hostname) LIKE ?
          )
        """,
        (cluster_key, f"{cluster_key}.%"),
    ).fetchall()

    resolved = 0
    for row in open_rows:
        alert_id = int(row[0] or 0)
        alert_hostname = str(row[1] or "").strip()
        alert_host_uid = str(row[2] or "").strip()
        alert_mountpoint = str(row[3] or "").strip()
        if not alert_id or not alert_hostname or not alert_mountpoint:
            continue
        if safe_mountpoint and alert_mountpoint != safe_mountpoint:
            continue
        if _hostname_cluster_key(alert_hostname) != cluster_key:
            continue

        alert_key = alert_host_key(alert_hostname, alert_host_uid)
        if alert_key == canonical_key:
            continue

        conn.execute(
            """
            UPDATE alerts
            SET status = 'resolved', resolved_at_utc = ?, last_seen_at_utc = ?, report_id = ?
            WHERE id = ?
            """,
            (now_utc, now_utc, report_id, alert_id),
        )
        conn.execute(
            "DELETE FROM alert_debounce WHERE host_uid = ? AND mountpoint = ?",
            (alert_key, alert_mountpoint),
        )
        resolved += 1

    return resolved


def _dedupe_open_alert_rows_by_cluster_mountpoint(rows: list[tuple]) -> list[tuple]:
    seen: set[tuple[str, str]] = set()
    deduped: list[tuple] = []
    for row in rows:
        cluster_key = _hostname_cluster_key(str(row[1] or ""))
        mountpoint_key = normalize_mountpoint_key(str(row[3] or ""))
        if not cluster_key or not mountpoint_key:
            deduped.append(row)
            continue
        dedupe_key = (cluster_key, mountpoint_key)
        if dedupe_key in seen:
            continue
        seen.add(dedupe_key)
        deduped.append(row)
    return deduped


def init_db() -> None:
    DATA_DIR.mkdir(parents=True, exist_ok=True)
    CUSTOMER_LOGOS_DIR.mkdir(parents=True, exist_ok=True)
    with sqlite3.connect(DB_PATH) as conn:
        conn.execute(
            """
            CREATE TABLE IF NOT EXISTS reports (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                received_at_utc TEXT NOT NULL,
                agent_id TEXT,
                hostname TEXT,
                host_uid TEXT,
                primary_ip TEXT,
                payload_json TEXT NOT NULL
            )
            """
        )
        existing_reports_columns = {
            str(row[1])
            for row in conn.execute("PRAGMA table_info(reports)").fetchall()
        }
        if "host_uid" not in existing_reports_columns:
            conn.execute("ALTER TABLE reports ADD COLUMN host_uid TEXT")
