def utc_now_iso() -> str:
    return datetime.now(timezone.utc).strftime("%Y-%m-%dT%H:%M:%SZ")


def minutes_since_utc_iso(value: str) -> int | None:
    raw = str(value or "").strip()
    if not raw:
        return None
    try:
        if raw.endswith("Z"):
            parsed = datetime.strptime(raw, "%Y-%m-%dT%H:%M:%SZ").replace(tzinfo=timezone.utc)
        else:
            parsed = datetime.fromisoformat(raw)
            if parsed.tzinfo is None:
                parsed = parsed.replace(tzinfo=timezone.utc)
        delta = datetime.now(timezone.utc) - parsed.astimezone(timezone.utc)
        return max(0, int(delta.total_seconds() // 60))
    except (TypeError, ValueError):
        return None


def web_session_cutoff_iso() -> str:
    return utc_minutes_ago_iso(WEB_SESSION_INACTIVITY_MINUTES)


def web_session_expires_iso() -> str:
    return (datetime.now(timezone.utc) + timedelta(minutes=WEB_SESSION_INACTIVITY_MINUTES)).strftime("%Y-%m-%dT%H:%M:%SZ")


def format_mail_datetime(value: str | None = None) -> str:
    target_tz = SCHEDULE_TIMEZONE or datetime.now().astimezone().tzinfo
    if not value:
        return datetime.now(timezone.utc).astimezone(target_tz).strftime("%d.%m.%Y %H:%M %Z")
    raw = str(value).strip()
    if not raw:
        return datetime.now(timezone.utc).astimezone(target_tz).strftime("%d.%m.%Y %H:%M %Z")
    try:
        parsed = datetime.fromisoformat(raw.replace("Z", "+00:00"))
        if parsed.tzinfo is None:
            parsed = parsed.replace(tzinfo=timezone.utc)
        return parsed.astimezone(target_tz).strftime("%d.%m.%Y %H:%M %Z")
    except ValueError:
        return raw


def utc_hours_ago_iso(hours: int) -> str:
    cutoff = datetime.now(timezone.utc) - timedelta(hours=hours)
    return cutoff.strftime("%Y-%m-%dT%H:%M:%SZ")


def utc_minutes_ago_iso(minutes: int) -> str:
    cutoff = datetime.now(timezone.utc) - timedelta(minutes=minutes)
    return cutoff.strftime("%Y-%m-%dT%H:%M:%SZ")


def read_build_version() -> str:
    try:
        value = BUILD_VERSION_PATH.read_text(encoding="utf-8").strip()
        return value or "dev"
    except OSError:
        return "dev"


def parse_payload_json(payload_json: str) -> dict:
    try:
        value = json.loads(payload_json)
        if isinstance(value, dict):
            return value
    except json.JSONDecodeError:
        return {}
    return {}


def _is_valid_ipv4(text: object) -> bool:
    raw = str(text or "").strip()
    if not raw:
        return False
    try:
        socket.inet_aton(raw)
    except OSError:
        return False
    # inet_aton accepts shortened forms; enforce dotted-quad only.
    parts = raw.split(".")
    if len(parts) != 4:
        return False
    try:
        return all(0 <= int(part) <= 255 for part in parts)
    except ValueError:
        return False


def _first_ipv4_from_value(value: object) -> str:
    if value is None:
        return ""

    if isinstance(value, (list, tuple, set)):
        for entry in value:
            found = _first_ipv4_from_value(entry)
            if found:
                return found
        return ""

    raw = str(value or "").strip()
    if not raw:
        return ""
    if _is_valid_ipv4(raw):
        return raw

    for part in re.split(r"\s+", raw):
        if _is_valid_ipv4(part):
            return part
    return ""


def _resolve_std_nic_ipv4(payload: dict, fallback_primary_ip: str = "") -> str:
    if not isinstance(payload, dict):
        return _first_ipv4_from_value(fallback_primary_ip)

    network = payload.get("network") if isinstance(payload.get("network"), dict) else {}
    default_interface = str(network.get("default_interface", "") or "").strip()
    interfaces = network.get("interfaces") if isinstance(network.get("interfaces"), list) else []

    if default_interface and interfaces:
        for iface in interfaces:
            if not isinstance(iface, dict):
                continue
            if str(iface.get("name", "") or "") != default_interface:
                continue
            candidate = _first_ipv4_from_value([
                iface.get("ipv4"),
                iface.get("ip"),
                iface.get("address"),
                iface.get("addresses"),
            ])
            if candidate:
                return candidate

    from_primary = _first_ipv4_from_value(payload.get("primary_ip") or fallback_primary_ip)
    if from_primary:
        return from_primary

    return _first_ipv4_from_value(payload.get("all_ips"))


def _derive_host_uid(payload: dict, hostname: str, agent_id: str = "", primary_ip: str = "") -> str:
    safe_hostname = str(hostname or "").strip()
    safe_agent_id = str(agent_id or "").strip()
    explicit_uid = str(payload.get("host_uid", "") or "").strip() if isinstance(payload, dict) else ""
    if explicit_uid:
        return explicit_uid

    if safe_agent_id:
        return f"{safe_hostname}::agent:{safe_agent_id}"

    resolved_ip = _resolve_std_nic_ipv4(payload if isinstance(payload, dict) else {}, str(primary_ip or ""))
    if resolved_ip:
        return f"{safe_hostname}::ip:{resolved_ip}"

    return safe_hostname


def _is_plain_hostname_host_uid(host_uid: object, hostname: object) -> bool:
    safe_host_uid = str(host_uid or "").strip()
    safe_hostname = str(hostname or "").strip()
    return bool(safe_host_uid and safe_hostname and safe_host_uid == safe_hostname)


def _host_uid_has_identity_suffix(host_uid: object) -> bool:
    return "::" in str(host_uid or "")


def _find_established_host_uid_for_ingest(
    conn: sqlite3.Connection,
    hostname: str,
    agent_id: str = "",
    primary_ip: str = "",
    payload: dict | None = None,
) -> str:
    """Return the canonical rich host_uid for an existing host, if one can be matched safely."""
    safe_hostname = str(hostname or "").strip()
    if not safe_hostname:
        return ""

    safe_agent_id = str(agent_id or "").strip()
    resolved_ip = _resolve_std_nic_ipv4(payload if isinstance(payload, dict) else {}, str(primary_ip or ""))
    ip_guard = resolved_ip or (str(primary_ip or "").strip() if _is_valid_ipv4(primary_ip) else "")

    rows = conn.execute(
        """
        SELECT host_uid,
               COUNT(*) AS report_count,
               MAX(received_at_utc) AS last_seen_utc
        FROM reports
        WHERE hostname = ?
          AND COALESCE(host_uid, '') <> ''
          AND COALESCE(host_uid, '') <> ?
          AND COALESCE(host_uid, '') LIKE '%::%'
        GROUP BY host_uid
        ORDER BY report_count DESC, last_seen_utc DESC
        """,
        (safe_hostname, safe_hostname),
    ).fetchall()

    candidates: list[tuple[str, int, str]] = []
    for row in rows:
        uid = str(row[0] or "").strip()
        report_count = int(row[1] or 0)
        if not uid or not _host_uid_has_identity_suffix(uid):
            continue
        if report_count <= INACTIVE_HOST_GHOST_MAX_REPORTS:
            continue
        candidates.append((uid, report_count, str(row[2] or "")))

    if not candidates:
        return ""

    def _identity_matches(uid: str) -> bool:
        if safe_agent_id:
            matched = conn.execute(
                """
                SELECT 1
                FROM reports
                WHERE hostname = ?
                  AND host_uid = ?
                  AND COALESCE(agent_id, '') = ?
                LIMIT 1
                """,
                (safe_hostname, uid, safe_agent_id),
            ).fetchone()
            if matched:
                return True
        if ip_guard:
            matched = conn.execute(
                """
                SELECT 1
                FROM reports
                WHERE hostname = ?
                  AND host_uid = ?
                  AND COALESCE(primary_ip, '') = ?
                LIMIT 1
                """,
                (safe_hostname, uid, ip_guard),
            ).fetchone()
            if matched:
                return True
        return False

    for uid, _, _ in candidates:
        if _identity_matches(uid):
            return uid

    if len(candidates) == 1:
        return candidates[0][0]

    return ""


def _strengthen_plain_hostname_host_uid(
    hostname: str,
    host_uid: str,
    agent_id: str = "",
    primary_ip: str = "",
    payload: dict | None = None,
) -> str:
    safe_hostname = str(hostname or "").strip()
    safe_host_uid = str(host_uid or "").strip()
    if not _is_plain_hostname_host_uid(safe_host_uid, safe_hostname):
        return safe_host_uid

    safe_agent_id = str(agent_id or "").strip()
    if safe_agent_id:
        return f"{safe_hostname}::agent:{safe_agent_id}"

    resolved_ip = _resolve_std_nic_ipv4(payload if isinstance(payload, dict) else {}, str(primary_ip or ""))
    if resolved_ip:
        return f"{safe_hostname}::ip:{resolved_ip}"

    return safe_host_uid


def _resolve_incoming_host_uid(
    conn: sqlite3.Connection,
    payload: dict,
    hostname: str,
    agent_id: str = "",
    primary_ip: str = "",
) -> str:
    incoming_host_uid = str(payload.get("host_uid", "") or "").strip()
    if not incoming_host_uid:
        incoming_host_uid = _derive_host_uid(payload, hostname, agent_id, primary_ip)

    if _is_plain_hostname_host_uid(incoming_host_uid, hostname):
        canonical_uid = _find_established_host_uid_for_ingest(
            conn,
            hostname,
            agent_id=agent_id,
            primary_ip=primary_ip,
            payload=payload,
        )
        if canonical_uid:
            return canonical_uid
        return _strengthen_plain_hostname_host_uid(
            hostname,
            incoming_host_uid,
            agent_id=agent_id,
            primary_ip=primary_ip,
            payload=payload,
        )

    canonical_uid = _find_established_host_uid_for_ingest(
        conn,
        hostname,
        agent_id=agent_id,
        primary_ip=primary_ip,
        payload=payload,
    )
    if canonical_uid and canonical_uid != incoming_host_uid:
        return canonical_uid

    return incoming_host_uid


def _repoint_report_rows_for_identity(
    conn: sqlite3.Connection,
    hostname: str,
    old_host_uid: str,
    new_host_uid: str,
) -> int:
    safe_hostname = str(hostname or "").strip()
    old_key = str(old_host_uid or "").strip()
    new_key = str(new_host_uid or "").strip()
    if not safe_hostname or not old_key or not new_key or old_key == new_key:
        return 0

    conn.execute(
        """
        UPDATE reports
        SET host_uid = ?
        WHERE hostname = ?
          AND COALESCE(host_uid, '') = ?
        """,
        (new_key, safe_hostname, old_key),
    )
    return int(conn.execute("SELECT changes()").fetchone()[0] or 0)


def _reconcile_legacy_host_uids(
    conn: sqlite3.Connection,
    payload: dict,
    hostname: str,
    incoming_host_uid: str,
    agent_id: str = "",
    primary_ip: str = "",
) -> None:
    safe_hostname = str(hostname or "").strip()
    safe_host_uid = str(incoming_host_uid or "").strip()
    safe_agent_id = str(agent_id or "").strip()
    safe_primary_ip = str(primary_ip or "").strip()
    if not safe_hostname or not safe_host_uid:
        return

    # Plain hostname fallback on a host that already has a rich identity: merge legacy rows.
    if safe_host_uid == safe_hostname:
        canonical_uid = _find_established_host_uid_for_ingest(
            conn,
            safe_hostname,
            agent_id=safe_agent_id,
            primary_ip=safe_primary_ip,
            payload=payload if isinstance(payload, dict) else {},
        )
        if not canonical_uid or canonical_uid == safe_host_uid:
            return
        _repoint_host_identity_rows(conn, safe_hostname, safe_host_uid, canonical_uid)
        _repoint_report_rows_for_identity(conn, safe_hostname, safe_host_uid, canonical_uid)
        return

    candidates: set[str] = set()
    if safe_hostname != safe_host_uid:
        candidates.add(safe_hostname)
    if safe_agent_id:
        candidates.add(f"{safe_hostname}::agent:{safe_agent_id}")

    resolved_ip = _resolve_std_nic_ipv4(payload if isinstance(payload, dict) else {}, safe_primary_ip)
    if resolved_ip:
        candidates.add(f"{safe_hostname}::ip:{resolved_ip}")
    if safe_primary_ip and _is_valid_ipv4(safe_primary_ip):
        candidates.add(f"{safe_hostname}::ip:{safe_primary_ip}")

    candidates.discard(safe_host_uid)
    if not candidates:
        return

    placeholders = ",".join(["?"] * len(candidates))
    where_parts = [
        "hostname = ?",
        f"COALESCE(host_uid, '') IN ({placeholders})",
    ]
    args: list = [safe_hostname, *sorted(candidates)]

    # Guard against false merges: require stable secondary identity axes.
    # If both agent_id and IP are available, both must match.
    ip_guard = ""
    if resolved_ip:
        ip_guard = resolved_ip
    elif safe_primary_ip and _is_valid_ipv4(safe_primary_ip):
        ip_guard = safe_primary_ip

    if safe_agent_id:
        where_parts.append("COALESCE(agent_id, '') = ?")
        args.append(safe_agent_id)

    if ip_guard:
        where_parts.append("COALESCE(primary_ip, '') = ?")
        args.append(ip_guard)

    # Reconciliation is unsafe without at least one stable secondary axis.
    if not safe_agent_id and not ip_guard:
        return

    # If multiple explicit non-legacy host_uids exist for the same hostname,
    # skip reconciliation to avoid collapsing distinct machines.
    ambiguous_values = [safe_host_uid, safe_hostname, *sorted(candidates)]
    ambiguous_placeholders = ",".join(["?"] * len(ambiguous_values))
    ambiguity_row = conn.execute(
        f"""
        SELECT 1
        FROM reports
        WHERE hostname = ?
          AND COALESCE(host_uid, '') <> ''
          AND COALESCE(host_uid, '') NOT IN ({ambiguous_placeholders})
        LIMIT 1
        """,
        (safe_hostname, *ambiguous_values),
    ).fetchone()
    repoint_targets = sorted(candidates)
    if ambiguity_row:
        repoint_targets = [
            legacy_host_uid
            for legacy_host_uid in repoint_targets
            if _should_repoint_superseded_identity(conn, safe_hostname, legacy_host_uid, safe_host_uid)
        ]
        if not repoint_targets:
            return
    else:
        # Keep legacy report rows under their original host_uid so temporary identities
        # remain visible at the bottom of the host list. Only repoint alert-related state.
        pass

    for legacy_host_uid in repoint_targets:
        _repoint_host_identity_rows(conn, safe_hostname, legacy_host_uid, safe_host_uid)


def _identity_last_report_utc(conn: sqlite3.Connection, hostname: str, host_uid: str) -> str:
    safe_hostname = str(hostname or "").strip()
    safe_host_uid = str(host_uid or "").strip()
    if not safe_hostname or not safe_host_uid:
        return ""
    host_key_expr = reports_host_key_sql()
    row = conn.execute(
        f"""
        SELECT MAX(received_at_utc)
        FROM reports
        WHERE hostname = ?
          AND {host_key_expr} = ?
        """,
        (safe_hostname, safe_host_uid),
    ).fetchone()
    return str(row[0] or "").strip() if row else ""


def _should_repoint_superseded_identity(
    conn: sqlite3.Connection,
    hostname: str,
    old_host_uid: str,
    new_host_uid: str,
) -> bool:
    old_key = str(old_host_uid or "").strip()
    new_key = str(new_host_uid or "").strip()
    if not old_key or not new_key or old_key == new_key:
        return False

    new_last = _identity_last_report_utc(conn, hostname, new_key)
    if not new_last:
        return False

    old_last = _identity_last_report_utc(conn, hostname, old_key)
    if not old_last:
        has_state = conn.execute(
            """
            SELECT 1
            FROM alerts
            WHERE COALESCE(NULLIF(host_uid, ''), hostname) = ?
            LIMIT 1
            """,
            (old_key,),
        ).fetchone()
        return bool(has_state)

    return old_last < new_last


def _repoint_host_identity_rows(
    conn: sqlite3.Connection,
    hostname: str,
    old_host_uid: str,
    new_host_uid: str,
) -> dict[str, int]:
    safe_hostname = str(hostname or "").strip()
    old_key = str(old_host_uid or "").strip()
    new_key = str(new_host_uid or "").strip()
    stats = {
        "alerts_repointed": 0,
        "alerts_resolved_duplicate": 0,
        "debounce_deleted": 0,
        "debounce_repointed": 0,
        "muted_repointed": 0,
        "heads_up_repointed": 0,
    }
    if not safe_hostname or not old_key or not new_key or old_key == new_key:
        return stats

    now_utc = utc_now_iso()
    open_old_rows = conn.execute(
        """
        SELECT id, mountpoint
        FROM alerts
        WHERE COALESCE(NULLIF(host_uid, ''), hostname) = ?
          AND status = 'open'
        """,
        (old_key,),
    ).fetchall()
    for alert_row in open_old_rows:
        alert_id = int(alert_row[0] or 0)
        mountpoint = str(alert_row[1] or "")
        duplicate_open = conn.execute(
            """
            SELECT id
            FROM alerts
            WHERE COALESCE(NULLIF(host_uid, ''), hostname) = ?
              AND mountpoint = ?
              AND status = 'open'
            LIMIT 1
            """,
            (new_key, mountpoint),
        ).fetchone()
        if duplicate_open:
            conn.execute(
                """
                UPDATE alerts
                SET status = 'resolved', resolved_at_utc = ?, last_seen_at_utc = ?
                WHERE id = ?
                """,
                (now_utc, now_utc, alert_id),
            )
            stats["alerts_resolved_duplicate"] += 1
        else:
            conn.execute(
                "UPDATE alerts SET host_uid = ? WHERE id = ?",
                (new_key, alert_id),
            )
            stats["alerts_repointed"] += 1

    conn.execute(
        """
        UPDATE alerts
        SET host_uid = ?
        WHERE COALESCE(NULLIF(host_uid, ''), hostname) = ?
          AND status <> 'open'
        """,
        (new_key, old_key),
    )

    debounce_rows = conn.execute(
        "SELECT mountpoint FROM alert_debounce WHERE host_uid = ?",
        (old_key,),
    ).fetchall()
    for debounce_row in debounce_rows:
        mountpoint = str(debounce_row[0] or "")
        duplicate_debounce = conn.execute(
            "SELECT 1 FROM alert_debounce WHERE host_uid = ? AND mountpoint = ? LIMIT 1",
            (new_key, mountpoint),
        ).fetchone()
        if duplicate_debounce:
            conn.execute(
                "DELETE FROM alert_debounce WHERE host_uid = ? AND mountpoint = ?",
                (old_key, mountpoint),
            )
            stats["debounce_deleted"] += 1
        else:
            conn.execute(
                "UPDATE alert_debounce SET host_uid = ?, hostname = ? WHERE host_uid = ? AND mountpoint = ?",
                (new_key, safe_hostname, old_key, mountpoint),
            )
            stats["debounce_repointed"] += 1

    for table_name, stat_key in (
        ("muted_alert_rules", "muted_repointed"),
        ("heads_up_suppression_rules", "heads_up_repointed"),
    ):
        conn.execute(
            f"UPDATE {table_name} SET host_uid = ? WHERE host_uid = ?",
            (new_key, old_key),
        )
        changed = int(conn.execute("SELECT changes()").fetchone()[0] or 0)
        stats[stat_key] += changed

    return stats


def _canonical_identities_by_hostname_from_rows(rows: list[tuple]) -> dict[str, dict[str, object]]:
    best_row_by_hostname = _best_report_row_by_hostname(rows)
    canonical: dict[str, dict[str, object]] = {}
    for hostname, row in best_row_by_hostname.items():
        canonical[hostname] = {
            "host_uid": str(row[0] or "").strip(),
            "last_report_time_utc": str(row[2] or "").strip(),
            "report_count": int(row[5] or 0),
        }
    return canonical


def _canonical_identities_by_hostname(conn: sqlite3.Connection) -> dict[str, dict[str, object]]:
    return _canonical_identities_by_hostname_from_rows(_latest_report_rows_by_host_key(conn))


def _canonical_identities_by_cluster_from_rows(rows: list[tuple]) -> dict[str, dict[str, object]]:
    best_row_by_cluster = _best_report_row_by_hostname_cluster(rows)
    canonical: dict[str, dict[str, object]] = {}
    for cluster_key, row in best_row_by_cluster.items():
        canonical[cluster_key] = {
            "host_uid": str(row[0] or "").strip(),
            "hostname": str(row[1] or "").strip(),
            "last_report_time_utc": str(row[2] or "").strip(),
            "report_count": int(row[5] or 0),
        }
    return canonical


def _last_seen_by_host_uid_from_rows(rows: list[tuple]) -> dict[str, str]:
    last_seen: dict[str, str] = {}
    for row in rows:
        host_uid = str(row[0] or "").strip()
        last_seen_utc = str(row[2] or "").strip()
        if not host_uid or host_uid.startswith("__legacy_report__:") or not last_seen_utc:
            continue
        existing = last_seen.get(host_uid)
        if not existing or last_seen_utc > existing:
            last_seen[host_uid] = last_seen_utc
    return last_seen


def _identity_is_older_than(identity_last_seen: str, canonical_last_seen: str) -> bool:
    safe_identity_last = str(identity_last_seen or "").strip()
    safe_canonical_last = str(canonical_last_seen or "").strip()
    if not safe_canonical_last:
        return False
    if not safe_identity_last:
        return True
    return safe_identity_last < safe_canonical_last


def _resolve_canonical_alert_identity_from_maps(
    conn: sqlite3.Connection,
    hostname: str,
    host_uid: str,
    canonical_by_hostname: dict[str, dict[str, object]],
    canonical_by_cluster: dict[str, dict[str, object]],
    last_seen_by_host_uid: dict[str, str],
) -> tuple[str, str]:
    safe_hostname = str(hostname or "").strip()
    safe_host_uid = str(host_uid or "").strip()
    if not safe_hostname or not safe_host_uid:
        return safe_hostname, safe_host_uid

    if not _is_superseded_host_identity_key(
        conn,
        safe_hostname,
        safe_host_uid,
        canonical_by_hostname,
        canonical_by_cluster,
        last_seen_by_host_uid,
    ):
        return safe_hostname, safe_host_uid

    canonical = canonical_by_hostname.get(safe_hostname)
    if canonical:
        canonical_uid = str(canonical.get("host_uid") or "").strip()
        if canonical_uid:
            return safe_hostname, canonical_uid

    cluster_key = _hostname_cluster_key(safe_hostname)
    if cluster_key:
        cluster_canonical = canonical_by_cluster.get(cluster_key)
        if cluster_canonical:
            canonical_uid = str(cluster_canonical.get("host_uid") or "").strip()
            canonical_hostname = str(cluster_canonical.get("hostname") or "").strip() or safe_hostname
            if canonical_uid:
                return canonical_hostname, canonical_uid

    return safe_hostname, safe_host_uid


def _should_resolve_alert_for_usage(
    used_percent: float,
    warning_threshold: float,
    critical_threshold: float,
    *,
    hysteresis_percent: float = ALERT_RESOLVE_HYSTERESIS_PERCENT,
) -> bool:
    if used_percent >= critical_threshold:
        return False
    resolve_below = max(0.0, warning_threshold - hysteresis_percent)
    return used_percent < resolve_below


def _alert_open_duration_minutes(created_at_utc: str, now_utc: str) -> float | None:
    created_dt = parse_utc_iso(str(created_at_utc or "").strip())
    now_dt = parse_utc_iso(str(now_utc or "").strip())
    if created_dt is None or now_dt is None:
        return None
    return max(0.0, (now_dt - created_dt).total_seconds() / 60.0)


def _is_superseded_host_identity_key(
    conn: sqlite3.Connection,
    hostname: str,
    host_uid: str,
    canonical_by_hostname: dict[str, dict[str, object]] | None = None,
    canonical_by_cluster: dict[str, dict[str, object]] | None = None,
    last_seen_by_host_uid: dict[str, str] | None = None,
) -> bool:
    safe_hostname = str(hostname or "").strip()
    safe_host_uid = str(host_uid or "").strip()
    if not safe_hostname or not safe_host_uid:
        return True
    if safe_host_uid.startswith("__legacy_report__:"):
        return True

    canonical_map = canonical_by_hostname if canonical_by_hostname is not None else _canonical_identities_by_hostname(conn)
    canonical = canonical_map.get(safe_hostname)
    if canonical:
        canonical_uid = str(canonical.get("host_uid") or "").strip()
        canonical_last = str(canonical.get("last_report_time_utc") or "").strip()
        canonical_report_count = int(canonical.get("report_count") or 0)
        if (
            _is_plain_hostname_host_uid(safe_host_uid, safe_hostname)
            and canonical_uid
            and _host_uid_has_identity_suffix(canonical_uid)
            and canonical_report_count > INACTIVE_HOST_GHOST_MAX_REPORTS
        ):
            return True
        if canonical_uid and canonical_last:
            if safe_host_uid == canonical_uid:
                return False
            if last_seen_by_host_uid is not None:
                if _identity_is_older_than(last_seen_by_host_uid.get(safe_host_uid, ""), canonical_last):
                    return True
            elif _should_repoint_superseded_identity(conn, safe_hostname, safe_host_uid, canonical_uid):
                return True

    cluster_key = _hostname_cluster_key(safe_hostname)
    if not cluster_key:
        return False

    cluster_map = canonical_by_cluster if canonical_by_cluster is not None else _canonical_identities_by_cluster(conn)
    cluster_canonical = cluster_map.get(cluster_key)
    if not cluster_canonical:
        return False

    cluster_uid = str(cluster_canonical.get("host_uid") or "").strip()
    cluster_last = str(cluster_canonical.get("last_report_time_utc") or "").strip()
    if not cluster_uid:
        return False
    if safe_host_uid == cluster_uid:
        return False

    if last_seen_by_host_uid is not None:
        return _identity_is_older_than(last_seen_by_host_uid.get(safe_host_uid, ""), cluster_last)

    cluster_hostname = str(cluster_canonical.get("hostname") or "").strip() or safe_hostname
    return _should_repoint_superseded_identity(conn, cluster_hostname, safe_host_uid, cluster_uid)


def cleanup_superseded_host_identities(conn: sqlite3.Connection) -> dict[str, int]:
    latest_identity_rows = _latest_report_rows_by_host_key(conn)
    canonical_by_hostname = _canonical_identities_by_hostname_from_rows(latest_identity_rows)
    canonical_by_cluster = _canonical_identities_by_cluster_from_rows(latest_identity_rows)
    last_seen_by_host_uid = _last_seen_by_host_uid_from_rows(latest_identity_rows)
    host_key_expr = reports_host_key_sql()
    identity_rows = conn.execute(
        f"""
        SELECT DISTINCT hostname, identity_key
        FROM (
            SELECT COALESCE(hostname, '') AS hostname, {host_key_expr} AS identity_key
            FROM reports
            UNION
            SELECT COALESCE(hostname, ''), COALESCE(NULLIF(host_uid, ''), hostname) AS identity_key
            FROM alerts
        )
        WHERE COALESCE(hostname, '') <> ''
          AND COALESCE(identity_key, '') <> ''
        """
    ).fetchall()

    totals = {
        "hosts_scanned": len(canonical_by_hostname),
        "identities_scanned": 0,
        "identities_repointed": 0,
        "alerts_repointed": 0,
        "alerts_resolved_duplicate": 0,
        "debounce_deleted": 0,
        "debounce_repointed": 0,
        "orphan_reports_deleted": 0,
        "reports_repointed": 0,
    }

    processed_pairs: set[tuple[str, str]] = set()
    for row in identity_rows:
        hostname = str(row[0] or "").strip()
        identity_key = str(row[1] or "").strip()
        if not hostname or not identity_key or identity_key.startswith("__legacy_report__:"):
            continue
        totals["identities_scanned"] += 1

        canonical_uid = ""
        canonical_hostname = hostname
        canonical_last = ""
        cluster_canonical = None
        canonical = canonical_by_hostname.get(hostname)
        if canonical:
            canonical_uid = str(canonical.get("host_uid") or "").strip()
            canonical_hostname = hostname
            canonical_last = str(canonical.get("last_report_time_utc") or "").strip()
        else:
            cluster_key = _hostname_cluster_key(hostname)
            cluster_canonical = canonical_by_cluster.get(cluster_key) if cluster_key else None
            if cluster_canonical:
                canonical_uid = str(cluster_canonical.get("host_uid") or "").strip()
                canonical_hostname = str(cluster_canonical.get("hostname") or "").strip() or hostname
                canonical_last = str(cluster_canonical.get("last_report_time_utc") or "").strip()

        if not canonical_uid or identity_key == canonical_uid:
            continue
        if not _identity_is_older_than(last_seen_by_host_uid.get(identity_key, ""), canonical_last):
            continue

        pair = (hostname, identity_key)
        if pair in processed_pairs:
            continue
        processed_pairs.add(pair)

        repoint_stats = _repoint_host_identity_rows(conn, canonical_hostname, identity_key, canonical_uid)
        totals["identities_repointed"] += 1
        totals["alerts_repointed"] += int(repoint_stats.get("alerts_repointed", 0) or 0)
        totals["alerts_resolved_duplicate"] += int(repoint_stats.get("alerts_resolved_duplicate", 0) or 0)
        totals["debounce_deleted"] += int(repoint_stats.get("debounce_deleted", 0) or 0)
        totals["debounce_repointed"] += int(repoint_stats.get("debounce_repointed", 0) or 0)

        if _is_plain_hostname_host_uid(identity_key, hostname):
            totals["reports_repointed"] += _repoint_report_rows_for_identity(
                conn,
                hostname,
                identity_key,
                canonical_uid,
            )
        else:
            conn.execute(
                f"DELETE FROM reports WHERE hostname = ? AND {host_key_expr} = ?",
                (hostname, identity_key),
            )
            totals["orphan_reports_deleted"] += int(conn.execute("SELECT changes()").fetchone()[0] or 0)

    return totals


def _is_ghost_identity_report_count(report_count: object) -> bool:
    count = int(report_count or 0)
    return count > 0 and count <= INACTIVE_HOST_GHOST_MAX_REPORTS


def _identity_row_is_stronger(new_row: tuple, existing_row: tuple) -> bool:
    new_count = int(new_row[5] or 0)
    existing_count = int(existing_row[5] or 0)
    if new_count != existing_count:
        return new_count > existing_count
    return str(new_row[2] or "").strip() > str(existing_row[2] or "").strip()


def _established_identity_maps_from_rows(
    rows: list[tuple],
) -> tuple[dict[str, tuple], dict[str, tuple]]:
    """Map hostname/cluster to the strongest non-ghost identity row."""
    by_hostname: dict[str, tuple] = {}
    by_cluster: dict[str, tuple] = {}
    for row in rows:
        host_uid = str(row[0] or "").strip()
        hostname = str(row[1] or "").strip()
        if not host_uid or not hostname or host_uid.startswith("__legacy_report__:"):
            continue
        if not _is_ghost_identity_report_count(row[5]):
            existing_hostname = by_hostname.get(hostname)
            if not existing_hostname or _identity_row_is_stronger(row, existing_hostname):
                by_hostname[hostname] = row
            cluster_key = _hostname_cluster_key(hostname)
            if cluster_key:
                existing_cluster = by_cluster.get(cluster_key)
                if not existing_cluster or _identity_row_is_stronger(row, existing_cluster):
                    by_cluster[cluster_key] = row
    return by_hostname, by_cluster


def cleanup_ghost_host_identities(
    conn: sqlite3.Connection,
    *,
    min_age_hours: int | None = None,
    dry_run: bool = False,
) -> dict[str, object]:
    """Remove stale temporary host identities (wrong UID, few reports, no follow-up)."""
    safe_min_age_hours = max(1, min(720, int(min_age_hours or GHOST_HOST_CLEANUP_MIN_AGE_HOURS)))
    cutoff_iso = utc_hours_ago_iso(safe_min_age_hours)
    rows = _latest_report_rows_by_host_key(conn)
    established_by_hostname, established_by_cluster = _established_identity_maps_from_rows(rows)

    ghosts_scanned = 0
    ghosts_targeted = 0
    reports_deleted = 0
    alerts_deleted = 0
    deleted_sample: list[dict[str, str]] = []

    for row in rows:
        host_uid = str(row[0] or "").strip()
        hostname = str(row[1] or "").strip()
        last_seen_utc = str(row[2] or "").strip()
        report_count = int(row[5] or 0)
        if not host_uid or not hostname or host_uid.startswith("__legacy_report__:"):
            continue
        if not _is_ghost_identity_report_count(report_count):
            continue

        ghosts_scanned += 1
        if not last_seen_utc or last_seen_utc >= cutoff_iso:
            continue

        delete_reason = ""
        established_hostname_row = established_by_hostname.get(hostname)
        if established_hostname_row:
            established_uid = str(established_hostname_row[0] or "").strip()
            if established_uid and established_uid != host_uid:
                delete_reason = "superseded_by_hostname"
        if not delete_reason:
            cluster_key = _hostname_cluster_key(hostname)
            established_cluster_row = established_by_cluster.get(cluster_key) if cluster_key else None
            if established_cluster_row:
                established_uid = str(established_cluster_row[0] or "").strip()
                if established_uid and established_uid != host_uid:
                    delete_reason = "superseded_by_cluster"
        if not delete_reason:
            delete_reason = "orphan_ghost"

        ghosts_targeted += 1
        if len(deleted_sample) < 40:
            deleted_sample.append(
                {
                    "hostname": hostname,
                    "host_uid": host_uid,
                    "reason": delete_reason,
                    "report_count": str(report_count),
                    "last_seen_utc": last_seen_utc,
                }
            )
        if dry_run:
            continue

        deleted = delete_host_card_data(conn, hostname, host_uid)
        reports_deleted += int(deleted.get("reports", 0) or 0)
        alerts_deleted += int(deleted.get("alerts", 0) or 0)

    if not dry_run and ghosts_targeted > 0:
        _invalidate_identity_maps_cache()

    return {
        "ghosts_scanned": ghosts_scanned,
        "ghosts_targeted": ghosts_targeted,
        "ghosts_deleted": 0 if dry_run else ghosts_targeted,
        "reports_deleted": reports_deleted,
        "alerts_deleted": alerts_deleted,
        "min_age_hours": safe_min_age_hours,
        "dry_run": dry_run,
        "deleted_sample": deleted_sample,
    }


def _ensure_reports_host_uid_support(conn: sqlite3.Connection) -> None:
    existing_reports_columns = {
        str(row[1])
        for row in conn.execute("PRAGMA table_info(reports)").fetchall()
    }
    if "host_uid" not in existing_reports_columns:
        conn.execute("ALTER TABLE reports ADD COLUMN host_uid TEXT")

    conn.execute("CREATE INDEX IF NOT EXISTS idx_reports_host_uid_id ON reports(host_uid, id)")
    conn.execute(
        """
        CREATE INDEX IF NOT EXISTS idx_reports_host_key_id
        ON reports(COALESCE(NULLIF(host_uid, ''), hostname), id)
        """
    )
    conn.execute(
        """
        CREATE INDEX IF NOT EXISTS idx_reports_host_key_received
        ON reports(COALESCE(NULLIF(host_uid, ''), hostname), received_at_utc)
        """
    )
    conn.execute(
        """
        CREATE INDEX IF NOT EXISTS idx_reports_host_agent_ip_uid
        ON reports(hostname, agent_id, primary_ip, host_uid, id)
        """
    )
    conn.execute(
        """
        CREATE INDEX IF NOT EXISTS idx_reports_host_uid_received
        ON reports(host_uid, received_at_utc, id)
        WHERE COALESCE(host_uid, '') <> ''
        """
    )
    conn.execute(
        """
        CREATE INDEX IF NOT EXISTS idx_reports_hostname_received_id
        ON reports(hostname, received_at_utc, id)
        """
    )
    conn.execute(
        """
        CREATE INDEX IF NOT EXISTS idx_reports_legacy_no_uid_id
        ON reports(id)
        WHERE COALESCE(host_uid, '') = ''
        """
    )


def _backfill_report_host_uids(conn: sqlite3.Connection, batch_size: int = 1000) -> None:
    _ensure_reports_host_uid_support(conn)
    safe_batch_size = max(100, min(int(batch_size or 1000), 5000))
    last_report_id = 0
    while True:
        rows = conn.execute(
            """
            SELECT id, COALESCE(hostname, ''), COALESCE(agent_id, ''), COALESCE(primary_ip, ''), COALESCE(payload_json, '{}')
            FROM reports
            WHERE COALESCE(host_uid, '') = ''
              AND id > ?
            ORDER BY id ASC
            LIMIT ?
            """,
            (last_report_id, safe_batch_size),
        ).fetchall()
        if not rows:
            return

        updates: list[tuple[str, int]] = []
        for row in rows:
            report_id = int(row[0] or 0)
            hostname = str(row[1] or "").strip()
            agent_id = str(row[2] or "").strip()
            primary_ip = str(row[3] or "").strip()
            payload = parse_payload_json(str(row[4] or "{}"))
            host_uid = _resolve_incoming_host_uid(
                conn,
                payload,
                hostname,
                agent_id=agent_id,
                primary_ip=primary_ip,
            )
            if host_uid:
                updates.append((host_uid, report_id))

        if updates:
            conn.executemany("UPDATE reports SET host_uid = ? WHERE id = ?", updates)

        last_report_id = int(rows[-1][0] or last_report_id)
        conn.commit()
        if len(rows) < safe_batch_size:
            return


def _repair_report_host_uids(conn: sqlite3.Connection, batch_size: int = 1000) -> dict:
    _ensure_reports_host_uid_support(conn)
    safe_batch_size = max(100, min(int(batch_size or 1000), 5000))
    host_key_expr = reports_host_key_sql()
    before_host_cards = int(
        conn.execute(
            f"SELECT COUNT(*) FROM (SELECT 1 FROM reports GROUP BY {host_key_expr})"
        ).fetchone()[0]
        or 0
    )

    scanned_reports = 0
    updated_reports = 0
    changed_hostnames: set[str] = set()
    last_report_id = 0

    while True:
        rows = conn.execute(
            """
            SELECT id,
                   COALESCE(hostname, ''),
                   COALESCE(agent_id, ''),
                   COALESCE(primary_ip, ''),
                   COALESCE(payload_json, '{}'),
                '' AS latest_display_name,
            FROM reports
            WHERE id > ?
            ORDER BY id ASC
            LIMIT ?
            """,
            (last_report_id, safe_batch_size),
        ).fetchall()
        if not rows:
            break

        scanned_reports += len(rows)
        updates: list[tuple[str, int]] = []
        for row in rows:
            report_id = int(row[0] or 0)
            hostname = str(row[1] or "").strip()
            agent_id = str(row[2] or "").strip()
            primary_ip = str(row[3] or "").strip()
            payload = parse_payload_json(str(row[4] or "{}"))
            current_uid = str(payload.get("host_uid", "") or "").strip() or str(row[5] or "").strip()
            expected_uid = _resolve_incoming_host_uid(
                conn,
                payload,
                hostname,
                agent_id=agent_id,
                primary_ip=primary_ip,
            )
            if expected_uid and expected_uid != current_uid:
                updates.append((expected_uid, report_id))
                if hostname:
                    changed_hostnames.add(hostname)

        if updates:
            conn.executemany("UPDATE reports SET host_uid = ? WHERE id = ?", updates)
            updated_reports += len(updates)

        last_report_id = int(rows[-1][0] or last_report_id)
        if len(rows) < safe_batch_size:
            break

    after_host_cards = int(
        conn.execute(
            f"SELECT COUNT(*) FROM (SELECT 1 FROM reports GROUP BY {host_key_expr})"
        ).fetchone()[0]
        or 0
    )

    return {
        "status": "ok",
        "scanned_reports": scanned_reports,
        "updated_reports": updated_reports,
        "before_host_cards": before_host_cards,
        "after_host_cards": after_host_cards,
        "delta_host_cards": after_host_cards - before_host_cards,
        "changed_hostnames_count": len(changed_hostnames),
        "changed_hostnames_sample": sorted(changed_hostnames)[:30],
    }


def normalize_sap_b1_version_map_entries(entries_raw: object) -> list[dict[str, str]]:
    if not isinstance(entries_raw, list):
        return []
    normalized: list[dict[str, str]] = []
    seen_builds: set[str] = set()
    for item in entries_raw:
        if not isinstance(item, dict):
            continue
        build = str(item.get("build", "") or "").strip()
        if not build or build in seen_builds:
            continue
        seen_builds.add(build)
        normalized.append(
            {
                "build": build,
                "feature_pack": str(item.get("feature_pack", "") or "").strip(),
                "patch_level": str(item.get("patch_level", "") or "").strip(),
                "release_date": str(item.get("release_date", "") or "").strip(),
            }
        )
    return normalized


def load_sap_b1_version_map_entries() -> list[dict[str, str]]:
    try:
        raw = SAP_B1_VERSION_MAP_PATH.read_text(encoding="utf-8")
    except OSError:
        return []
    try:
        parsed = json.loads(raw)
    except json.JSONDecodeError:
        return []
    return normalize_sap_b1_version_map_entries(parsed)


def save_sap_b1_version_map_entries(entries_raw: object) -> list[dict[str, str]]:
    normalized = normalize_sap_b1_version_map_entries(entries_raw)
    DATA_DIR.mkdir(parents=True, exist_ok=True)
    SAP_B1_VERSION_MAP_PATH.write_text(
        json.dumps(normalized, ensure_ascii=True, indent=2) + "\n",
        encoding="utf-8",
    )
    return normalized


def normalize_sap_license_type_map_entries(entries_raw: object) -> list[dict[str, object]]:
    if not isinstance(entries_raw, list):
        return []
    normalized: list[dict[str, object]] = []
    seen_patterns: set[str] = set()
    for item in entries_raw:
        if not isinstance(item, dict):
            continue
        match_text = str(item.get("match_text", "") or "").strip()
        display_name = str(item.get("display_name", "") or "").strip()
        if not match_text:
            continue
        raw_visible = item.get("visible", None)
        if raw_visible is None:
            # Migration default: only genuinely translated rows are visible.
            visible = bool(display_name) and display_name.strip().casefold() != match_text.casefold()
        else:
            visible = bool(raw_visible)
        if not visible and display_name.strip().casefold() == match_text.casefold():
            # Keep non-translated rows visually empty in the editor/UI.
            display_name = ""
        dedupe_key = match_text.upper()
        if dedupe_key in seen_patterns:
            continue
        seen_patterns.add(dedupe_key)
        normalized.append(
            {
                "match_text": match_text,
                "display_name": display_name,
                "visible": visible,
            }
        )
    return normalized


def load_sap_license_type_map_entries() -> list[dict[str, object]]:
    try:
        raw = SAP_LICENSE_TYPE_MAP_PATH.read_text(encoding="utf-8")
    except OSError:
        return normalize_sap_license_type_map_entries(DEFAULT_SAP_LICENSE_TYPE_MAP_ENTRIES)
    try:
        parsed = json.loads(raw)
    except json.JSONDecodeError:
        return normalize_sap_license_type_map_entries(DEFAULT_SAP_LICENSE_TYPE_MAP_ENTRIES)
    normalized = normalize_sap_license_type_map_entries(parsed)
    if normalized:
        return normalized
    return normalize_sap_license_type_map_entries(DEFAULT_SAP_LICENSE_TYPE_MAP_ENTRIES)


def save_sap_license_type_map_entries(entries_raw: object) -> list[dict[str, object]]:
    normalized = normalize_sap_license_type_map_entries(entries_raw)
    DATA_DIR.mkdir(parents=True, exist_ok=True)
    SAP_LICENSE_TYPE_MAP_PATH.write_text(
        json.dumps(normalized, ensure_ascii=True, indent=2) + "\n",
        encoding="utf-8",
    )
    return normalized


def auto_sync_discovered_license_types(payload: object) -> None:
    """Auto-discover new SAP license types from agent report and add them to matrix."""
    if not isinstance(payload, dict):
        return
    
    sap_license = payload.get("sap_license")
    if not isinstance(sap_license, dict):
        return
    
    focus_license_types = sap_license.get("focus_license_types")
    if not isinstance(focus_license_types, list):
        return
    
    # Extract discovered license types
    discovered_types = set()
    for item in focus_license_types:
        if isinstance(item, dict):
            license_type = str(item.get("license_type", "")).strip()
            if license_type:
                discovered_types.add(license_type)
    
    if not discovered_types:
        return
    
    # Load current matrix
    current_matrix = load_sap_license_type_map_entries()
    existing_match_texts = {entry.get("match_text", "").upper() for entry in current_matrix}
    
    # Find new types not yet in matrix
    new_entries = []
    for discovered_type in sorted(discovered_types):
        if discovered_type.upper() not in existing_match_texts:
            new_entries.append({
                "match_text": discovered_type,
                "display_name": "",
                "visible": False,
            })
    
    if not new_entries:
        return
    
    # Add new entries to matrix and save
    updated_matrix = current_matrix + new_entries
    try:
        save_sap_license_type_map_entries(updated_matrix)
    except OSError:
        pass  # Silent failure, don't block report storage


def _backup_job_meta_path(job_id: str) -> Path:
    safe_job_id = re.sub(r"[^A-Za-z0-9_-]", "", str(job_id or "").strip())
    return BACKUP_TEMP_DIR / f"{safe_job_id}.meta.json"


def _write_backup_job_meta(job_id: str, job: dict[str, str]) -> None:
    safe_job_id = str(job_id or "").strip()
    if not safe_job_id:
        return
    try:
        BACKUP_TEMP_DIR.mkdir(parents=True, exist_ok=True)
        payload = {
            "job_id": safe_job_id,
            "status": str(job.get("status") or ""),
            "created_at_utc": str(job.get("created_at_utc") or ""),
            "updated_at_utc": str(job.get("updated_at_utc") or ""),
            "started_at_utc": str(job.get("started_at_utc") or ""),
            "file_path": str(job.get("file_path") or ""),
            "filename": str(job.get("filename") or ""),
            "access_token": str(job.get("access_token") or ""),
            "error": str(job.get("error") or ""),
        }
        meta_path = _backup_job_meta_path(safe_job_id)
        meta_path.write_text(json.dumps(payload, ensure_ascii=True, separators=(",", ":")), encoding="utf-8")
    except OSError:
        pass


def _read_backup_job_meta(job_id: str) -> dict[str, str] | None:
    safe_job_id = str(job_id or "").strip()
    if not safe_job_id:
        return None
    meta_path = _backup_job_meta_path(safe_job_id)
    if not meta_path.is_file():
        return None
    try:
        payload = json.loads(meta_path.read_text(encoding="utf-8"))
    except (OSError, json.JSONDecodeError, TypeError, ValueError):
        return None
    if not isinstance(payload, dict):
        return None
    return {
        "status": str(payload.get("status") or ""),
        "created_at_utc": str(payload.get("created_at_utc") or ""),
        "updated_at_utc": str(payload.get("updated_at_utc") or ""),
        "started_at_utc": str(payload.get("started_at_utc") or ""),
        "file_path": str(payload.get("file_path") or ""),
        "filename": str(payload.get("filename") or ""),
        "access_token": str(payload.get("access_token") or ""),
        "error": str(payload.get("error") or ""),
    }


def _delete_backup_job_meta(job_id: str) -> None:
    meta_path = _backup_job_meta_path(job_id)
    try:
        if meta_path.exists():
            meta_path.unlink()
    except OSError:
        pass


def _sqlite_backup_file_looks_valid(path: Path) -> bool:
    if not path.is_file():
        return False
    try:
        if path.stat().st_size < 1024:
            return False
        with sqlite3.connect(str(path)) as conn:
            conn.execute("SELECT 1 FROM sqlite_schema LIMIT 1")
        return True
    except (OSError, sqlite3.Error):
        return False


def _reconcile_backup_job_after_restart(job_id: str, job: dict[str, str]) -> dict[str, str]:
    status = str(job.get("status") or "")
    if status not in {"running", "ready"}:
        return job
    backup_path = Path(str(job.get("file_path") or ""))
    if status == "ready":
        if _sqlite_backup_file_looks_valid(backup_path):
            return job
        failed = dict(job)
        failed["status"] = "error"
        failed["error"] = "backup file missing or invalid"
        failed["updated_at_utc"] = utc_now_iso()
        return failed
    if status != "running":
        return job
    if _sqlite_backup_file_looks_valid(backup_path):
        reconciled = dict(job)
        reconciled["status"] = "ready"
        reconciled["error"] = ""
        reconciled["updated_at_utc"] = utc_now_iso()
        print(f"[backup] recovered completed job {job_id} from disk after process restart")
        return reconciled
    if backup_path.is_file():
        try:
            backup_path.unlink()
        except OSError:
            pass
    interrupted = dict(job)
    interrupted["status"] = "error"
    interrupted["error"] = "backup interrupted (server restart or low memory) — please retry"
    interrupted["updated_at_utc"] = utc_now_iso()
    print(f"[backup] marked interrupted job {job_id} after process restart")
    return interrupted


def _remember_backup_job(job_id: str, job: dict[str, str]) -> None:
    safe_job_id = str(job_id or "").strip()
    if not safe_job_id:
        return
    with _backup_jobs_lock:
        _backup_jobs[safe_job_id] = dict(job)
    _write_backup_job_meta(safe_job_id, job)


def _restore_backup_jobs_from_disk() -> None:
    try:
        BACKUP_TEMP_DIR.mkdir(parents=True, exist_ok=True)
        meta_paths = sorted(BACKUP_TEMP_DIR.glob("*.meta.json"))
    except OSError:
        return
    restored = 0
    for meta_path in meta_paths:
        if not meta_path.name.endswith(".meta.json"):
            continue
        job_id = meta_path.name[: -len(".meta.json")]
        job = _read_backup_job_meta(job_id)
        if not isinstance(job, dict):
            continue
        job = _reconcile_backup_job_after_restart(job_id, job)
        _remember_backup_job(job_id, job)
        restored += 1
    if restored > 0:
        print(f"[backup] restored {restored} job(s) from disk")


def _cleanup_backup_jobs(max_age_minutes: int = 30) -> None:
    cutoff = datetime.now(timezone.utc) - timedelta(minutes=max_age_minutes)
    remove_ids: list[str] = []
    with _backup_jobs_lock:
        for job_id, job in _backup_jobs.items():
            created_raw = str(job.get("created_at_utc", "") or "").strip()
            try:
                created_at = datetime.fromisoformat(created_raw.replace("Z", "+00:00"))
            except ValueError:
                created_at = datetime.now(timezone.utc)
            if created_at < cutoff:
                remove_ids.append(job_id)

        for job_id in remove_ids:
            file_path = Path(str(_backup_jobs.get(job_id, {}).get("file_path", "") or ""))
            if file_path.exists():
                try:
                    file_path.unlink()
                except OSError:
                    pass
            _backup_jobs.pop(job_id, None)
            _delete_backup_job_meta(job_id)


def _get_backup_job_if_token_valid(job_id: str, job_token: str) -> dict[str, str] | None:
    safe_job_id = str(job_id or "").strip()
    safe_job_token = str(job_token or "").strip()
    if not safe_job_id or not safe_job_token:
        return None
    with _backup_jobs_lock:
        job = _backup_jobs.get(safe_job_id)
    if not isinstance(job, dict):
        job = _read_backup_job_meta(safe_job_id)
        if isinstance(job, dict):
            job = _reconcile_backup_job_after_restart(safe_job_id, job)
            _remember_backup_job(safe_job_id, job)
    if not isinstance(job, dict):
        return None
    if not secrets.compare_digest(str(job.get("access_token") or ""), safe_job_token):
        return None
    return dict(job)


def _create_database_backup_job() -> dict:
    _cleanup_backup_jobs()
    BACKUP_TEMP_DIR.mkdir(parents=True, exist_ok=True)

    if not DB_PATH.exists() or not DB_PATH.is_file():
        return {"status": "error", "error": "database file not found"}

    now_utc = datetime.now(timezone.utc)
    timestamp = now_utc.strftime("%Y%m%d-%H%M%S")
    job_id = secrets.token_urlsafe(10)
    job_access_token = secrets.token_urlsafe(24)
    backup_filename = f"monitoring-backup-{timestamp}.db"
    backup_path = BACKUP_TEMP_DIR / f"{job_id}.db"

    created_at = now_utc.strftime("%Y-%m-%dT%H:%M:%SZ")
    _remember_backup_job(
        job_id,
        {
            "status": "running",
            "created_at_utc": created_at,
            "updated_at_utc": created_at,
            "started_at_utc": created_at,
            "file_path": str(backup_path),
            "filename": backup_filename,
            "access_token": job_access_token,
            "error": "",
        },
    )

    def _run_job() -> None:
        backup_busy_ms = max(
            30000,
            min(300000, int(os.getenv("MONITORING_BACKUP_BUSY_TIMEOUT_MS", "120000") or "120000")),
        )
        try:
            # Read-only source URI avoids write-lock contention with live ingest/session traffic.
            src_uri = f"file:{DB_PATH.resolve()}?mode=ro"
            with sqlite3.connect(src_uri, uri=True) as src_conn:
                src_conn.execute(f"PRAGMA busy_timeout = {backup_busy_ms}")
                with sqlite3.connect(backup_path) as dst_conn:
                    dst_conn.execute(f"PRAGMA busy_timeout = {backup_busy_ms}")
                    # Smaller page batches reduce write-lock pressure on the live DB.
                    src_conn.backup(dst_conn, pages=256, sleep=0.15)
            with _backup_jobs_lock:
                job = _backup_jobs.get(job_id)
            if isinstance(job, dict):
                ready_job = dict(job)
                ready_job["status"] = "ready"
                ready_job["error"] = ""
                ready_job["updated_at_utc"] = datetime.now(timezone.utc).strftime("%Y-%m-%dT%H:%M:%SZ")
                _remember_backup_job(job_id, ready_job)
        except Exception as exc:
            with _backup_jobs_lock:
                job = _backup_jobs.get(job_id)
            if isinstance(job, dict):
                error_job = dict(job)
                error_job["status"] = "error"
                error_job["error"] = f"backup copy failed: {exc}"
                error_job["updated_at_utc"] = datetime.now(timezone.utc).strftime("%Y-%m-%dT%H:%M:%SZ")
                _remember_backup_job(job_id, error_job)
            if backup_path.exists():
                try:
                    backup_path.unlink()
                except OSError:
                    pass

    threading.Thread(target=_run_job, daemon=True).start()
    return {
        "status": "started",
        "job_id": job_id,
        "job_token": job_access_token,
        "filename": backup_filename,
    }


def _restore_database_from_bytes(raw_bytes: bytes) -> tuple[bool, str]:
    if not raw_bytes:
        return False, "empty upload"
    if not raw_bytes.startswith(b"SQLite format 3"):
        return False, "uploaded file is not a valid SQLite database"

    DATA_DIR.mkdir(parents=True, exist_ok=True)
    temp_restore_path = DATA_DIR / f"restore-{secrets.token_hex(8)}.db"
    final_restore_path = DATA_DIR / f"restore-final-{secrets.token_hex(8)}.db"
    backup_current_path = DATA_DIR / f"monitoring.db.pre-restore-{datetime.now(timezone.utc).strftime('%Y%m%d-%H%M%S')}.bak"

    try:
        # Write uploaded bytes to temp file
        temp_restore_path.write_bytes(raw_bytes)
        
        # Use VACUUM INTO to create a clean, non-WAL copy to avoid corruption
        # when WAL files are missing or incomplete
        try:
            conn = sqlite3.connect(str(temp_restore_path))
            conn.execute(f"VACUUM INTO '{final_restore_path}'")
            conn.close()
            cleaned_restore_path = final_restore_path
        except (sqlite3.DatabaseError, sqlite3.OperationalError):
            # If VACUUM INTO fails, use temp file directly (might still be valid)
            cleaned_restore_path = temp_restore_path
        
        # Backup current database if it exists
        if DB_PATH.exists():
            shutil.copy2(DB_PATH, backup_current_path)
            # Also backup any WAL/SHM files that exist
            for suffix in ("-wal", "-shm"):
                wal_path = DB_PATH.parent / f"{DB_PATH.name}{suffix}"
                if wal_path.exists():
                    backup_wal_path = DATA_DIR / f"monitoring.db{suffix}.pre-restore-{datetime.now(timezone.utc).strftime('%Y%m%d-%H%M%S')}.bak"
                    try:
                        shutil.copy2(wal_path, backup_wal_path)
                    except OSError:
                        pass
        
        # Replace old DB with cleaned one
        os.replace(cleaned_restore_path, DB_PATH)
        
        # Clean up any old WAL/SHM files from the previous session
        for suffix in ("-wal", "-shm"):
            old_wal = DB_PATH.parent / f"{DB_PATH.name}{suffix}"
            if old_wal.exists():
                try:
                    old_wal.unlink()
                except OSError:
                    pass
        
        return True, str(backup_current_path.name)
    except OSError as exc:
        return False, f"restore failed: {exc}"
    finally:
        # Clean up temp files
        for path in (temp_restore_path, final_restore_path):
            if path.exists():
                try:
                    path.unlink()
                except OSError:
                    pass


def _normalize_backup_target_dir(value: object) -> str:
    raw = str(value or "").strip().replace("\\", "/")
    if not raw:
        return AUTO_BACKUP_DIR.name
    if raw.startswith("/") or ".." in raw:
        return AUTO_BACKUP_DIR.name
    if not re.fullmatch(r"[A-Za-z0-9._/-]+", raw):
        return AUTO_BACKUP_DIR.name
    return raw.strip("/") or AUTO_BACKUP_DIR.name


def _coerce_int(value: object, fallback: int, minimum: int, maximum: int) -> int:
    try:
        num = int(str(value or "").strip())
    except (TypeError, ValueError):
        num = fallback
    return max(minimum, min(maximum, num))


def get_backup_automation_settings(conn: sqlite3.Connection) -> dict[str, object]:
    row = conn.execute(
        """
        SELECT local_enabled,
               local_interval_hours,
               local_retention_days,
               local_retention_max_files,
               local_target_dir,
               sftp_enabled,
               sftp_host,
               sftp_port,
               sftp_username,
               sftp_remote_path,
               sftp_auth_mode,
               sftp_key_path,
               sftp_password,
               updated_at_utc
        FROM backup_automation_settings
        WHERE id = 1
        """
    ).fetchone()
    if not row:
        now_utc = utc_now_iso()
        conn.execute(
            """
            INSERT INTO backup_automation_settings (
                id,
                local_enabled,
                local_interval_hours,
                local_retention_days,
                local_retention_max_files,
                local_target_dir,
                sftp_enabled,
                sftp_host,
                sftp_port,
                sftp_username,
                sftp_remote_path,
                sftp_auth_mode,
                sftp_key_path,
                sftp_password,
                updated_at_utc
            ) VALUES (1, ?, ?, ?, ?, ?, 0, '', 22, '', '', 'key', '', '', ?)
            """,
            (
                1 if AUTO_BACKUP_DEFAULT_ENABLED else 0,
                AUTO_BACKUP_DEFAULT_INTERVAL_HOURS,
                AUTO_BACKUP_DEFAULT_RETENTION_DAYS,
                AUTO_BACKUP_DEFAULT_RETENTION_MAX_FILES,
                AUTO_BACKUP_DIR.name,
                now_utc,
            ),
        )
        row = conn.execute(
            """
            SELECT local_enabled,
                   local_interval_hours,
                   local_retention_days,
                   local_retention_max_files,
                   local_target_dir,
                   sftp_enabled,
                   sftp_host,
                   sftp_port,
                   sftp_username,
                   sftp_remote_path,
                   sftp_auth_mode,
                   sftp_key_path,
                   sftp_password,
                   updated_at_utc
            FROM backup_automation_settings
            WHERE id = 1
            """
        ).fetchone()
    return {
        "local_enabled": bool(int(row[0] or 0)),
        "local_interval_hours": _coerce_int(row[1], AUTO_BACKUP_DEFAULT_INTERVAL_HOURS, 1, 168),
        "local_retention_days": _coerce_int(row[2], AUTO_BACKUP_DEFAULT_RETENTION_DAYS, 1, 365),
        "local_retention_max_files": _coerce_int(
            row[3],
            AUTO_BACKUP_DEFAULT_RETENTION_MAX_FILES,
            0,
            20,
        ),
        "local_target_dir": _normalize_backup_target_dir(row[4]),
        "sftp_enabled": bool(int(row[5] or 0)),
        "sftp_host": str(row[6] or ""),
        "sftp_port": _coerce_int(row[7], 22, 1, 65535),
        "sftp_username": str(row[8] or ""),
        "sftp_remote_path": str(row[9] or ""),
        "sftp_auth_mode": "password" if str(row[10] or "").strip().lower() == "password" else "key",
        "sftp_key_path": str(row[11] or ""),
        "sftp_password": str(row[12] or ""),
        "updated_at_utc": str(row[13] or ""),
    }


def save_backup_automation_settings(conn: sqlite3.Connection, payload: dict) -> dict[str, object]:
    existing = get_backup_automation_settings(conn)
    local_enabled = coerce_bool(payload.get("local_enabled", existing.get("local_enabled", True)))
    local_interval_hours = _coerce_int(
        payload.get("local_interval_hours", existing.get("local_interval_hours", AUTO_BACKUP_DEFAULT_INTERVAL_HOURS)),
        AUTO_BACKUP_DEFAULT_INTERVAL_HOURS,
        1,
        168,
    )
    local_retention_days = _coerce_int(
        payload.get("local_retention_days", existing.get("local_retention_days", AUTO_BACKUP_DEFAULT_RETENTION_DAYS)),
        AUTO_BACKUP_DEFAULT_RETENTION_DAYS,
        1,
        365,
    )
    local_retention_max_files = _coerce_int(
        payload.get(
            "local_retention_max_files",
            existing.get("local_retention_max_files", AUTO_BACKUP_DEFAULT_RETENTION_MAX_FILES),
        ),
        AUTO_BACKUP_DEFAULT_RETENTION_MAX_FILES,
        0,
        20,
    )
    local_target_dir = _normalize_backup_target_dir(
        payload.get("local_target_dir", existing.get("local_target_dir", AUTO_BACKUP_DIR.name))
    )
    sftp_enabled = coerce_bool(payload.get("sftp_enabled", existing.get("sftp_enabled", False)))
    sftp_host = str(payload.get("sftp_host", existing.get("sftp_host", "")) or "").strip()
    sftp_port = _coerce_int(payload.get("sftp_port", existing.get("sftp_port", 22)), 22, 1, 65535)
    sftp_username = str(payload.get("sftp_username", existing.get("sftp_username", "")) or "").strip()
    sftp_remote_path = str(payload.get("sftp_remote_path", existing.get("sftp_remote_path", "")) or "").strip()
    sftp_auth_mode_raw = str(payload.get("sftp_auth_mode", existing.get("sftp_auth_mode", "key")) or "key").strip().lower()
    sftp_auth_mode = "password" if sftp_auth_mode_raw == "password" else "key"
    sftp_key_path = str(payload.get("sftp_key_path", existing.get("sftp_key_path", "")) or "").strip()
    sftp_password = str(payload.get("sftp_password", existing.get("sftp_password", "")) or "")
    now_utc = utc_now_iso()

    conn.execute(
        """
        INSERT INTO backup_automation_settings (
            id,
            local_enabled,
            local_interval_hours,
            local_retention_days,
            local_retention_max_files,
            local_target_dir,
            sftp_enabled,
            sftp_host,
            sftp_port,
            sftp_username,
            sftp_remote_path,
            sftp_auth_mode,
            sftp_key_path,
            sftp_password,
            updated_at_utc
        ) VALUES (1, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
        ON CONFLICT(id) DO UPDATE SET
            local_enabled = excluded.local_enabled,
            local_interval_hours = excluded.local_interval_hours,
            local_retention_days = excluded.local_retention_days,
            local_retention_max_files = excluded.local_retention_max_files,
            local_target_dir = excluded.local_target_dir,
            sftp_enabled = excluded.sftp_enabled,
            sftp_host = excluded.sftp_host,
            sftp_port = excluded.sftp_port,
            sftp_username = excluded.sftp_username,
            sftp_remote_path = excluded.sftp_remote_path,
            sftp_auth_mode = excluded.sftp_auth_mode,
            sftp_key_path = excluded.sftp_key_path,
            sftp_password = excluded.sftp_password,
            updated_at_utc = excluded.updated_at_utc
        """,
        (
            1 if local_enabled else 0,
            local_interval_hours,
            local_retention_days,
            local_retention_max_files,
            local_target_dir,
            1 if sftp_enabled else 0,
            sftp_host,
            sftp_port,
            sftp_username,
            sftp_remote_path,
            sftp_auth_mode,
            sftp_key_path,
            sftp_password,
            now_utc,
        ),
    )
    return get_backup_automation_settings(conn)


def _sftp_batch_quote(value: str) -> str:
    return '"' + str(value or "").replace("\\", "\\\\").replace('"', '\\"') + '"'


def _resolve_sftp_config(payload: dict[str, object]) -> dict[str, object]:
    sftp_host = str(payload.get("sftp_host", "") or "").strip()
    sftp_port = _coerce_int(payload.get("sftp_port", 22), 22, 1, 65535)
    sftp_username = str(payload.get("sftp_username", "") or "").strip()
    sftp_remote_path = str(payload.get("sftp_remote_path", "") or "").strip()
    sftp_auth_mode_raw = str(payload.get("sftp_auth_mode", "key") or "key").strip().lower()
    sftp_auth_mode = "password" if sftp_auth_mode_raw == "password" else "key"
    sftp_key_path = str(payload.get("sftp_key_path", "") or "").strip()
    sftp_password = str(payload.get("sftp_password", "") or "")

    if not sftp_host:
        raise ValueError("sFTP Host fehlt")
    if not sftp_username:
        raise ValueError("sFTP Benutzer fehlt")
    if not sftp_remote_path:
        raise ValueError("Remote Pfad fehlt")

    try:
        with socket.create_connection((sftp_host, sftp_port), timeout=6):
            pass
    except OSError as exc:
        raise RuntimeError(f"sFTP Host/Port nicht erreichbar: {exc}")

    if shutil.which("sftp") is None:
        raise RuntimeError("Systembefehl 'sftp' nicht gefunden")

    if sftp_auth_mode == "key":
        if not sftp_key_path:
            raise ValueError("Key Pfad fehlt (Auth Modus: SSH Key)")
        key_path = Path(sftp_key_path).expanduser()
        if not key_path.exists() or not key_path.is_file():
            raise ValueError("Key Datei nicht gefunden")
        if not os.access(key_path, os.R_OK):
            raise ValueError("Key Datei ist nicht lesbar")
    else:
        if not sftp_password:
            raise ValueError("Passwort fehlt (Auth Modus: Passwort)")
        if shutil.which("sshpass") is None:
            raise RuntimeError("Passwort-Test erfordert 'sshpass' auf dem Server")

    return {
        "host": sftp_host,
        "port": sftp_port,
        "username": sftp_username,
        "remote_path": sftp_remote_path,
        "auth_mode": sftp_auth_mode,
        "key_path": sftp_key_path,
        "password": sftp_password,
    }


def _run_sftp_batch(sftp_cfg: dict[str, object], batch_lines: list[str], *, timeout_seconds: int = 30, error_prefix: str = "sFTP Aktion fehlgeschlagen") -> None:
    sftp_command = [
        "sftp",
        "-o",
        "StrictHostKeyChecking=accept-new",
        "-o",
        "ConnectTimeout=8",
        "-P",
        str(int(sftp_cfg.get("port") or 22)),
    ]

    env = os.environ.copy()
    auth_mode = str(sftp_cfg.get("auth_mode") or "key")
    if auth_mode == "key":
        sftp_command.extend(["-o", "BatchMode=yes", "-i", str(Path(str(sftp_cfg.get("key_path") or "")).expanduser())])
    else:
        sftp_command.extend(["-o", "BatchMode=no"])
        sftp_command = ["sshpass", "-e"] + sftp_command
        env["SSHPASS"] = str(sftp_cfg.get("password") or "")

    sftp_command.append(f"{sftp_cfg.get('username')}@{sftp_cfg.get('host')}")
    batch_input = "\n".join(batch_lines) + "\n"

    proc = subprocess.run(
        sftp_command,
        input=batch_input,
        text=True,
        capture_output=True,
        timeout=timeout_seconds,
        env=env,
    )
    if proc.returncode != 0:
        details = (proc.stderr or proc.stdout or "").strip()
        if len(details) > 600:
            details = details[:600] + "..."
        raise RuntimeError(f"{error_prefix}: {details or 'unbekannter Fehler'}")


def _calculate_sftp_upload_timeout_seconds(local_file_path: Path) -> int:
    try:
        file_size_bytes = int(local_file_path.stat().st_size)
    except OSError:
        return SFTP_UPLOAD_TIMEOUT_MIN_SECONDS

    # Add fixed handshake margin plus transfer time estimate for slower links.
    estimated_transfer_seconds = int(file_size_bytes / SFTP_UPLOAD_ASSUMED_BYTES_PER_SECOND)
    timeout_seconds = 120 + estimated_transfer_seconds
    return max(SFTP_UPLOAD_TIMEOUT_MIN_SECONDS, min(SFTP_UPLOAD_TIMEOUT_MAX_SECONDS, timeout_seconds))


def upload_backup_file_to_sftp(payload: dict[str, object], local_file_path: Path, remote_filename: str | None = None) -> dict[str, object]:
    sftp_cfg = _resolve_sftp_config(payload)

    local_path = Path(local_file_path)
    if not local_path.exists() or not local_path.is_file():
        raise ValueError("Lokale Backup-Datei nicht gefunden")

    remote_name = str(remote_filename or local_path.name).strip() or local_path.name
    timeout_seconds = _calculate_sftp_upload_timeout_seconds(local_path)
    batch_lines = [
        f"cd {_sftp_batch_quote(str(sftp_cfg['remote_path']))}",
        f"put {_sftp_batch_quote(str(local_path))} {_sftp_batch_quote(remote_name)}",
        f"ls {_sftp_batch_quote(remote_name)}",
        "bye",
    ]
    _run_sftp_batch(
        sftp_cfg,
        batch_lines,
        timeout_seconds=timeout_seconds,
        error_prefix="sFTP Upload fehlgeschlagen",
    )

    return {
        "host": str(sftp_cfg.get("host") or ""),
        "port": int(sftp_cfg.get("port") or 22),
        "username": str(sftp_cfg.get("username") or ""),
        "remote_path": str(sftp_cfg.get("remote_path") or ""),
        "auth_mode": str(sftp_cfg.get("auth_mode") or "key"),
        "remote_filename": remote_name,
    }


def run_sftp_upload_test(payload: dict[str, object]) -> dict[str, object]:
    sftp_cfg = _resolve_sftp_config(payload)

    BACKUP_TEMP_DIR.mkdir(parents=True, exist_ok=True)
    timestamp = datetime.now(timezone.utc).strftime("%Y%m%d-%H%M%S")
    remote_name = f"monitoring-sftp-test-{timestamp}.txt"

    with tempfile.NamedTemporaryFile(mode="w", delete=False, dir=str(BACKUP_TEMP_DIR), prefix="sftp-test-", suffix=".txt") as tmp:
        tmp.write(f"Monitoring SFTP test at {utc_now_iso()}\n")
        local_path = Path(tmp.name)

    try:
        batch_lines = [
            f"cd {_sftp_batch_quote(str(sftp_cfg['remote_path']))}",
            f"put {_sftp_batch_quote(str(local_path))} {_sftp_batch_quote(remote_name)}",
            f"ls {_sftp_batch_quote(remote_name)}",
            f"rm {_sftp_batch_quote(remote_name)}",
            "bye",
        ]
        _run_sftp_batch(
            sftp_cfg,
            batch_lines,
            timeout_seconds=SFTP_TEST_TIMEOUT_SECONDS,
            error_prefix="sFTP Test fehlgeschlagen",
        )

        return {
            "status": "ok",
            "message": "sFTP Test erfolgreich (Upload + Entfernen der Testdatei abgeschlossen)",
            "details": {
                "host": str(sftp_cfg.get("host") or ""),
                "port": int(sftp_cfg.get("port") or 22),
                "username": str(sftp_cfg.get("username") or ""),
                "remote_path": str(sftp_cfg.get("remote_path") or ""),
                "auth_mode": str(sftp_cfg.get("auth_mode") or "key"),
                "remote_test_file": remote_name,
            },
        }
    finally:
        try:
            local_path.unlink(missing_ok=True)
        except Exception:
            pass


def list_backup_automation_runs(conn: sqlite3.Connection, limit: int = 20) -> list[dict[str, object]]:
    safe_limit = max(1, min(100, int(limit or 20)))
    rows = conn.execute(
        """
        SELECT id,
               started_at_utc,
               finished_at_utc,
               trigger_source,
               status,
               backup_path,
               backup_size_bytes,
               uploaded_sftp,
               error_message
        FROM backup_automation_runs
        ORDER BY id DESC
        LIMIT ?
        """,
        (safe_limit,),
    ).fetchall()
    return [
        {
            "id": int(row[0] or 0),
            "started_at_utc": str(row[1] or ""),
            "finished_at_utc": str(row[2] or ""),
            "trigger_source": str(row[3] or ""),
            "status": str(row[4] or ""),
            "backup_path": str(row[5] or ""),
            "backup_size_bytes": int(row[6] or 0),
            "uploaded_sftp": bool(int(row[7] or 0)),
            "error_message": str(row[8] or ""),
        }
        for row in rows
    ]


def _prune_local_automated_backups(
    target_dir: Path,
    *,
    max_files: int,
    retention_days: int,
) -> int:
    entries: list[tuple[datetime, Path]] = []
    for path in target_dir.glob("monitoring-auto-*.db"):
        try:
            mtime = datetime.fromtimestamp(path.stat().st_mtime, tz=timezone.utc)
            entries.append((mtime, path))
        except OSError:
            continue

    entries.sort(key=lambda item: item[0], reverse=True)
    cutoff = datetime.now(timezone.utc) - timedelta(days=retention_days)
    pruned_count = 0
    for index, (mtime, path) in enumerate(entries):
        if index >= max_files or mtime < cutoff:
            try:
                path.unlink()
                pruned_count += 1
            except OSError:
                pass
    return pruned_count


def _run_local_automated_backup(settings: dict[str, object], trigger_source: str) -> dict[str, object]:
    started_at = utc_now_iso()
    local_target_dir = _normalize_backup_target_dir(settings.get("local_target_dir", AUTO_BACKUP_DIR.name))
    target_dir = DATA_DIR / local_target_dir
    target_dir.mkdir(parents=True, exist_ok=True)

    timestamp = datetime.now(timezone.utc).strftime("%Y%m%d-%H%M%S")
    backup_file = target_dir / f"monitoring-auto-{timestamp}.db"
    temp_file = target_dir / f".{backup_file.name}.tmp"

    with sqlite3.connect(DB_PATH) as src_conn:
        with sqlite3.connect(temp_file) as dst_conn:
            src_conn.backup(dst_conn)
    os.replace(temp_file, backup_file)
    size_bytes = int(backup_file.stat().st_size)

    retention_days = _coerce_int(
        settings.get("local_retention_days", AUTO_BACKUP_DEFAULT_RETENTION_DAYS),
        AUTO_BACKUP_DEFAULT_RETENTION_DAYS,
        1,
        365,
    )
    retention_max_files = _coerce_int(
        settings.get("local_retention_max_files", AUTO_BACKUP_DEFAULT_RETENTION_MAX_FILES),
        AUTO_BACKUP_DEFAULT_RETENTION_MAX_FILES,
        0,
        20,
    )

    uploaded_sftp = False
    upload_error_message = ""
    upload_details: dict[str, object] | None = None
    if bool(settings.get("sftp_enabled", False)):
        try:
            upload_details = upload_backup_file_to_sftp(settings, backup_file, backup_file.name)
            uploaded_sftp = True
        except Exception as exc:
            upload_error_message = str(exc)

    pruned_count = _prune_local_automated_backups(
        target_dir,
        max_files=retention_max_files,
        retention_days=retention_days,
    )

    finished_at = utc_now_iso()
    backup_path_value = str(backup_file.relative_to(DATA_DIR))
    if not backup_file.exists():
        backup_path_value = ""
    with sqlite3.connect(DB_PATH) as conn:
        conn.execute(
            """
            INSERT INTO backup_automation_runs (
                started_at_utc,
                finished_at_utc,
                trigger_source,
                status,
                backup_path,
                backup_size_bytes,
                uploaded_sftp,
                error_message
            ) VALUES (?, ?, ?, 'ok', ?, ?, ?, ?)
            """,
            (
                started_at,
                finished_at,
                trigger_source,
                backup_path_value,
                size_bytes,
                1 if uploaded_sftp else 0,
                upload_error_message,
            ),
        )
        conn.commit()

    return {
        "status": "ok",
        "started_at_utc": started_at,
        "finished_at_utc": finished_at,
        "backup_path": backup_path_value,
        "backup_size_bytes": size_bytes,
        "pruned_count": pruned_count,
        "local_retention_max_files": retention_max_files,
        "uploaded_sftp": uploaded_sftp,
        "sftp_error": upload_error_message,
        "sftp_details": upload_details,
    }


def trigger_automated_backup_now(trigger_source: str = "manual", force_local: bool = True) -> dict[str, object]:
    if not _auto_backup_lock.acquire(blocking=False):
        raise RuntimeError("backup already running")
    try:
        with sqlite3.connect(DB_PATH) as conn:
            settings = get_backup_automation_settings(conn)

        if not force_local and not bool(settings.get("local_enabled", False)) and not bool(settings.get("sftp_enabled", False)):
            return {"status": "skipped", "reason": "backup automation disabled"}

        return _run_local_automated_backup(settings, trigger_source)
    except Exception as exc:
        finished_at = utc_now_iso()
        started_at = finished_at
        with sqlite3.connect(DB_PATH) as conn:
            conn.execute(
                """
                INSERT INTO backup_automation_runs (
                    started_at_utc,
                    finished_at_utc,
                    trigger_source,
                    status,
                    backup_path,
                    backup_size_bytes,
                    uploaded_sftp,
                    error_message
                ) VALUES (?, ?, ?, 'error', '', 0, 0, ?)
                """,
                (
                    started_at,
                    finished_at,
                    trigger_source,
                    str(exc),
                ),
            )
            conn.commit()
        raise
    finally:
        _auto_backup_lock.release()


def _auto_backup_scheduler_loop() -> None:
    while True:
        try:
            with sqlite3.connect(DB_PATH) as conn:
                settings = get_backup_automation_settings(conn)
                if bool(settings.get("local_enabled", False)) or bool(settings.get("sftp_enabled", False)):
                    latest_row = conn.execute(
                        """
                        SELECT finished_at_utc
                        FROM backup_automation_runs
                        ORDER BY id DESC
                        LIMIT 1
                        """
                    ).fetchone()
                    should_run = latest_row is None
                    if latest_row and not should_run:
                        last_iso = str(latest_row[0] or "").strip()
                        try:
                            last_dt = datetime.fromisoformat(last_iso.replace("Z", "+00:00"))
                        except ValueError:
                            last_dt = datetime.now(timezone.utc) - timedelta(hours=999)
                        interval_hours = _coerce_int(
                            settings.get("local_interval_hours", AUTO_BACKUP_DEFAULT_INTERVAL_HOURS),
                            AUTO_BACKUP_DEFAULT_INTERVAL_HOURS,
                            1,
                            168,
                        )
                        should_run = datetime.now(timezone.utc) >= (last_dt + timedelta(hours=interval_hours))
                    if should_run:
                        try:
                            trigger_automated_backup_now(trigger_source="scheduler", force_local=False)
                        except Exception as exc:
                            print(f"[auto-backup-scheduler] {exc}")
        except Exception as exc:
            print(f"[auto-backup-scheduler] {exc}")
        threading.Event().wait(60)


def _sqlite_sidecar_paths(db_path: Path) -> tuple[Path, Path]:
    return (
        db_path.parent / f"{db_path.name}-wal",
        db_path.parent / f"{db_path.name}-shm",
    )


def collect_database_maintenance_stats(conn: sqlite3.Connection) -> dict[str, object]:
    reports_row = conn.execute(
        """
        SELECT
            COUNT(*) AS reports_total,
            COUNT(DISTINCT hostname) AS hosts_with_reports,
            MIN(received_at_utc) AS oldest_report_utc,
            MAX(received_at_utc) AS newest_report_utc,
            AVG(LENGTH(payload_json)) AS avg_payload_bytes,
            MAX(LENGTH(payload_json)) AS max_payload_bytes
        FROM reports
        """
    ).fetchone()
    alerts_row = conn.execute(
        """
        SELECT
            COUNT(*) AS alerts_total,
            SUM(CASE WHEN status = 'open' THEN 1 ELSE 0 END) AS alerts_open
        FROM alerts
        """
    ).fetchone()
    hosts_total_row = conn.execute("SELECT COUNT(DISTINCT hostname) FROM host_settings").fetchone()

    page_size = int((conn.execute("PRAGMA page_size").fetchone() or [0])[0] or 0)
    page_count = int((conn.execute("PRAGMA page_count").fetchone() or [0])[0] or 0)
    freelist_count = int((conn.execute("PRAGMA freelist_count").fetchone() or [0])[0] or 0)
    used_pages = max(0, page_count - freelist_count)

    db_file_bytes = int(DB_PATH.stat().st_size) if DB_PATH.exists() else 0
    wal_path, shm_path = _sqlite_sidecar_paths(DB_PATH)
    wal_file_bytes = int(wal_path.stat().st_size) if wal_path.exists() else 0
    shm_file_bytes = int(shm_path.stat().st_size) if shm_path.exists() else 0
    total_file_bytes = db_file_bytes + wal_file_bytes + shm_file_bytes

    free_ratio = (float(freelist_count) / float(page_count)) if page_count > 0 else 0.0

    return {
        "retention_days": int(REPORT_RETENTION_DAYS),
        "reports_total": int((reports_row[0] or 0) if reports_row else 0),
        "hosts_with_reports": int((reports_row[1] or 0) if reports_row else 0),
        "hosts_total": int((hosts_total_row[0] or 0) if hosts_total_row else 0),
        "oldest_report_utc": str((reports_row[2] or "") if reports_row else ""),
        "newest_report_utc": str((reports_row[3] or "") if reports_row else ""),
        "avg_payload_bytes": float((reports_row[4] or 0.0) if reports_row else 0.0),
        "max_payload_bytes": int((reports_row[5] or 0) if reports_row else 0),
        "alerts_total": int((alerts_row[0] or 0) if alerts_row else 0),
        "alerts_open": int((alerts_row[1] or 0) if alerts_row else 0),
        "db_file_bytes": db_file_bytes,
        "wal_file_bytes": wal_file_bytes,
        "shm_file_bytes": shm_file_bytes,
        "total_file_bytes": total_file_bytes,
        "page_size": page_size,
        "page_count": page_count,
        "freelist_count": freelist_count,
        "used_pages": used_pages,
        "free_ratio": free_ratio,
    }


def _read_sqlite_file_byte_sizes() -> dict[str, int]:
    db_file_bytes = int(DB_PATH.stat().st_size) if DB_PATH.exists() else 0
    wal_path, shm_path = _sqlite_sidecar_paths(DB_PATH)
    wal_file_bytes = int(wal_path.stat().st_size) if wal_path.exists() else 0
    shm_file_bytes = int(shm_path.stat().st_size) if shm_path.exists() else 0
    return {
        "db_file_bytes": db_file_bytes,
        "wal_file_bytes": wal_file_bytes,
        "shm_file_bytes": shm_file_bytes,
        "total_file_bytes": db_file_bytes + wal_file_bytes + shm_file_bytes,
    }


def _count_reports_total(conn: sqlite3.Connection) -> int:
    row = conn.execute("SELECT COUNT(*) FROM reports").fetchone()
    return int((row[0] or 0) if row else 0)


def _count_reports_last_hour(conn: sqlite3.Connection) -> int:
    cutoff_1h = utc_hours_ago_iso(1)
    reports_last_hour_row = conn.execute(
        """
        SELECT COUNT(*)
        FROM agent_ingest_audit_log
        WHERE status = 'written'
          AND db_written_at_utc >= ?
        """,
        (cutoff_1h,),
    ).fetchone()
    reports_last_hour = int((reports_last_hour_row[0] or 0) if reports_last_hour_row else 0)
    if reports_last_hour > 0:
        return reports_last_hour
    fallback_row = conn.execute(
        "SELECT COUNT(*) FROM reports WHERE received_at_utc >= ?",
        (cutoff_1h,),
    ).fetchone()
    return int((fallback_row[0] or 0) if fallback_row else 0)


def collect_dashboard_db_kpis(conn: sqlite3.Connection) -> dict[str, object]:
    """Lightweight header KPIs: snapshot + indexed 1h count, no full reports scan."""
    cache_key = "dashboard-db-kpis:v1"
    cached = _read_cache_get(cache_key)
    if isinstance(cached, dict):
        payload = dict(cached)
        payload.update(_read_sqlite_file_byte_sizes())
        baseline = payload.get("db_size_baseline_1h_bytes")
        if baseline is not None:
            try:
                payload["db_size_delta_1h_bytes"] = int(payload["db_file_bytes"]) - int(baseline)
            except (TypeError, ValueError):
                pass
        payload["total_file_bytes"] = int(payload.get("total_file_bytes", 0) or 0)
        payload["reports_last_hour"] = _count_reports_last_hour(conn)
        payload.pop("db_size_baseline_1h_bytes", None)
        payload.pop("reports_total", None)
        payload.pop("reports_total_computed_at_utc", None)
        return payload

    file_stats = _read_sqlite_file_byte_sizes()
    total_file_bytes = int(file_stats["total_file_bytes"])

    reports_last_hour = _count_reports_last_hour(conn)

    db_file_bytes = int(file_stats["db_file_bytes"])
    cutoff_1h = utc_hours_ago_iso(1)
    delta_1h_row = conn.execute(
        """
        SELECT db_file_bytes
        FROM db_maintenance_history
        WHERE computed_at_utc <= ?
        ORDER BY computed_at_utc DESC
        LIMIT 1
        """,
        (cutoff_1h,),
    ).fetchone()
    db_size_delta_1h_bytes = None
    db_size_baseline_1h_bytes = None
    if delta_1h_row and delta_1h_row[0] is not None:
        db_size_baseline_1h_bytes = int(delta_1h_row[0] or 0)
        db_size_delta_1h_bytes = db_file_bytes - db_size_baseline_1h_bytes

    cache_payload: dict[str, object] = {
        "reports_last_hour": reports_last_hour,
        "total_file_bytes": total_file_bytes,
        "db_file_bytes": db_file_bytes,
        "db_size_delta_1h_bytes": db_size_delta_1h_bytes,
        "db_size_baseline_1h_bytes": db_size_baseline_1h_bytes,
    }
    _read_cache_set(cache_key, cache_payload, ttl_seconds=DASHBOARD_DB_KPIS_CACHE_TTL_SECONDS)
    public_payload = dict(cache_payload)
    public_payload.pop("db_size_baseline_1h_bytes", None)
    return public_payload


def _read_proc_cpu_totals() -> tuple[int, int] | None:
    try:
        with open("/proc/stat", "r", encoding="utf-8") as handle:
            first_line = handle.readline().strip()
    except OSError:
        return None
    if not first_line.startswith("cpu "):
        return None
    parts = first_line.split()
    if len(parts) < 5:
        return None
    try:
        values = [int(part) for part in parts[1:]]
    except ValueError:
        return None
    total = sum(values)
    idle = values[3] + (values[4] if len(values) > 4 else 0)
    return total, idle


def collect_local_server_resource_usage() -> dict[str, float | int]:
    global _local_cpu_prev_total, _local_cpu_prev_idle

    cpu_percent = 0.0
    sample = _read_proc_cpu_totals()
    with _local_cpu_sample_lock:
        if sample is not None:
            total, idle = sample
            if _local_cpu_prev_total is not None and _local_cpu_prev_idle is not None and total > _local_cpu_prev_total:
                delta_total = total - _local_cpu_prev_total
                delta_idle = max(0, idle - _local_cpu_prev_idle)
                busy = max(0, delta_total - delta_idle)
                if delta_total > 0:
                    cpu_percent = (busy / float(delta_total)) * 100.0
            else:
                try:
                    cpu_count = max(1, int(os.cpu_count() or 1))
                    load_1m = os.getloadavg()[0]
                    cpu_percent = (float(load_1m) / float(cpu_count)) * 100.0
                except (OSError, ValueError):
                    cpu_percent = 0.0
            _local_cpu_prev_total = total
            _local_cpu_prev_idle = idle

    mem_total_kb = 0
    mem_available_kb = 0
    try:
        with open("/proc/meminfo", "r", encoding="utf-8") as handle:
            for line in handle:
                if line.startswith("MemTotal:"):
                    mem_total_kb = int(line.split()[1])
                elif line.startswith("MemAvailable:"):
                    mem_available_kb = int(line.split()[1])
    except (OSError, ValueError, IndexError):
        mem_total_kb = 0
        mem_available_kb = 0

    memory_percent = 0.0
    if mem_total_kb > 0:
        used_kb = max(0, mem_total_kb - max(0, mem_available_kb))
        memory_percent = (used_kb / float(mem_total_kb)) * 100.0

    return {
        "cpu_percent": max(0.0, min(100.0, float(cpu_percent))),
        "memory_percent": max(0.0, min(100.0, float(memory_percent))),
        "memory_total_bytes": max(0, int(mem_total_kb) * 1024),
    }


def collect_agent_ingest_queue_overview(conn: sqlite3.Connection, recent_errors_limit: int = 20) -> dict[str, object]:
    now_iso = utc_now_iso()
    now_dt = datetime.now(timezone.utc)

    totals_row = conn.execute(
        """
        SELECT
            COUNT(*) AS queue_depth,
            SUM(CASE WHEN next_attempt_at_utc <= ? THEN 1 ELSE 0 END) AS ready_count,
            SUM(CASE WHEN attempt_count > 0 OR COALESCE(last_error, '') <> '' THEN 1 ELSE 0 END) AS retry_count,
            SUM(CASE WHEN COALESCE(processing_started_at_utc, '') <> '' THEN 1 ELSE 0 END) AS in_flight_count,
            SUM(CASE WHEN next_attempt_at_utc > ? THEN 1 ELSE 0 END) AS delayed_count,
            SUM(CASE WHEN attempt_count <= 0 AND COALESCE(last_error, '') = '' THEN 1 ELSE 0 END) AS pending_count
        FROM agent_ingest_queue
        """,
        (now_iso, now_iso),
    ).fetchone()

    oldest_row = conn.execute(
        """
        SELECT enqueued_at_utc
        FROM agent_ingest_queue
        ORDER BY enqueued_at_utc ASC, id ASC
        LIMIT 1
        """
    ).fetchone()

    newest_row = conn.execute(
        """
        SELECT enqueued_at_utc
        FROM agent_ingest_queue
        ORDER BY enqueued_at_utc DESC, id DESC
        LIMIT 1
        """
    ).fetchone()

    next_ready_row = conn.execute(
        """
        SELECT next_attempt_at_utc
        FROM agent_ingest_queue
        ORDER BY next_attempt_at_utc ASC, id ASC
        LIMIT 1
        """
    ).fetchone()

    recent_errors_rows = conn.execute(
        """
        SELECT id, hostname, host_uid, attempt_count, updated_at_utc, next_attempt_at_utc, last_error
        FROM agent_ingest_queue
        WHERE COALESCE(last_error, '') <> ''
        ORDER BY updated_at_utc DESC, id DESC
        LIMIT ?
        """,
        (max(1, int(recent_errors_limit)),),
    ).fetchall()

    def _parse_iso(value: object) -> datetime | None:
        raw = str(value or "").strip()
        if not raw:
            return None
        try:
            parsed = datetime.fromisoformat(raw.replace("Z", "+00:00"))
        except ValueError:
            return None
        if parsed.tzinfo is None:
            return parsed.replace(tzinfo=timezone.utc)
        return parsed.astimezone(timezone.utc)

    oldest_enqueued_at_utc = str((oldest_row[0] if oldest_row else "") or "")
    newest_enqueued_at_utc = str((newest_row[0] if newest_row else "") or "")
    next_attempt_at_utc = str((next_ready_row[0] if next_ready_row else "") or "")

    oldest_age_seconds = 0
    oldest_dt = _parse_iso(oldest_enqueued_at_utc)
    if oldest_dt is not None:
        oldest_age_seconds = max(0, int((now_dt - oldest_dt).total_seconds()))

    next_attempt_in_seconds = 0
    next_attempt_dt = _parse_iso(next_attempt_at_utc)
    if next_attempt_dt is not None:
        next_attempt_in_seconds = int((next_attempt_dt - now_dt).total_seconds())

    recent_errors: list[dict[str, object]] = []
    for row in recent_errors_rows:
        updated_at = str(row[4] or "")
        next_attempt = str(row[5] or "")
        updated_dt = _parse_iso(updated_at)
        next_attempt_dt_row = _parse_iso(next_attempt)
        age_seconds = max(0, int((now_dt - updated_dt).total_seconds())) if updated_dt is not None else 0
        retry_in_seconds = int((next_attempt_dt_row - now_dt).total_seconds()) if next_attempt_dt_row is not None else 0
        recent_errors.append(
            {
                "id": int(row[0] or 0),
                "hostname": str(row[1] or ""),
                "host_uid": str(row[2] or ""),
                "attempt_count": int(row[3] or 0),
                "updated_at_utc": updated_at,
                "next_attempt_at_utc": next_attempt,
                "error_age_seconds": age_seconds,
                "retry_in_seconds": retry_in_seconds,
                "last_error": str(row[6] or ""),
            }
        )

    queue_depth = int((totals_row[0] or 0) if totals_row else 0)
    ready_count = int((totals_row[1] or 0) if totals_row else 0)
    retry_count = int((totals_row[2] or 0) if totals_row else 0)
    in_flight_count = int((totals_row[3] or 0) if totals_row else 0)
    delayed_count = int((totals_row[4] or 0) if totals_row else 0)
    pending_count = int((totals_row[5] or 0) if totals_row else 0)

    return {
        "queue_depth": queue_depth,
        "ready_count": ready_count,
        "retry_count": retry_count,
        "in_flight_count": in_flight_count,
        "delayed_count": delayed_count,
        "pending_count": pending_count,
        "oldest_enqueued_at_utc": oldest_enqueued_at_utc,
        "newest_enqueued_at_utc": newest_enqueued_at_utc,
        "oldest_age_seconds": oldest_age_seconds,
        "next_attempt_at_utc": next_attempt_at_utc,
        "next_attempt_in_seconds": next_attempt_in_seconds,
        "recent_errors": recent_errors,
    }


def _agent_ingest_duration_ms(start_iso: object, end_iso: object) -> int:
    start_dt = parse_utc_iso(start_iso)
    end_dt = parse_utc_iso(end_iso)
    if start_dt is None or end_dt is None:
        return 0
    return max(0, int((end_dt - start_dt).total_seconds() * 1000))


def _prune_agent_ingest_audit_log(conn: sqlite3.Connection) -> None:
    rows_to_delete = conn.execute(
        """
        SELECT id, payload_file_path
        FROM agent_ingest_audit_log
        ORDER BY id DESC
        LIMIT -1 OFFSET ?
        """,
        (AGENT_INGEST_AUDIT_MAX_ROWS,),
    ).fetchall()
    if not rows_to_delete:
        return

    for row in rows_to_delete:
        file_name = str((row[1] if len(row) > 1 else "") or "").strip()
        if not file_name:
            continue
        file_path = AGENT_INGEST_AUDIT_PAYLOAD_DIR / file_name
        try:
            if file_path.is_file():
                file_path.unlink()
        except OSError:
            pass

    conn.execute(
        """
        DELETE FROM agent_ingest_audit_log
        WHERE id IN (
            SELECT id
            FROM agent_ingest_audit_log
            ORDER BY id DESC
            LIMIT -1 OFFSET ?
        )
        """,
        (AGENT_INGEST_AUDIT_MAX_ROWS,),
    )


def _insert_agent_ingest_audit_log_row(
    conn: sqlite3.Connection,
    *,
    queue_id: int,
    hostname: str,
    host_uid: str,
    report_received_at_utc: str,
    enqueued_at_utc: str,
    payload_bytes: int,
    payload_file_path: str,
) -> None:
    safe_file_name = str(payload_file_path or "").strip()
    payload_stored = 1 if safe_file_name else 0
    conn.execute(
        """
        INSERT OR REPLACE INTO agent_ingest_audit_log (
            queue_id,
            hostname,
            host_uid,
            report_received_at_utc,
            enqueued_at_utc,
            db_written_at_utc,
            payload_bytes,
            payload_stored,
            payload_file_path,
            payload_snapshot_json,
            attempt_count,
            queue_wait_ms,
            processing_ms,
            end_to_end_ms,
            status,
            error_message,
            updated_at_utc
        ) VALUES (?, ?, ?, ?, ?, '', ?, ?, ?, '', 0, 0, 0, 0, 'queued', '', ?)
        """,
        (
            int(queue_id),
            str(hostname or ""),
            str(host_uid or ""),
            str(report_received_at_utc or ""),
            str(enqueued_at_utc or ""),
            max(0, int(payload_bytes or 0)),
            payload_stored,
            safe_file_name,
            str(enqueued_at_utc or ""),
        ),
    )
    _prune_agent_ingest_audit_log(conn)


def _update_agent_ingest_audit_log_row(
    conn: sqlite3.Connection,
    *,
    queue_id: int,
    status: str,
    updated_at_utc: str,
    attempt_count: int,
    db_written_at_utc: str = "",
    queue_wait_ms: int = 0,
    processing_ms: int = 0,
    end_to_end_ms: int = 0,
    error_message: str = "",
) -> None:
    conn.execute(
        """
        UPDATE agent_ingest_audit_log
        SET status = ?,
            updated_at_utc = ?,
            attempt_count = ?,
            db_written_at_utc = ?,
            queue_wait_ms = ?,
            processing_ms = ?,
            end_to_end_ms = ?,
            error_message = ?
        WHERE queue_id = ?
        """,
        (
            str(status or "queued"),
            str(updated_at_utc or ""),
            max(0, int(attempt_count or 0)),
            str(db_written_at_utc or ""),
            max(0, int(queue_wait_ms or 0)),
            max(0, int(processing_ms or 0)),
            max(0, int(end_to_end_ms or 0)),
            str(error_message or ""),
            int(queue_id),
        ),
    )


def collect_agent_ingest_audit_log(
    conn: sqlite3.Connection,
    *,
    limit: int = AGENT_INGEST_AUDIT_MAX_ROWS,
) -> dict[str, object]:
    safe_limit = max(10, min(2000, int(limit or AGENT_INGEST_AUDIT_MAX_ROWS)))
    rows = conn.execute(
        """
        SELECT
            a.id,
            a.queue_id,
            a.hostname,
            a.host_uid,
            a.report_received_at_utc,
            a.enqueued_at_utc,
            a.db_written_at_utc,
            a.payload_bytes,
            a.payload_stored,
            a.payload_file_path,
            a.attempt_count,
            a.queue_wait_ms,
            a.processing_ms,
            a.end_to_end_ms,
            a.status,
            a.error_message,
            a.updated_at_utc,
            COALESCE(
                (
                    SELECT c_uid.customer_name
                    FROM reports r_uid
                    JOIN host_settings hs_uid ON hs_uid.hostname = r_uid.hostname
                    LEFT JOIN customers c_uid ON c_uid.id = hs_uid.customer_id
                    WHERE COALESCE(a.host_uid, '') <> ''
                      AND COALESCE(r_uid.host_uid, '') = a.host_uid
                    ORDER BY r_uid.id DESC
                    LIMIT 1
                ),
                (
                    SELECT c_host.customer_name
                    FROM host_settings hs_host
                    LEFT JOIN customers c_host ON c_host.id = hs_host.customer_id
                    WHERE hs_host.hostname = a.hostname
                    LIMIT 1
                ),
                ''
            ) AS customer_name
        FROM agent_ingest_audit_log a
        ORDER BY id DESC
        LIMIT ?
        """,
        (safe_limit,),
    ).fetchall()

    entries: list[dict[str, object]] = []
    for row in rows:
        payload_stored = int(row[8] or 0) == 1
        payload_file_name = str(row[9] or "").strip()
        payload_download_path = ""
        if payload_stored and payload_file_name:
            payload_download_path = f"/api/v1/admin/agent-ingest-log/payload?audit_id={int(row[0] or 0)}"
        entries.append(
            {
                "id": int(row[0] or 0),
                "queue_id": int(row[1] or 0),
                "hostname": str(row[2] or ""),
                "host_uid": str(row[3] or ""),
                "report_received_at_utc": str(row[4] or ""),
                "enqueued_at_utc": str(row[5] or ""),
                "db_written_at_utc": str(row[6] or ""),
                "payload_bytes": int(row[7] or 0),
                "payload_stored": payload_stored,
                "payload_file_name": payload_file_name,
                "payload_download_path": payload_download_path,
                "attempt_count": int(row[10] or 0),
                "queue_wait_ms": int(row[11] or 0),
                "processing_ms": int(row[12] or 0),
                "end_to_end_ms": int(row[13] or 0),
                "status": str(row[14] or "queued"),
                "error_message": str(row[15] or ""),
                "updated_at_utc": str(row[16] or ""),
                "customer_name": str(row[17] or ""),
            }
        )

    return {
        "limit": safe_limit,
        "retention_limit": AGENT_INGEST_AUDIT_MAX_ROWS,
        "payload_capture_enabled": AGENT_INGEST_AUDIT_STORE_PAYLOAD,
        "payload_capture_max_bytes": AGENT_INGEST_AUDIT_PAYLOAD_MAX_BYTES,
        "payload_capture_mode": "disk" if AGENT_INGEST_AUDIT_STORE_PAYLOAD else "off",
        "entries": entries,
    }


def _write_agent_ingest_audit_payload_file(
    *,
    queue_id: int,
    hostname: str,
    report_received_at_utc: str,
    payload_json: str,
) -> str:
    if not AGENT_INGEST_AUDIT_STORE_PAYLOAD:
        return ""
    payload_text = str(payload_json or "")
    payload_bytes = len(payload_text.encode("utf-8"))
    if payload_bytes > AGENT_INGEST_AUDIT_PAYLOAD_MAX_BYTES:
        return ""

    AGENT_INGEST_AUDIT_PAYLOAD_DIR.mkdir(parents=True, exist_ok=True)
    host_slug = re.sub(r"[^a-zA-Z0-9._-]+", "-", str(hostname or "").strip()).strip("-._") or "host"
    ts = re.sub(r"[^0-9]", "", str(report_received_at_utc or ""))[:14]
    if not ts:
        ts = datetime.now(timezone.utc).strftime("%Y%m%d%H%M%S")
    file_name = f"ingest_{ts}_q{int(queue_id)}_{host_slug}.json"
    file_path = AGENT_INGEST_AUDIT_PAYLOAD_DIR / file_name
    tmp_path = AGENT_INGEST_AUDIT_PAYLOAD_DIR / f"{file_name}.tmp"

    try:
        tmp_path.write_text(payload_text, encoding="utf-8")
        tmp_path.replace(file_path)
        return file_name
    except OSError as exc:
        print(f"[agent-ingest-audit] payload snapshot write failed for queue_id={queue_id}: {exc}")
        try:
            if tmp_path.exists():
                tmp_path.unlink()
        except OSError:
            pass
        return ""


REPORT_DEDUPE_BATCH_SIZE = max(
    100,
    min(10_000, int(os.getenv("MONITORING_REPORT_DEDUPE_BATCH_SIZE", "2000") or "2000")),
)


def _report_dedupe_host_key_sql(alias: str = "") -> str:
    alias_text = str(alias or "").strip()
    if alias_text.endswith("."):
        alias_text = alias_text[:-1]
    prefix = f"{alias_text}." if alias_text else ""
    return f"COALESCE(NULLIF({prefix}host_uid, ''), {prefix}hostname)"


def analyze_ingest_duplicate_reports(conn: sqlite3.Connection) -> dict[str, object]:
    """Find redundant report rows from ingest retries (same host, time, payload)."""
    host_key = _report_dedupe_host_key_sql()
    totals_row = conn.execute("SELECT COUNT(*) FROM reports").fetchone()
    reports_total = int((totals_row[0] or 0) if totals_row else 0)

    dup_row = conn.execute(
        f"""
        SELECT
            COUNT(*) AS duplicate_groups,
            COALESCE(SUM(group_count - 1), 0) AS redundant_rows,
            COALESCE(MAX(group_count), 0) AS max_group_size
        FROM (
            SELECT COUNT(*) AS group_count
            FROM reports
            GROUP BY {host_key}, received_at_utc, payload_json
            HAVING group_count > 1
        )
        """
    ).fetchone()
    duplicate_groups = int((dup_row[0] or 0) if dup_row else 0)
    redundant_rows = int((dup_row[1] or 0) if dup_row else 0)
    max_group_size = int((dup_row[2] or 0) if dup_row else 0)

    files = _read_sqlite_file_byte_sizes()
    avg_payload_row = conn.execute("SELECT AVG(LENGTH(payload_json)) FROM reports").fetchone()
    avg_payload_bytes = float((avg_payload_row[0] or 0.0) if avg_payload_row else 0.0)
    estimated_reclaim_bytes = int(redundant_rows * avg_payload_bytes)

    return {
        "reports_total": reports_total,
        "duplicate_groups": duplicate_groups,
        "redundant_rows": redundant_rows,
        "unique_rows_after_dedupe": max(0, reports_total - redundant_rows),
        "max_group_size": max_group_size,
        "estimated_reclaim_bytes": estimated_reclaim_bytes,
        "db_file_bytes": int(files.get("db_file_bytes", 0) or 0),
        "total_file_bytes": int(files.get("total_file_bytes", 0) or 0),
        "wal_file_bytes": int(files.get("wal_file_bytes", 0) or 0),
    }


def _unlink_and_delete_reports_by_ids(conn: sqlite3.Connection, report_ids: list[int]) -> int:
    if not report_ids:
        return 0
    placeholders = ",".join("?" for _ in report_ids)
    conn.execute(
        f"UPDATE alerts SET report_id = NULL WHERE report_id IN ({placeholders})",
        report_ids,
    )
    conn.execute(
        f"DELETE FROM host_config_changes WHERE report_id IN ({placeholders})",
        report_ids,
    )
    conn.execute(
        f"DELETE FROM database_lifecycle WHERE report_id IN ({placeholders})",
        report_ids,
    )
    conn.execute(
        f"DELETE FROM reports WHERE id IN ({placeholders})",
        report_ids,
    )
    return len(report_ids)


def dedupe_ingest_duplicate_reports(
    conn: sqlite3.Connection,
    *,
    dry_run: bool = False,
    batch_size: int = REPORT_DEDUPE_BATCH_SIZE,
) -> dict[str, object]:
    """Remove ingest duplicate reports, keeping the lowest id per host/time/payload."""
    started_at = datetime.now(timezone.utc)
    before = analyze_ingest_duplicate_reports(conn)
    host_key = _report_dedupe_host_key_sql()
    safe_batch_size = max(100, min(10_000, int(batch_size or REPORT_DEDUPE_BATCH_SIZE)))

    if dry_run:
        return {
            "dry_run": True,
            "before": before,
            "deleted_rows": int(before.get("redundant_rows", 0) or 0),
            "duration_ms": int((datetime.now(timezone.utc) - started_at).total_seconds() * 1000),
        }

    deleted_rows = 0
    while True:
        rows = conn.execute(
            f"""
            WITH ranked AS (
                SELECT id,
                       ROW_NUMBER() OVER (
                           PARTITION BY {host_key}, received_at_utc, payload_json
                           ORDER BY id ASC
                       ) AS rn
                FROM reports
            )
            SELECT id
            FROM ranked
            WHERE rn > 1
            ORDER BY id ASC
            LIMIT ?
            """,
            (safe_batch_size,),
        ).fetchall()
        if not rows:
            break
        report_ids = [int(row[0] or 0) for row in rows if int(row[0] or 0) > 0]
        if not report_ids:
            break
        deleted_rows += _unlink_and_delete_reports_by_ids(conn, report_ids)
        conn.commit()

    after = analyze_ingest_duplicate_reports(conn)
    _read_cache_invalidate_prefix("admin-database-stats")
    _read_cache_invalidate_prefix("dashboard-db-kpis")
    _schedule_identity_snapshot_refresh()
    _schedule_identity_maps_cache_invalidation()
    _schedule_read_cache_invalidation()

    return {
        "dry_run": False,
        "before": before,
        "after": after,
        "deleted_rows": deleted_rows,
        "duration_ms": int((datetime.now(timezone.utc) - started_at).total_seconds() * 1000),
    }


def run_database_vacuum() -> dict[str, object]:
    started_at = datetime.now(timezone.utc)
    with sqlite3.connect(DB_PATH) as conn_before:
        before = collect_database_maintenance_stats(conn_before)

    with sqlite3.connect(DB_PATH) as conn:
        conn.isolation_level = None
        conn.execute("PRAGMA wal_checkpoint(TRUNCATE)")
        conn.execute("VACUUM")
        conn.execute("PRAGMA wal_checkpoint(TRUNCATE)")

    with sqlite3.connect(DB_PATH) as conn_after:
        after = collect_database_maintenance_stats(conn_after)

    duration_ms = int((datetime.now(timezone.utc) - started_at).total_seconds() * 1000)
    reclaimed_bytes = int(before.get("total_file_bytes", 0) or 0) - int(after.get("total_file_bytes", 0) or 0)

    return {
        "before": before,
        "after": after,
        "reclaimed_bytes": reclaimed_bytes,
        "duration_ms": duration_ms,
    }


def _maintenance_bucket_start_utc(now_utc: datetime | None = None) -> datetime:
    ref_utc = now_utc or datetime.now(timezone.utc)
    local_now = ref_utc.astimezone(SCHEDULE_TIMEZONE)
    bucket_hour = (local_now.hour // DB_MAINTENANCE_INTERVAL_HOURS) * DB_MAINTENANCE_INTERVAL_HOURS
    local_bucket = local_now.replace(hour=bucket_hour, minute=0, second=0, microsecond=0)
    return local_bucket.astimezone(timezone.utc)


def _upsert_db_maintenance_snapshot_for_bucket(
    conn: sqlite3.Connection,
    *,
    bucket_start_utc: datetime,
    computed_at_utc: str | None = None,
) -> dict[str, object]:
    bucket_iso = bucket_start_utc.strftime("%Y-%m-%dT%H:%M:%SZ")
    computed_iso = str(computed_at_utc or "").strip() or utc_now_iso()
    stats = collect_database_maintenance_stats(conn)
    conn.execute(
        """
        INSERT INTO db_maintenance_history (
            bucket_start_utc,
            computed_at_utc,
            retention_days,
            reports_total,
            hosts_with_reports,
            hosts_total,
            alerts_open,
            avg_payload_bytes,
            max_payload_bytes,
            db_file_bytes,
            wal_file_bytes,
            shm_file_bytes,
            total_file_bytes,
            page_size,
            page_count,
            freelist_count,
            used_pages,
            free_ratio,
            oldest_report_utc,
            newest_report_utc
        ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
        ON CONFLICT(bucket_start_utc) DO UPDATE SET
            computed_at_utc = excluded.computed_at_utc,
            retention_days = excluded.retention_days,
            reports_total = excluded.reports_total,
            hosts_with_reports = excluded.hosts_with_reports,
            hosts_total = excluded.hosts_total,
            alerts_open = excluded.alerts_open,
            avg_payload_bytes = excluded.avg_payload_bytes,
            max_payload_bytes = excluded.max_payload_bytes,
            db_file_bytes = excluded.db_file_bytes,
            wal_file_bytes = excluded.wal_file_bytes,
            shm_file_bytes = excluded.shm_file_bytes,
            total_file_bytes = excluded.total_file_bytes,
            page_size = excluded.page_size,
            page_count = excluded.page_count,
            freelist_count = excluded.freelist_count,
            used_pages = excluded.used_pages,
            free_ratio = excluded.free_ratio,
            oldest_report_utc = excluded.oldest_report_utc,
            newest_report_utc = excluded.newest_report_utc
        """,
        (
            bucket_iso,
            computed_iso,
            int(stats.get("retention_days", REPORT_RETENTION_DAYS) or REPORT_RETENTION_DAYS),
            int(stats.get("reports_total", 0) or 0),
            int(stats.get("hosts_with_reports", 0) or 0),
            int(stats.get("hosts_total", 0) or 0),
            int(stats.get("alerts_open", 0) or 0),
            float(stats.get("avg_payload_bytes", 0.0) or 0.0),
            int(stats.get("max_payload_bytes", 0) or 0),
            int(stats.get("db_file_bytes", 0) or 0),
            int(stats.get("wal_file_bytes", 0) or 0),
            int(stats.get("shm_file_bytes", 0) or 0),
            int(stats.get("total_file_bytes", 0) or 0),
            int(stats.get("page_size", 0) or 0),
            int(stats.get("page_count", 0) or 0),
            int(stats.get("freelist_count", 0) or 0),
            int(stats.get("used_pages", 0) or 0),
            float(stats.get("free_ratio", 0.0) or 0.0),
            str(stats.get("oldest_report_utc", "") or ""),
            str(stats.get("newest_report_utc", "") or ""),
        ),
    )
    stats["computed_at_utc"] = computed_iso
    return stats


def _insert_db_maintenance_snapshot_if_missing(
    conn: sqlite3.Connection,
    *,
    bucket_start_utc: datetime,
) -> bool:
    bucket_iso = bucket_start_utc.strftime("%Y-%m-%dT%H:%M:%SZ")
    exists = conn.execute(
        "SELECT 1 FROM db_maintenance_history WHERE bucket_start_utc = ? LIMIT 1",
        (bucket_iso,),
    ).fetchone()
    if exists:
        return False

    stats = collect_database_maintenance_stats(conn)
    conn.execute(
        """
        INSERT INTO db_maintenance_history (
            bucket_start_utc,
            computed_at_utc,
            retention_days,
            reports_total,
            hosts_with_reports,
            hosts_total,
            alerts_open,
            avg_payload_bytes,
            max_payload_bytes,
            db_file_bytes,
            wal_file_bytes,
            shm_file_bytes,
            total_file_bytes,
            page_size,
            page_count,
            freelist_count,
            used_pages,
            free_ratio,
            oldest_report_utc,
            newest_report_utc
        ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
        """,
        (
            bucket_iso,
            utc_now_iso(),
            int(stats.get("retention_days", REPORT_RETENTION_DAYS) or REPORT_RETENTION_DAYS),
            int(stats.get("reports_total", 0) or 0),
            int(stats.get("hosts_with_reports", 0) or 0),
            int(stats.get("hosts_total", 0) or 0),
            int(stats.get("alerts_open", 0) or 0),
            float(stats.get("avg_payload_bytes", 0.0) or 0.0),
            int(stats.get("max_payload_bytes", 0) or 0),
            int(stats.get("db_file_bytes", 0) or 0),
            int(stats.get("wal_file_bytes", 0) or 0),
            int(stats.get("shm_file_bytes", 0) or 0),
            int(stats.get("total_file_bytes", 0) or 0),
            int(stats.get("page_size", 0) or 0),
            int(stats.get("page_count", 0) or 0),
            int(stats.get("freelist_count", 0) or 0),
            int(stats.get("used_pages", 0) or 0),
            float(stats.get("free_ratio", 0.0) or 0.0),
            str(stats.get("oldest_report_utc", "") or ""),
            str(stats.get("newest_report_utc", "") or ""),
        ),
    )
    return True


def _ensure_db_maintenance_snapshot(conn: sqlite3.Connection, *, force_if_empty: bool = False) -> None:
    if force_if_empty:
        row = conn.execute("SELECT 1 FROM db_maintenance_history LIMIT 1").fetchone()
        if not row:
            _insert_db_maintenance_snapshot_if_missing(
                conn,
                bucket_start_utc=_maintenance_bucket_start_utc(),
            )
            conn.commit()
            return

    _insert_db_maintenance_snapshot_if_missing(
        conn,
        bucket_start_utc=_maintenance_bucket_start_utc(),
    )
    conn.commit()


def trigger_db_maintenance_snapshot_now(conn: sqlite3.Connection) -> dict[str, object]:
    bucket_start_utc = _maintenance_bucket_start_utc()
    computed_at_utc = utc_now_iso()
    stats = _upsert_db_maintenance_snapshot_for_bucket(
        conn,
        bucket_start_utc=bucket_start_utc,
        computed_at_utc=computed_at_utc,
    )
    conn.commit()
    return {
        "bucket_start_utc": bucket_start_utc.strftime("%Y-%m-%dT%H:%M:%SZ"),
        "computed_at_utc": computed_at_utc,
        "stats": stats,
    }


def _coerce_number(value: object) -> float:
    try:
        return float(value)
    except (TypeError, ValueError):
        return 0.0


def _forecast_linear_14d(history: list[dict], key: str) -> dict[str, object] | None:
    if len(history) < 2:
        return None

    parsed_rows: list[tuple[datetime, float]] = []
    for row in history:
        bucket_iso = str(row.get("bucket_start_utc", "") or "")
        try:
            dt = datetime.fromisoformat(bucket_iso.replace("Z", "+00:00"))
        except ValueError:
            continue
        parsed_rows.append((dt, _coerce_number(row.get(key, 0))))

    if len(parsed_rows) < 2:
        return None

    last_dt, last_value = parsed_rows[-1]
    cutoff_dt = last_dt - timedelta(days=14)
    window_rows = [(dt, y) for dt, y in parsed_rows if dt >= cutoff_dt]
    if len(window_rows) < 2:
        window_rows = parsed_rows[-2:]

    first_dt = window_rows[0][0]
    points: list[tuple[float, float]] = []
    for dt, y in window_rows:
        x_hours = (dt - first_dt).total_seconds() / 3600.0
        points.append((x_hours, y))

    if len(points) < 2:
        return None

    n = float(len(points))
    sum_x = sum(p[0] for p in points)
    sum_y = sum(p[1] for p in points)
    sum_xx = sum(p[0] * p[0] for p in points)
    sum_xy = sum(p[0] * p[1] for p in points)
    denom = (n * sum_xx) - (sum_x * sum_x)
    if abs(denom) < 1e-9:
        return None

    slope = ((n * sum_xy) - (sum_x * sum_y)) / denom
    intercept = (sum_y - (slope * sum_x)) / n

    horizon_hours = 14.0 * 24.0
    last_x = (last_dt - first_dt).total_seconds() / 3600.0
    target_x = last_x + horizon_hours
    projected = max(0.0, intercept + slope * target_x)
    delta = projected - last_value

    return {
        "metric": key,
        "current": last_value,
        "projected_14d": projected,
        "delta_14d": delta,
        "slope_per_day": slope * 24.0,
    }


def _lightweight_maintenance_stats(conn: sqlite3.Connection) -> dict[str, object]:
    """File sizes + PRAGMA stats; reuses last history row instead of scanning reports."""
    files = _read_sqlite_file_byte_sizes()
    page_size = int((conn.execute("PRAGMA page_size").fetchone() or [0])[0] or 0)
    page_count = int((conn.execute("PRAGMA page_count").fetchone() or [0])[0] or 0)
    freelist_count = int((conn.execute("PRAGMA freelist_count").fetchone() or [0])[0] or 0)
    used_pages = max(0, page_count - freelist_count)
    free_ratio = (float(freelist_count) / float(page_count)) if page_count > 0 else 0.0

    history_row = conn.execute(
        """
        SELECT reports_total,
               hosts_with_reports,
               hosts_total,
               alerts_open,
               avg_payload_bytes,
               max_payload_bytes,
               oldest_report_utc,
               newest_report_utc
        FROM db_maintenance_history
        ORDER BY computed_at_utc DESC
        LIMIT 1
        """
    ).fetchone()
    if history_row:
        return {
            "retention_days": int(REPORT_RETENTION_DAYS),
            "reports_total": int(history_row[0] or 0),
            "hosts_with_reports": int(history_row[1] or 0),
            "hosts_total": int(history_row[2] or 0),
            "alerts_open": int(history_row[3] or 0),
            "avg_payload_bytes": float(history_row[4] or 0.0),
            "max_payload_bytes": int(history_row[5] or 0),
            "oldest_report_utc": str(history_row[6] or ""),
            "newest_report_utc": str(history_row[7] or ""),
            **files,
            "page_size": page_size,
            "page_count": page_count,
            "freelist_count": freelist_count,
            "used_pages": used_pages,
            "free_ratio": free_ratio,
            "stats_source": "history_snapshot",
        }

    alerts_row = conn.execute(
        """
        SELECT SUM(CASE WHEN status = 'open' THEN 1 ELSE 0 END)
        FROM alerts
        """
    ).fetchone()
    hosts_total_row = conn.execute("SELECT COUNT(DISTINCT hostname) FROM host_settings").fetchone()
    return {
        "retention_days": int(REPORT_RETENTION_DAYS),
        "reports_total": 0,
        "hosts_with_reports": 0,
        "hosts_total": int((hosts_total_row[0] or 0) if hosts_total_row else 0),
        "alerts_open": int((alerts_row[0] or 0) if alerts_row else 0),
        "avg_payload_bytes": 0.0,
        "max_payload_bytes": 0,
        "oldest_report_utc": "",
        "newest_report_utc": "",
        **files,
        "page_size": page_size,
        "page_count": page_count,
        "freelist_count": freelist_count,
        "used_pages": used_pages,
        "free_ratio": free_ratio,
        "stats_source": "lightweight",
    }


def build_db_maintenance_dashboard(conn: sqlite3.Connection) -> dict[str, object]:
    rows = conn.execute(
        """
        SELECT bucket_start_utc,
               computed_at_utc,
               retention_days,
               reports_total,
               hosts_with_reports,
               hosts_total,
               alerts_open,
               avg_payload_bytes,
               max_payload_bytes,
               db_file_bytes,
               wal_file_bytes,
               shm_file_bytes,
               total_file_bytes,
               page_size,
               page_count,
               freelist_count,
               used_pages,
               free_ratio,
               oldest_report_utc,
               newest_report_utc
        FROM db_maintenance_history
        ORDER BY bucket_start_utc DESC
        LIMIT 240
        """
    ).fetchall()
    rows = list(reversed(rows))

    history: list[dict[str, object]] = []
    for row in rows:
        history.append(
            {
                "bucket_start_utc": str(row[0] or ""),
                "computed_at_utc": str(row[1] or ""),
                "retention_days": int(row[2] or 0),
                "reports_total": int(row[3] or 0),
                "hosts_with_reports": int(row[4] or 0),
                "hosts_total": int(row[5] or 0),
                "alerts_open": int(row[6] or 0),
                "avg_payload_bytes": float(row[7] or 0.0),
                "max_payload_bytes": int(row[8] or 0),
                "db_file_bytes": int(row[9] or 0),
                "wal_file_bytes": int(row[10] or 0),
                "shm_file_bytes": int(row[11] or 0),
                "total_file_bytes": int(row[12] or 0),
                "page_size": int(row[13] or 0),
                "page_count": int(row[14] or 0),
                "freelist_count": int(row[15] or 0),
                "used_pages": int(row[16] or 0),
                "free_ratio": float(row[17] or 0.0),
                "oldest_report_utc": str(row[18] or ""),
                "newest_report_utc": str(row[19] or ""),
            }
        )

    latest_stats = history[-1] if history else _lightweight_maintenance_stats(conn)

    recent_rows: list[dict[str, object]] = []
    recent_src = history[-20:]
    for idx, row in enumerate(recent_src):
        prev = recent_src[idx - 1] if idx > 0 else None
        total_now = int(row.get("total_file_bytes", 0) or 0)
        reports_now = int(row.get("reports_total", 0) or 0)
        alerts_now = int(row.get("alerts_open", 0) or 0)
        recent_rows.append(
            {
                **row,
                "delta_total_file_bytes": None if prev is None else total_now - int(prev.get("total_file_bytes", 0) or 0),
                "delta_reports_total": None if prev is None else reports_now - int(prev.get("reports_total", 0) or 0),
                "delta_alerts_open": None if prev is None else alerts_now - int(prev.get("alerts_open", 0) or 0),
            }
        )

    forecasts: dict[str, dict[str, object]] = {}
    for metric in ("total_file_bytes", "reports_total", "alerts_open", "wal_file_bytes"):
        forecast = _forecast_linear_14d(history, metric)
        if forecast:
            forecasts[metric] = forecast

    now_local = datetime.now(SCHEDULE_TIMEZONE)
    next_bucket_local = now_local.replace(minute=0, second=0, microsecond=0)
    while (next_bucket_local.hour % DB_MAINTENANCE_INTERVAL_HOURS) != 0 or next_bucket_local <= now_local:
        next_bucket_local += timedelta(hours=1)

    return {
        "stats": latest_stats,
        "history": history,
        "recent_rows": recent_rows,
        "forecasts": forecasts,
        "schedule": {
            "timezone": SCHEDULE_TIMEZONE_NAME,
            "interval_hours": DB_MAINTENANCE_INTERVAL_HOURS,
            "next_bucket_local": next_bucket_local.isoformat(),
        },
    }


def _db_maintenance_scheduler_loop() -> None:
    while True:
        try:
            inserted = False
            with sqlite_connect_maintenance() as conn:
                inserted = _insert_db_maintenance_snapshot_if_missing(
                    conn,
                    bucket_start_utc=_maintenance_bucket_start_utc(),
                )
                conn.commit()
            if inserted:
                _read_cache_invalidate_prefix("admin-database-stats")
                _read_cache_invalidate_prefix("dashboard-db-kpis")
            _start_background_changelog_jobs(max_jobs=1)
        except Exception as exc:
            print(f"[db-maintenance-scheduler] {exc}")
        threading.Event().wait(60)


def hash_password(password: str, salt_hex: str) -> str:
    salt = bytes.fromhex(salt_hex)
    derived = hashlib.pbkdf2_hmac("sha256", password.encode("utf-8"), salt, 200000)
    return derived.hex()


def verify_password(password: str, password_hash: str, password_salt: str) -> bool:
    candidate = hash_password(password, password_salt)
    return hmac.compare_digest(candidate, password_hash)


def _execute_web_login(
    username: str,
    password: str,
    *,
    source_ip: str = "",
    user_agent: str = "",
) -> tuple[dict, str, str]:
    last_exc: sqlite3.OperationalError | None = None
    deadline = time.monotonic() + WEB_AUTH_MAX_WALL_SECONDS
    for attempt in range(WEB_AUTH_BUSY_RETRY_ATTEMPTS):
        if time.monotonic() >= deadline:
            break
        try:
            with sqlite_connect_interactive() as conn:
                conn.execute("BEGIN IMMEDIATE")
                try:
                    user = get_web_user(conn, username)
                    if not user or user.get("is_disabled"):
                        raise ValueError("invalid credentials")
                    if not verify_password(password, str(user["password_hash"]), str(user["password_salt"])):
                        raise ValueError("invalid credentials")

                    token, expires_at = create_web_session(conn, username)
                    record_web_login_event(
                        conn,
                        username=username,
                        display_name=str(user.get("display_name", "") or ""),
                        source_ip=source_ip,
                        auth_method="password",
                        user_agent=user_agent,
                    )
                    conn.commit()
                    return user, token, expires_at
                except ValueError:
                    conn.rollback()
                    raise
                except Exception:
                    conn.rollback()
                    raise
        except ValueError:
            raise
        except sqlite3.OperationalError as exc:
            if not _sqlite_operational_error_is_lock(exc):
                raise
            last_exc = exc
            if attempt + 1 >= WEB_AUTH_BUSY_RETRY_ATTEMPTS:
                break
            time.sleep(min(2.0, 0.35 * (attempt + 1)))

    if last_exc is not None:
        raise last_exc
    raise sqlite3.OperationalError("database is locked")


def create_web_session(conn: sqlite3.Connection, username: str) -> tuple[str, str]:
    now = datetime.now(timezone.utc)
    session_token = secrets.token_urlsafe(32)
    now_iso = now.strftime("%Y-%m-%dT%H:%M:%SZ")
    # Session expires after configured inactivity timeout.
    expires_iso = web_session_expires_iso()
    conn.execute(
        """
        INSERT INTO web_sessions (session_token, username, created_at_utc, expires_at_utc, last_activity_at_utc)
        VALUES (?, ?, ?, ?, ?)
        """,
        (
            session_token,
            username,
            now_iso,
            expires_iso,
            now_iso,
        ),
    )
    return session_token, expires_iso


def list_active_web_sessions(conn: sqlite3.Connection) -> list[dict]:
    session_cutoff_iso = web_session_cutoff_iso()

    # Delete sessions that have been inactive longer than the configured timeout.
    conn.execute(
        "DELETE FROM web_sessions WHERE last_activity_at_utc <= ?",
        (session_cutoff_iso,),
    )
    rows = conn.execute(
        """
        SELECT s.username,
               COALESCE(u.display_name, ''),
               COUNT(*) AS session_count,
               MAX(s.expires_at_utc) AS latest_expires_at_utc,
               MAX(s.last_activity_at_utc) AS latest_activity_at_utc
        FROM web_sessions s
        LEFT JOIN web_users u ON u.username = s.username
        WHERE last_activity_at_utc > ?
        GROUP BY s.username, u.display_name
        ORDER BY s.username COLLATE NOCASE ASC
        """,
        (session_cutoff_iso,),
    ).fetchall()
    return [
        {
            "username": str(row[0] or ""),
            "display_name": str(row[1] or ""),
            "session_count": int(row[2] or 0),
            "latest_expires_at_utc": str(row[3] or ""),
            "latest_activity_at_utc": str(row[4] or ""),
        }
        for row in rows
        if str(row[0] or "").strip()
    ]


def record_web_login_event(
    conn: sqlite3.Connection,
    username: str,
    display_name: str,
    source_ip: str,
    auth_method: str,
    user_agent: str,
) -> None:
    try:
        conn.execute(
            """
            INSERT INTO web_login_events (
                logged_at_utc,
                username,
                display_name_snapshot,
                source_ip,
                auth_method,
                user_agent
            )
            VALUES (?, ?, ?, ?, ?, ?)
            """,
            (
                utc_now_iso(),
                str(username or "").strip(),
                str(display_name or "").strip(),
                str(source_ip or "").strip(),
                str(auth_method or "password").strip() or "password",
                str(user_agent or "").strip(),
            ),
        )
    except sqlite3.OperationalError as exc:
        if "no such table: web_login_events" not in str(exc).lower():
            raise
        conn.execute(
            """
            CREATE TABLE IF NOT EXISTS web_login_events (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                logged_at_utc TEXT NOT NULL,
                username TEXT NOT NULL,
                display_name_snapshot TEXT NOT NULL DEFAULT '',
                source_ip TEXT NOT NULL DEFAULT '',
                auth_method TEXT NOT NULL DEFAULT 'password',
                user_agent TEXT NOT NULL DEFAULT ''
            )
            """
        )
        conn.execute(
            """
            CREATE INDEX IF NOT EXISTS idx_web_login_events_time
            ON web_login_events(logged_at_utc DESC)
            """
        )
        conn.execute(
            """
            INSERT INTO web_login_events (
                logged_at_utc,
                username,
                display_name_snapshot,
                source_ip,
                auth_method,
                user_agent
            )
            VALUES (?, ?, ?, ?, ?, ?)
            """,
            (
                utc_now_iso(),
                str(username or "").strip(),
                str(display_name or "").strip(),
                str(source_ip or "").strip(),
                str(auth_method or "password").strip() or "password",
                str(user_agent or "").strip(),
            ),
        )


def list_web_login_events(conn: sqlite3.Connection, limit: int = 50) -> list[dict]:
    try:
        rows = conn.execute(
            """
            SELECT logged_at_utc,
                   username,
                   display_name_snapshot,
                   source_ip,
                   auth_method
            FROM web_login_events
            ORDER BY id DESC
            LIMIT ?
            """,
            (max(1, min(int(limit or 50), 200)),),
        ).fetchall()
    except sqlite3.OperationalError as exc:
        if "no such table: web_login_events" not in str(exc).lower():
            raise
        return []
    return [
        {
            "logged_at_utc": str(row[0] or ""),
            "username": str(row[1] or ""),
            "display_name": str(row[2] or ""),
            "source_ip": str(row[3] or ""),
            "auth_method": str(row[4] or "password"),
        }
        for row in rows
    ]


