def ensure_customers_extended_columns(conn: sqlite3.Connection) -> None:
    existing_columns = {
        str(row[1] or "").strip().lower()
        for row in conn.execute("PRAGMA table_info(customers)").fetchall()
    }
    alter_statements: list[str] = []
    if "logo_filename" not in existing_columns:
        alter_statements.append("ALTER TABLE customers ADD COLUMN logo_filename TEXT NOT NULL DEFAULT ''")
    if "it_provider_name" not in existing_columns:
        alter_statements.append("ALTER TABLE customers ADD COLUMN it_provider_name TEXT NOT NULL DEFAULT ''")
    if "it_provider_contact" not in existing_columns:
        alter_statements.append("ALTER TABLE customers ADD COLUMN it_provider_contact TEXT NOT NULL DEFAULT ''")
    if "it_provider_email" not in existing_columns:
        alter_statements.append("ALTER TABLE customers ADD COLUMN it_provider_email TEXT NOT NULL DEFAULT ''")
    if "it_provider_phone" not in existing_columns:
        alter_statements.append("ALTER TABLE customers ADD COLUMN it_provider_phone TEXT NOT NULL DEFAULT ''")
    if "it_provider_name_2" not in existing_columns:
        alter_statements.append("ALTER TABLE customers ADD COLUMN it_provider_name_2 TEXT NOT NULL DEFAULT ''")
    if "it_provider_contact_2" not in existing_columns:
        alter_statements.append("ALTER TABLE customers ADD COLUMN it_provider_contact_2 TEXT NOT NULL DEFAULT ''")
    if "it_provider_email_2" not in existing_columns:
        alter_statements.append("ALTER TABLE customers ADD COLUMN it_provider_email_2 TEXT NOT NULL DEFAULT ''")
    if "it_provider_phone_2" not in existing_columns:
        alter_statements.append("ALTER TABLE customers ADD COLUMN it_provider_phone_2 TEXT NOT NULL DEFAULT ''")
    if "it_provider_name_3" not in existing_columns:
        alter_statements.append("ALTER TABLE customers ADD COLUMN it_provider_name_3 TEXT NOT NULL DEFAULT ''")
    if "it_provider_contact_3" not in existing_columns:
        alter_statements.append("ALTER TABLE customers ADD COLUMN it_provider_contact_3 TEXT NOT NULL DEFAULT ''")
    if "it_provider_email_3" not in existing_columns:
        alter_statements.append("ALTER TABLE customers ADD COLUMN it_provider_email_3 TEXT NOT NULL DEFAULT ''")
    if "it_provider_phone_3" not in existing_columns:
        alter_statements.append("ALTER TABLE customers ADD COLUMN it_provider_phone_3 TEXT NOT NULL DEFAULT ''")

    for statement in alter_statements:
        conn.execute(statement)


def _extract_it_provider_fields_from_payload(payload: dict, fallback: dict | None = None) -> dict:
    source = payload if isinstance(payload, dict) else {}
    fallback_source = fallback if isinstance(fallback, dict) else {}
    contacts = source.get("it_provider_contacts")
    contacts_list = contacts if isinstance(contacts, list) else []

    if isinstance(contacts, dict):
        # Legacy clients may send a slot-indexed object instead of a list.
        ordered_contacts: list[dict] = []
        for slot_key in ("1", "2", "3"):
            entry = contacts.get(slot_key)
            if isinstance(entry, dict):
                ordered_contacts.append(entry)
        contacts_list = ordered_contacts

    field_aliases = {
        "it_provider_name": ["it_provider_name", "provider_name", "name"],
        "it_provider_contact": ["it_provider_contact", "contact", "ansprechpartner"],
        "it_provider_email": ["it_provider_email", "email", "mail"],
        "it_provider_phone": ["it_provider_phone", "phone", "telefon", "tel"],
    }

    def _fallback_value(key: str) -> str:
        return str(fallback_source.get(key, "") or "")

    def _value(field_base: str, slot: int) -> object:
        suffix = "" if slot == 1 else f"_{slot}"
        preferred_key = f"{field_base}{suffix}"
        top_level_keys = [
            preferred_key,
            f"customer_{preferred_key}",
        ]
        for key in top_level_keys:
            if key in source:
                return source.get(key, "")

        contact_entry = contacts_list[slot - 1] if slot - 1 < len(contacts_list) else None
        if isinstance(contact_entry, dict):
            aliases = field_aliases.get(field_base, [field_base])
            for alias in aliases:
                if alias in contact_entry:
                    return contact_entry.get(alias, "")

        return _fallback_value(preferred_key)

    return {
        "it_provider_name": _value("it_provider_name", 1),
        "it_provider_contact": _value("it_provider_contact", 1),
        "it_provider_email": _value("it_provider_email", 1),
        "it_provider_phone": _value("it_provider_phone", 1),
        "it_provider_name_2": _value("it_provider_name", 2),
        "it_provider_contact_2": _value("it_provider_contact", 2),
        "it_provider_email_2": _value("it_provider_email", 2),
        "it_provider_phone_2": _value("it_provider_phone", 2),
        "it_provider_name_3": _value("it_provider_name", 3),
        "it_provider_contact_3": _value("it_provider_contact", 3),
        "it_provider_email_3": _value("it_provider_email", 3),
        "it_provider_phone_3": _value("it_provider_phone", 3),
    }


def build_customer_logo_url(customer_id: object, logo_filename: object, updated_at_utc: object = "") -> str:
    try:
        cid = int(customer_id)
    except (TypeError, ValueError):
        return ""
    if cid <= 0:
        return ""
    if not str(logo_filename or "").strip():
        return ""
    stamp = str(updated_at_utc or "").strip()
    if not stamp:
        return f"/api/v1/customers/{cid}/logo"
    return f"/api/v1/customers/{cid}/logo?v={parse.quote(stamp, safe='')}"


CUSTOMER_LOGO_ALLOWED_EXTENSIONS = {
    ".png",
    ".jpg",
    ".webp",
    ".gif",
    ".bmp",
    ".avif",
    ".ico",
    ".tif",
    ".tiff",
    ".svg",
}


def _customer_logo_extension_from_name_or_mime(file_name: object, mime_type: object) -> str:
    name_suffix = Path(str(file_name or "")).suffix.lower()
    if name_suffix == ".jpeg":
        name_suffix = ".jpg"
    elif name_suffix == ".jpe" or name_suffix == ".jfif":
        name_suffix = ".jpg"
    elif name_suffix == ".tiff":
        name_suffix = ".tif"
    if name_suffix in CUSTOMER_LOGO_ALLOWED_EXTENSIONS:
        return name_suffix
    mime = str(mime_type or "").strip().lower()
    return {
        "image/png": ".png",
        "image/x-png": ".png",
        "image/jpeg": ".jpg",
        "image/jpg": ".jpg",
        "image/pjpeg": ".jpg",
        "image/webp": ".webp",
        "image/gif": ".gif",
        "image/bmp": ".bmp",
        "image/x-bmp": ".bmp",
        "image/x-windows-bmp": ".bmp",
        "image/avif": ".avif",
        "image/x-icon": ".ico",
        "image/vnd.microsoft.icon": ".ico",
        "image/tiff": ".tif",
        "image/tif": ".tif",
        "image/svg+xml": ".svg",
    }.get(mime, "")


def _detect_customer_logo_extension_from_bytes(data: bytes) -> str:
    if len(data) >= 8 and data[:8] == b"\x89PNG\r\n\x1a\n":
        return ".png"
    if len(data) >= 3 and data[:3] == b"\xff\xd8\xff":
        return ".jpg"
    if len(data) >= 12 and data[:4] == b"RIFF" and data[8:12] == b"WEBP":
        return ".webp"
    if len(data) >= 6 and data[:6] in (b"GIF87a", b"GIF89a"):
        return ".gif"
    if len(data) >= 2 and data[:2] == b"BM":
        return ".bmp"
    if len(data) >= 12 and data[4:8] == b"ftyp":
        brand = data[8:12]
        if brand in (b"avif", b"avis"):
            return ".avif"
    if len(data) >= 4 and data[:4] in (b"II*\x00", b"MM\x00*"):
        return ".tif"
    if len(data) >= 4 and data[:4] == b"\x00\x00\x01\x00":
        return ".ico"
    head = data[:512].lstrip()
    if head.startswith(b"<svg") or head.startswith(b"<?xml"):
        return ".svg"
    return ""


def _parse_customer_logo_upload_data(image_data: object, file_name: object) -> tuple[bytes, str]:
    raw = str(image_data or "").strip()
    if not raw:
        raise ValueError("image_data fehlt.")

    mime_type = ""
    b64_payload = raw
    if raw.startswith("data:"):
        match = re.match(r"^data:([^;,]+);base64,(.+)$", raw, re.IGNORECASE | re.DOTALL)
        if not match:
            raise ValueError("image_data muss ein gültiges Data-URL-Format haben.")
        mime_type = str(match.group(1) or "").strip().lower()
        b64_payload = str(match.group(2) or "").strip()

    try:
        decoded = base64.b64decode(b64_payload, validate=True)
    except Exception as exc:
        raise ValueError("image_data ist kein gültiges Base64.") from exc
    if not decoded:
        raise ValueError("Leere Bilddaten.")
    if len(decoded) > CUSTOMER_LOGO_MAX_BYTES:
        raise ValueError(f"Logo ist zu gross (max. {CUSTOMER_LOGO_MAX_BYTES // 1024} KB).")

    file_ext = _customer_logo_extension_from_name_or_mime(file_name, mime_type)
    if file_ext not in CUSTOMER_LOGO_ALLOWED_EXTENSIONS:
        file_ext = _detect_customer_logo_extension_from_bytes(decoded)
    if file_ext not in CUSTOMER_LOGO_ALLOWED_EXTENSIONS:
        label = Path(str(file_name or "")).suffix.lower() or mime_type or "unbekannt"
        raise ValueError(
            f"Dateityp nicht unterstützt ({label}). Erlaubt sind gängige Bildformate wie PNG, JPG, WebP, GIF, SVG, BMP, AVIF, ICO und TIFF."
        )
    return decoded, file_ext


def save_customer_logo(conn: sqlite3.Connection, customer_id: object, file_name: object, image_data: object) -> dict:
    ensure_customers_extended_columns(conn)
    customer = get_customer_by_id(conn, customer_id)
    if not customer:
        raise ValueError("customer_id not found")

    decoded, file_ext = _parse_customer_logo_upload_data(image_data, file_name)
    cid = int(customer["id"])
    previous_file = str(customer.get("logo_filename", "") or "").strip()
    new_file = f"customer-{cid}{file_ext}"

    CUSTOMER_LOGOS_DIR.mkdir(parents=True, exist_ok=True)
    final_path = CUSTOMER_LOGOS_DIR / new_file
    tmp_path = CUSTOMER_LOGOS_DIR / f"{new_file}.tmp"
    tmp_path.write_bytes(decoded)
    tmp_path.replace(final_path)

    if previous_file and previous_file != new_file:
        previous_path = CUSTOMER_LOGOS_DIR / Path(previous_file).name
        if previous_path.exists() and previous_path.is_file():
            try:
                previous_path.unlink()
            except OSError:
                pass

    now_utc = utc_now_iso()
    conn.execute(
        "UPDATE customers SET logo_filename = ?, updated_at_utc = ? WHERE id = ?",
        (new_file, now_utc, cid),
    )

    updated_customer = get_customer_by_id(conn, cid)
    if not updated_customer:
        raise ValueError("Kunde konnte nach Logo-Upload nicht geladen werden.")
    return updated_customer


