def _build_sap_license_type_label_map() -> dict[str, tuple[str, str]]:
    label_map: dict[str, tuple[str, str]] = {}
    for entry in load_sap_license_type_map_entries():
        if not isinstance(entry, dict):
            continue
        raw_match_text = str(entry.get("match_text", "") or "").strip()
        display_name = str(entry.get("display_name", "") or "").strip()
        is_visible = bool(entry.get("visible", False))
        if not raw_match_text or not display_name or not is_visible:
            continue
        normalized_key = raw_match_text.upper()
        if normalized_key in label_map:
            continue
        label_map[normalized_key] = (raw_match_text, display_name)
    return label_map


def _extract_translated_sap_license_type_counts(
    payload: dict,
    *,
    license_label_map: dict[str, tuple[str, str]] | None = None,
) -> dict[str, int]:
    label_map = license_label_map or _build_sap_license_type_label_map()
    if not label_map:
        return {}

    sap_license = payload.get("sap_license") if isinstance(payload, dict) else None
    focus_license_types = sap_license.get("focus_license_types") if isinstance(sap_license, dict) else []

    raw_counts: dict[str, int] = {}
    if isinstance(focus_license_types, list):
        for item in focus_license_types:
            if not isinstance(item, dict):
                continue
            raw_type = str(item.get("license_type", "") or "").strip().upper()
            if not raw_type:
                continue
            count_raw = item.get("count", 0)
            try:
                count_value = int(float(str(count_raw).strip()))
            except (TypeError, ValueError):
                count_value = 0
            raw_counts[raw_type] = raw_counts.get(raw_type, 0) + max(0, count_value)

    # Only include types that are BOTH in the payload (raw_counts) AND have a translation (label_map).
    # Types present in the payload but not translated are excluded.
    # Types present in label_map but absent from the payload are excluded entirely.
    translated_counts: dict[str, int] = {}
    for raw_type_upper in sorted(raw_counts.keys()):
        if raw_type_upper not in label_map:
            continue
        translated_counts[raw_type_upper] = int(raw_counts[raw_type_upper] or 0)
    return translated_counts


def _host_config_field_label(field_key: str, *, license_label_map: dict[str, tuple[str, str]] | None = None) -> str:
    field_key_text = str(field_key or "").strip()
    if not field_key_text:
        return "-"

    static_label = HOST_CONFIG_FIELD_LABELS.get(field_key_text)
    if static_label:
        return static_label

    if field_key_text.startswith(SAP_LICENSE_TYPE_FIELD_PREFIX):
        match_text = field_key_text[len(SAP_LICENSE_TYPE_FIELD_PREFIX):].strip()
        normalized_match_text = match_text.upper()
        label_map = license_label_map or _build_sap_license_type_label_map()
        mapped = label_map.get(normalized_match_text)
        if mapped:
            raw_match_text, display_name = mapped
            return f"{display_name} ({raw_match_text})"
        return match_text or "-"

    if field_key_text.startswith("sap_addon::"):
        addon_name = field_key_text[len("sap_addon::"):]
        label_source, plain_name = _describe_sap_addon_key(addon_name)
        return f"{label_source}: {plain_name}"

    return field_key_text


def _ensure_host_config_snapshot_schema(conn: sqlite3.Connection) -> None:
    columns = {
        str(row[1])
        for row in conn.execute("PRAGMA table_info(host_config_snapshot)").fetchall()
    }
    if "kernel_release" not in columns:
        conn.execute("ALTER TABLE host_config_snapshot ADD COLUMN kernel_release TEXT NOT NULL DEFAULT '-'")
    if "sap_services_ports" not in columns:
        conn.execute("ALTER TABLE host_config_snapshot ADD COLUMN sap_services_ports TEXT NOT NULL DEFAULT '-'")
    conn.execute(
        """
        CREATE TABLE IF NOT EXISTS host_license_type_snapshot (
            host_uid TEXT NOT NULL,
            hostname TEXT NOT NULL,
            license_type_match_text TEXT NOT NULL,
            count_value INTEGER NOT NULL DEFAULT 0,
            updated_at_utc TEXT NOT NULL,
            PRIMARY KEY(host_uid, license_type_match_text)
        )
        """
    )
    conn.execute(
        """
        CREATE INDEX IF NOT EXISTS idx_host_license_type_snapshot_host
        ON host_license_type_snapshot(host_uid, updated_at_utc DESC)
        """
    )


def _normalize_config_value(field_key: str, value: object) -> str:
    raw = str(value or "").strip()
    if not raw:
        return "-"

    lowered = raw.lower()
    if lowered in {"-", "na", "n/a", "none", "null", "unknown", "unbekannt", "not available"}:
        return "-"

    if field_key in {"ram_gb", "cpu_cores"}:
        try:
            parsed = int(float(raw))
            return str(parsed) if parsed > 0 else "-"
        except (TypeError, ValueError):
            return "-"

    normalized = re.sub(r"\s+", " ", raw)
    if field_key == "hana_sid":
        return normalized.upper()
    return normalized


def _canonical_config_value(field_key: str, value: str) -> str:
    if field_key in {"ram_gb", "cpu_cores"}:
        return value
    return value.lower()


def _is_significant_config_change(field_key: str, old_value: str, new_value: str) -> bool:
    if old_value == new_value:
        return False

    old_canonical = _canonical_config_value(field_key, old_value)
    new_canonical = _canonical_config_value(field_key, new_value)
    if old_canonical == new_canonical:
        return False

    if field_key == "ram_gb" and old_value != "-" and new_value != "-":
        try:
            return abs(int(new_value) - int(old_value)) >= 1
        except (TypeError, ValueError):
            return True

    return True


def _extract_os_release(payload: dict) -> str:
    os_value = payload.get("os") if isinstance(payload, dict) else ""
    return str(os_value or "").strip() or "-"


def _extract_kernel_release(payload: dict) -> str:
    kernel_value = payload.get("kernel") if isinstance(payload, dict) else ""
    return str(kernel_value or "").strip() or "-"


def _extract_sql_release(payload: dict) -> str:
    sql_release = "-"
    sql_block = payload.get("sql_server_info")
    if isinstance(sql_block, dict) and sql_block.get("available") is True:
        instances = sql_block.get("instances")
        if isinstance(instances, list) and instances:
            first = instances[0]
            if isinstance(first, dict):
                sql_release = _map_sql_release(str(first.get("version", "")).strip())
    return str(sql_release or "-").strip() or "-"


def _extract_host_config_snapshot(payload: dict) -> dict[str, str]:
    release_info = _extract_sap_hana_ram(payload)
    cpu_info = _extract_cpu_overview(payload)
    return {
        "os_release": _extract_os_release(payload),
        "kernel_release": _extract_kernel_release(payload),
        "cpu_cores": str(cpu_info["cpu_cores"]),
        "cpu_model_name": str(cpu_info["cpu_model_name"]),
        "ram_gb": str(release_info["ram_gb"]),
        "sap_release": str(release_info["sap_release"]),
        "hana_release": str(release_info["hana_version"]),
        "hana_sid": str(release_info["hana_sid"]),
        "sql_release": _extract_sql_release(payload),
    }


def _track_host_license_type_changes(
    conn: sqlite3.Connection,
    hostname: str,
    host_uid: str,
    payload: dict,
    report_id: int,
    detected_at_utc: str,
) -> None:
    if not hostname:
        return

    host_key = alert_host_key(hostname, host_uid)
    license_label_map = _build_sap_license_type_label_map()
    new_counts = _extract_translated_sap_license_type_counts(payload, license_label_map=license_label_map)
    if not new_counts:
        return

    existing_rows = conn.execute(
        """
        SELECT license_type_match_text, count_value
        FROM host_license_type_snapshot
        WHERE host_uid = ?
        """,
        (host_key,),
    ).fetchall()
    old_counts = {
        str(row[0] or "").strip().upper(): max(0, int(row[1] or 0))
        for row in existing_rows
        if str(row[0] or "").strip()
    }
    has_existing_snapshot = bool(existing_rows)

    dedupe_cutoff = (datetime.now(timezone.utc) - timedelta(minutes=30)).strftime("%Y-%m-%dT%H:%M:%SZ")
    for match_text_upper in sorted(new_counts.keys()):
        field_key = f"{SAP_LICENSE_TYPE_FIELD_PREFIX}{match_text_upper}"
        new_count = int(new_counts.get(match_text_upper, 0) or 0)

        if not has_existing_snapshot or match_text_upper not in old_counts:
            old_value = "-"
            new_value = str(new_count)
            # Skip init entries where nothing was ever licensed
            if new_count == 0:
                continue
            should_insert = True
            source_value = "agent-report:license-init"
        else:
            old_count = int(old_counts.get(match_text_upper, 0) or 0)
            old_value = str(old_count)
            new_value = str(new_count)
            # Skip if both are 0 (no meaningful change)
            if old_count == 0 and new_count == 0:
                continue
            should_insert = old_count != new_count
            source_value = "agent-report:license"

        if not should_insert:
            continue

        duplicate = conn.execute(
            """
            SELECT 1
            FROM host_config_changes
            WHERE host_uid = ?
              AND field_key = ?
              AND old_value = ?
              AND new_value = ?
              AND detected_at_utc >= ?
            ORDER BY id DESC
            LIMIT 1
            """,
            (host_key, field_key, old_value, new_value, dedupe_cutoff),
        ).fetchone()
        if duplicate:
            continue

        conn.execute(
            """
            INSERT INTO host_config_changes (
                detected_at_utc,
                host_uid,
                hostname,
                field_key,
                old_value,
                new_value,
                report_id,
                source
            )
            VALUES (?, ?, ?, ?, ?, ?, ?, ?)
            """,
            (detected_at_utc, host_key, hostname, field_key, old_value, new_value, report_id, source_value),
        )

    conn.execute("DELETE FROM host_license_type_snapshot WHERE host_uid = ?", (host_key,))
    for match_text_upper in sorted(new_counts.keys()):
        conn.execute(
            """
            INSERT INTO host_license_type_snapshot (
                host_uid,
                hostname,
                license_type_match_text,
                count_value,
                updated_at_utc
            )
            VALUES (?, ?, ?, ?, ?)
            """,
            (host_key, hostname, match_text_upper, int(new_counts.get(match_text_upper, 0) or 0), detected_at_utc),
        )


def _track_host_config_changes(
    conn: sqlite3.Connection,
    hostname: str,
    host_uid: str,
    payload: dict,
    report_id: int,
    detected_at_utc: str,
) -> None:
    _ensure_host_config_snapshot_schema(conn)

    if not hostname:
        return
    host_key = alert_host_key(hostname, host_uid)

    new_snapshot_raw = _extract_host_config_snapshot(payload)
    new_snapshot = {
        key: _normalize_config_value(key, new_snapshot_raw.get(key, "-"))
        for key in HOST_CONFIG_TRACKED_FIELDS
    }

    existing_row = conn.execute(
        """
        SELECT os_release, kernel_release, cpu_cores, cpu_model_name, ram_gb, sap_release, hana_release, hana_sid, sql_release
        FROM host_config_snapshot
        WHERE hostname = ?
        """,
        (host_key,),
    ).fetchone()

    if existing_row:
        old_snapshot = {
            "os_release": _normalize_config_value("os_release", existing_row[0]),
            "kernel_release": _normalize_config_value("kernel_release", existing_row[1]),
            "cpu_cores": _normalize_config_value("cpu_cores", existing_row[2]),
            "cpu_model_name": _normalize_config_value("cpu_model_name", existing_row[3]),
            "ram_gb": _normalize_config_value("ram_gb", existing_row[4]),
            "sap_release": _normalize_config_value("sap_release", existing_row[5]),
            "hana_release": _normalize_config_value("hana_release", existing_row[6]),
            "hana_sid": _normalize_config_value("hana_sid", existing_row[7]),
            "sql_release": _normalize_config_value("sql_release", existing_row[8]),
        }

        dedupe_cutoff = (datetime.now(timezone.utc) - timedelta(minutes=30)).strftime("%Y-%m-%dT%H:%M:%SZ")
        for field_key in HOST_CONFIG_TRACKED_FIELDS:
            old_value = old_snapshot.get(field_key, "-")
            new_value = new_snapshot.get(field_key, "-")
            if not _is_significant_config_change(field_key, old_value, new_value):
                continue

            duplicate = conn.execute(
                """
                SELECT 1
                FROM host_config_changes
                WHERE host_uid = ?
                  AND field_key = ?
                  AND old_value = ?
                  AND new_value = ?
                  AND detected_at_utc >= ?
                ORDER BY id DESC
                LIMIT 1
                """,
                (host_key, field_key, old_value, new_value, dedupe_cutoff),
            ).fetchone()
            if duplicate:
                continue

            conn.execute(
                """
                INSERT INTO host_config_changes (
                    detected_at_utc,
                    host_uid,
                    hostname,
                    field_key,
                    old_value,
                    new_value,
                    report_id,
                    source
                )
                VALUES (?, ?, ?, ?, ?, ?, ?, 'agent-report')
                """,
                (detected_at_utc, host_key, hostname, field_key, old_value, new_value, report_id),
            )
    else:
        dedupe_cutoff = (datetime.now(timezone.utc) - timedelta(minutes=30)).strftime("%Y-%m-%dT%H:%M:%SZ")
        for field_key in HOST_CONFIG_TRACKED_FIELDS:
            old_value = "-"
            new_value = new_snapshot.get(field_key, "-")
            if not _is_significant_config_change(field_key, old_value, new_value):
                continue
            duplicate = conn.execute(
                """
                SELECT 1
                FROM host_config_changes
                WHERE host_uid = ?
                  AND field_key = ?
                  AND old_value = ?
                  AND new_value = ?
                  AND detected_at_utc >= ?
                LIMIT 1
                """,
                (host_key, field_key, old_value, new_value, dedupe_cutoff),
            ).fetchone()
            if duplicate:
                continue
            conn.execute(
                """
                INSERT INTO host_config_changes (
                    detected_at_utc,
                    host_uid,
                    hostname,
                    field_key,
                    old_value,
                    new_value,
                    report_id,
                    source
                )
                VALUES (?, ?, ?, ?, ?, ?, ?, 'agent-report:init')
                """,
                (detected_at_utc, host_key, hostname, field_key, old_value, new_value, report_id),
            )

    conn.execute(
        """
        INSERT INTO host_config_snapshot (
            hostname,
            os_release,
            kernel_release,
            cpu_cores,
            cpu_model_name,
            ram_gb,
            sap_release,
            hana_release,
            hana_sid,
            sql_release,
            updated_at_utc
        )
        VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
        ON CONFLICT(hostname) DO UPDATE SET
            os_release = excluded.os_release,
            kernel_release = excluded.kernel_release,
            cpu_cores = excluded.cpu_cores,
            cpu_model_name = excluded.cpu_model_name,
            ram_gb = excluded.ram_gb,
            sap_release = excluded.sap_release,
            hana_release = excluded.hana_release,
            hana_sid = excluded.hana_sid,
            sql_release = excluded.sql_release,
            updated_at_utc = excluded.updated_at_utc
        """,
        (
            host_key,
            new_snapshot["os_release"],
            new_snapshot["kernel_release"],
            new_snapshot["cpu_cores"],
            new_snapshot["cpu_model_name"],
            new_snapshot["ram_gb"],
            new_snapshot["sap_release"],
            new_snapshot["hana_release"],
            new_snapshot["hana_sid"],
            new_snapshot["sql_release"],
            detected_at_utc,
        ),
    )

    _track_host_license_type_changes(conn, hostname, host_key, payload, report_id, detected_at_utc)


def _extract_sap_addon_snapshot(payload: dict) -> dict[str, str]:
    sap_block = payload.get("sap_business_one") if isinstance(payload, dict) else None
    if not isinstance(sap_block, dict):
        return {}

    snapshot: dict[str, str] = {}

    def _clean_text(value: object) -> str:
        text = str(value or "").strip()
        if text.startswith('"'):
            text = text[1:].strip()
        if text.endswith('"'):
            text = text[:-1].strip()
        if text.startswith("'"):
            text = text[1:].strip()
        if text.endswith("'"):
            text = text[:-1].strip()
        return text

    def _looks_like_hdbsql_footer(raw_text: str) -> bool:
        lower = raw_text.strip().lower()
        return "rows selected" in lower or "overall time" in lower or "server time" in lower

    def _parse_combined_pair(raw_name: str) -> tuple[str, str] | None:
        candidates = [raw_name]
        if raw_name and not raw_name.startswith('"'):
            candidates.append(f'"{raw_name}')
        if raw_name and not raw_name.endswith('"'):
            candidates.append(f'{raw_name}"')
        if raw_name and not raw_name.startswith('"') and not raw_name.endswith('"'):
            candidates.append(f'"{raw_name}"')

        for candidate in candidates:
            try:
                parsed = next(csv.reader([candidate], skipinitialspace=True))
            except Exception:
                continue
            if len(parsed) < 2:
                continue
            left = _clean_text(parsed[0])
            right = _clean_text(parsed[1])
            if left:
                return left, right
        return None

    def _normalize_pair(name_value: object, version_value: object) -> tuple[str, str]:
        raw_name = str(name_value or "").strip()
        name = _clean_text(name_value)
        version = _clean_text(version_value)

        if _looks_like_hdbsql_footer(raw_name):
            return "", "-"

        # Some collectors delivered combined CSV-like pairs in the name field:
        #   "Addon Name","1.2.3"
        # Normalize those into clean name/version values.
        if not version or version in {"?", "-"}:
            parsed_pair = _parse_combined_pair(raw_name)
            if parsed_pair is not None:
                left, right = parsed_pair
                name = left or name
                version = right or version

        name = _clean_text(name)
        version = _clean_text(version)

        if _looks_like_hdbsql_footer(name):
            return "", "-"

        return name, (version or "-")

    ext_block = sap_block.get("extensions")
    ext_rows = ext_block.get("rows") if isinstance(ext_block, dict) else []
    if not isinstance(ext_rows, list):
        ext_rows = []
    for row in ext_rows:
        if not isinstance(row, dict):
            continue
        addon_name, addon_version = _normalize_pair(row.get("AddOnName"), row.get("Version"))
        if not addon_name:
            continue
        snapshot[f"extensions::{addon_name}"] = addon_version

    sari_block = sap_block.get("sari_addons")
    sari_rows = sari_block.get("rows") if isinstance(sari_block, dict) else []
    if not isinstance(sari_rows, list):
        sari_rows = []
    for row in sari_rows:
        if not isinstance(row, dict):
            continue
        addon_name, addon_version = _normalize_pair(row.get("AName"), row.get("AddOnVer"))
        if not addon_name:
            continue
        snapshot[f"sari::{addon_name}"] = addon_version

    hana_block = payload.get("hana_addons") if isinstance(payload, dict) else None
    if isinstance(hana_block, dict):
        hana_lw_rows = hana_block.get("lightweight")
        if not isinstance(hana_lw_rows, list):
            hana_lw_rows = []
        for row in hana_lw_rows:
            if not isinstance(row, dict):
                continue
            addon_name, addon_version = _normalize_pair(row.get("name"), row.get("version"))
            if not addon_name:
                continue
            snapshot[f"hana_extensions::{addon_name}"] = addon_version

        hana_legacy_rows = hana_block.get("legacy")
        if not isinstance(hana_legacy_rows, list):
            hana_legacy_rows = []
        for row in hana_legacy_rows:
            if not isinstance(row, dict):
                continue
            addon_name, addon_version = _normalize_pair(row.get("name"), row.get("version"))
            if not addon_name:
                continue
            snapshot[f"hana_sari::{addon_name}"] = addon_version

        tenant_rows = hana_block.get("tenants")
        if not isinstance(tenant_rows, list):
            tenant_rows = []
        for tenant_row in tenant_rows:
            if not isinstance(tenant_row, dict):
                continue
            tenant_id = _clean_text(tenant_row.get("tenant_id"))
            tenant_prefix = f"tenant{tenant_id}::" if tenant_id else "tenant::"
            tenant_result = tenant_row.get("result") if isinstance(tenant_row.get("result"), dict) else tenant_row

            tenant_lw_rows = tenant_result.get("lightweight")
            if not isinstance(tenant_lw_rows, list):
                tenant_lw_rows = []
            for row in tenant_lw_rows:
                if not isinstance(row, dict):
                    continue
                addon_name, addon_version = _normalize_pair(row.get("name"), row.get("version"))
                if not addon_name:
                    continue
                snapshot[f"hana_extensions::{tenant_prefix}{addon_name}"] = addon_version

            tenant_legacy_rows = tenant_result.get("legacy")
            if not isinstance(tenant_legacy_rows, list):
                tenant_legacy_rows = []
            for row in tenant_legacy_rows:
                if not isinstance(row, dict):
                    continue
                addon_name, addon_version = _normalize_pair(row.get("name"), row.get("version"))
                if not addon_name:
                    continue
                snapshot[f"hana_sari::{tenant_prefix}{addon_name}"] = addon_version

    return snapshot


def _describe_sap_addon_key(addon_name: str) -> tuple[str, str]:
    label_source = "Lightweight Extension"
    plain_name = addon_name
    if addon_name.startswith("extensions::"):
        plain_name = addon_name.split("::", 1)[1]
        label_source = "LW"
    elif addon_name.startswith("sari::"):
        plain_name = addon_name.split("::", 1)[1]
        label_source = "Legacy"
    elif addon_name.startswith("hana_extensions::"):
        plain_name = addon_name.split("::", 1)[1]
        label_source = "LW"
    elif addon_name.startswith("hana_sari::"):
        plain_name = addon_name.split("::", 1)[1]
        label_source = "Legacy"

    if plain_name:
        plain_name = re.sub(r"(?i)^tenant", "", plain_name)
        plain_name = plain_name.replace("::", ":").lstrip(":")
    return label_source, plain_name


def _ensure_host_addon_snapshot_schema(conn: sqlite3.Connection) -> None:
    conn.execute(
        """
        CREATE TABLE IF NOT EXISTS host_addon_snapshot (
            host_uid TEXT PRIMARY KEY,
            hostname TEXT NOT NULL,
            snapshot_json TEXT NOT NULL DEFAULT '{}',
            updated_at_utc TEXT NOT NULL
        )
        """
    )


def _insert_sap_addon_change_row(
    conn: sqlite3.Connection,
    *,
    detected_at_utc: str,
    host_key: str,
    hostname: str,
    addon_name: str,
    old_value: str,
    new_value: str,
    report_id: int,
    source: str,
    skip_duplicate_check: bool = False,
) -> bool:
    field_key = f"sap_addon::{addon_name}"
    if not skip_duplicate_check:
        existing = conn.execute(
            """
            SELECT 1
            FROM host_config_changes
            WHERE host_uid = ?
              AND field_key = ?
              AND report_id = ?
              AND old_value = ?
              AND new_value = ?
            LIMIT 1
            """,
            (host_key, field_key, report_id, old_value, new_value),
        ).fetchone()
        if existing:
            return False
    conn.execute(
        """
        INSERT INTO host_config_changes (
            detected_at_utc,
            host_uid,
            hostname,
            field_key,
            old_value,
            new_value,
            report_id,
            source
        )
        VALUES (?, ?, ?, ?, ?, ?, ?, ?)
        """,
        (detected_at_utc, host_key, hostname, field_key, old_value, new_value, report_id, source),
    )
    return True


def backfill_sap_addon_changes(
    conn: sqlite3.Connection,
    days: int = 7,
    progress_callback=None,
    include_initial_snapshot_events: bool = False,
    job_id: int = 0,
    skip_pre_seed: bool = False,
    phase_steps_total: int = 3,
    inventory_greenfield: bool = False,
) -> dict:
    _ensure_host_addon_snapshot_schema(conn)

    window_days = _changelog_window_days(days)
    cutoff_iso = _changelog_cutoff_iso(days)
    reports_total = _count_reports_for_changelog_days(conn, window_days)

    reports_sql = """
        SELECT id, received_at_utc, hostname, COALESCE(host_uid, ''), payload_json
        FROM reports
    """
    reports_params: tuple = ()
    if cutoff_iso is not None:
        reports_sql += " WHERE received_at_utc >= ?"
        reports_params = (cutoff_iso,)
    reports_sql += " ORDER BY COALESCE(NULLIF(host_uid, ''), hostname) COLLATE NOCASE ASC, id ASC"

    last_snapshot_by_host_key: dict[str, dict[str, str]] = {}
    last_hostname_by_host_key: dict[str, str] = {}
    last_seen_at_by_host_key: dict[str, str] = {}

    if not skip_pre_seed and cutoff_iso is not None:
        pre_rows = conn.execute(
            """
            SELECT r.hostname, COALESCE(r.host_uid, ''), r.payload_json
            FROM reports r
            INNER JOIN (
                SELECT COALESCE(NULLIF(host_uid, ''), hostname) AS hkey, MAX(id) AS max_id
                FROM reports
                WHERE received_at_utc < ?
                GROUP BY hkey
            ) pre ON pre.max_id = r.id
            """,
            (cutoff_iso,),
        ).fetchall()
        for pre_row in pre_rows:
            pre_hostname = str(pre_row[0] or "").strip()
            pre_host_uid = str(pre_row[1] or "").strip()
            if not pre_hostname:
                continue
            pre_host_key = alert_host_key(pre_hostname, pre_host_uid)
            pre_payload = parse_payload_json(str(pre_row[2] or "{}"))
            last_snapshot_by_host_key[pre_host_key] = _extract_sap_addon_snapshot(pre_payload)

    report_count = 0
    inserted_changes = 0
    hosts_processed = 0
    last_progress_host_key = ""
    last_progress_emit_mono = 0.0
    addon_phase_step = 3 if int(phase_steps_total or 3) >= 4 else 2
    skip_dup = bool(inventory_greenfield)

    if callable(progress_callback):
        try:
            progress_callback({
                "phase": "addon_backfill",
                "phase_step": addon_phase_step,
                "phase_steps_total": int(phase_steps_total or 3),
                "reports_total": reports_total,
                "reports_scanned": 0,
                "hosts_processed": 0,
                "hosts_total": 0,
                "inserted_changes": 0,
                "message": "SAP-Add-ons (Extensions/SARI/HANA)…",
            })
            last_progress_emit_mono = time.monotonic()
        except Exception:
            pass
    conn.commit()

    read_conn = _changelog_read_connect()
    try:
        for batch in _iter_changelog_report_batches(
            read_conn,
            reports_sql,
            reports_params,
            batch_size=_CHANGELOG_INVENTORY_FETCH_BATCH_SIZE if inventory_greenfield else _CHANGELOG_REPORT_FETCH_BATCH_SIZE,
        ):
            for row in batch:
                report_id = int(row[0] or 0)
                detected_at_utc = str(row[1] or "").strip()
                hostname = str(row[2] or "").strip()
                host_uid = str(row[3] or "").strip()
                payload = parse_payload_json(str(row[4] or "{}"))
                if not hostname:
                    continue
                host_key = alert_host_key(hostname, host_uid)
                host_changed = host_key != last_progress_host_key
                if host_changed:
                    hosts_processed += 1
                    last_progress_host_key = host_key

                report_count += 1
                if inventory_greenfield and report_count == 1:
                    conn.commit()
                current_snapshot = _extract_sap_addon_snapshot(payload)
                previous_snapshot = last_snapshot_by_host_key.get(host_key)

                if _should_check_changelog_job_cancel(report_count, reports_total) or host_changed:
                    _ensure_changelog_job_running(conn, job_id)

                if previous_snapshot is not None:
                    addon_names = sorted(set(previous_snapshot.keys()) | set(current_snapshot.keys()), key=str.lower)
                    for addon_name in addon_names:
                        old_value = str(previous_snapshot.get(addon_name, "-") or "-")
                        new_value = str(current_snapshot.get(addon_name, "-") or "-")
                        if old_value == new_value:
                            continue
                        if _insert_sap_addon_change_row(
                            conn,
                            detected_at_utc=detected_at_utc or utc_now_iso(),
                            host_key=host_key,
                            hostname=hostname,
                            addon_name=addon_name,
                            old_value=old_value,
                            new_value=new_value,
                            report_id=report_id,
                            source="backfill-addon",
                            skip_duplicate_check=skip_dup,
                        ):
                            inserted_changes += 1
                            if inventory_greenfield:
                                conn.commit()
                elif include_initial_snapshot_events:
                    for addon_name in sorted(current_snapshot.keys(), key=str.lower):
                        new_value = str(current_snapshot.get(addon_name, "-") or "-")
                        if new_value == "-":
                            continue
                        if _insert_sap_addon_change_row(
                            conn,
                            detected_at_utc=detected_at_utc or utc_now_iso(),
                            host_key=host_key,
                            hostname=hostname,
                            addon_name=addon_name,
                            old_value="-",
                            new_value=new_value,
                            report_id=report_id,
                            source="backfill-addon-init",
                            skip_duplicate_check=skip_dup,
                        ):
                            inserted_changes += 1
                            if inventory_greenfield:
                                conn.commit()

                last_snapshot_by_host_key[host_key] = current_snapshot
                last_hostname_by_host_key[host_key] = hostname
                last_seen_at_by_host_key[host_key] = detected_at_utc or utc_now_iso()

                if callable(progress_callback):
                    now_mono = time.monotonic()
                    emit_progress = (
                        _should_emit_changelog_progress(
                            report_count,
                            reports_total,
                            host_changed=host_changed,
                        )
                        or (now_mono - last_progress_emit_mono)
                        >= CHANGELOG_PROGRESS_FLUSH_INTERVAL_SEC
                    )
                    if emit_progress:
                        try:
                            progress_callback({
                                "phase": "addon_backfill",
                                "phase_step": addon_phase_step,
                                "phase_steps_total": int(phase_steps_total or 3),
                                "reports_total": reports_total,
                                "reports_scanned": report_count,
                                "hosts_processed": hosts_processed,
                                "hosts_total": hosts_processed,
                                "current_host": hostname,
                                "inserted_changes": inserted_changes,
                                "message": f"Report {report_count}/{reports_total}: {hostname}…",
                            })
                            last_progress_emit_mono = now_mono
                        except Exception:
                            pass

                if inventory_greenfield:
                    if report_count % 250 == 0 or report_count == reports_total:
                        conn.commit()
                elif report_count % 1000 == 0:
                    conn.commit()

    finally:
        read_conn.close()

    conn.commit()

    snapshot_hosts = list(last_snapshot_by_host_key.items())

    def _emit_addon_finalize_progress(message: str, *, current_host: str = "") -> None:
        if not callable(progress_callback):
            return
        try:
            progress_callback({
                "phase": "addon_backfill",
                "phase_step": addon_phase_step,
                "phase_steps_total": int(phase_steps_total or 3),
                "reports_total": reports_total,
                "reports_scanned": report_count,
                "hosts_processed": hosts_processed,
                "hosts_total": hosts_processed,
                "current_host": current_host,
                "inserted_changes": inserted_changes,
                "message": message,
            })
        except Exception:
            pass

    _emit_addon_finalize_progress(
        f"SAP-Add-ons: Reports fertig ({report_count}/{reports_total}), Speichere Snapshots…"
    )

    finalize_conn = sqlite_connect()
    try:
        finalize_conn.execute(f"PRAGMA busy_timeout = {_maintenance_sqlite_busy_timeout_ms()}")
        for snap_idx, (host_key, snapshot) in enumerate(snapshot_hosts, start=1):
            updated_at_utc = last_seen_at_by_host_key.get(host_key, utc_now_iso())
            hostname_value = str(last_hostname_by_host_key.get(host_key, host_key) or host_key)
            finalize_conn.execute(
                """
                INSERT INTO host_addon_snapshot (host_uid, hostname, snapshot_json, updated_at_utc)
                VALUES (?, ?, ?, ?)
                ON CONFLICT(host_uid) DO UPDATE SET
                    hostname = excluded.hostname,
                    snapshot_json = excluded.snapshot_json,
                    updated_at_utc = excluded.updated_at_utc
                """,
                (
                    host_key,
                    hostname_value,
                    json.dumps(snapshot, separators=(",", ":")),
                    updated_at_utc,
                ),
            )
            finalize_conn.commit()
            if inventory_greenfield or snap_idx == 1 or snap_idx == len(snapshot_hosts) or snap_idx % 5 == 0:
                _emit_addon_finalize_progress(
                    f"SAP-Add-ons: Speichere Snapshots ({snap_idx}/{len(snapshot_hosts)})…",
                    current_host=hostname_value,
                )
    finally:
        finalize_conn.close()

    _emit_addon_finalize_progress("SAP-Add-ons abgeschlossen, weiter mit DB-Lifecycle…")
    conn.commit()

    return {
        "days": window_days,
        "reports_scanned": report_count,
        "hosts_processed": hosts_processed,
        "inserted_changes": inserted_changes,
    }


def _track_sap_addon_changes(
    conn: sqlite3.Connection,
    hostname: str,
    host_uid: str,
    payload: dict,
    report_id: int,
    detected_at_utc: str,
) -> None:
    if not hostname:
        return
    _ensure_host_addon_snapshot_schema(conn)
    host_key = alert_host_key(hostname, host_uid)
    current_snapshot = _extract_sap_addon_snapshot(payload)

    row = conn.execute(
        "SELECT snapshot_json FROM host_addon_snapshot WHERE host_uid = ?",
        (host_key,),
    ).fetchone()
    previous_snapshot: dict[str, str] | None = None
    if row:
        try:
            parsed = json.loads(str(row[0] or "{}"))
            if isinstance(parsed, dict):
                previous_snapshot = {str(k): str(v or "-") for k, v in parsed.items()}
        except json.JSONDecodeError:
            previous_snapshot = None

    dedupe_cutoff = (datetime.now(timezone.utc) - timedelta(minutes=30)).strftime("%Y-%m-%dT%H:%M:%SZ")

    if previous_snapshot is not None:
        addon_names = sorted(set(previous_snapshot.keys()) | set(current_snapshot.keys()), key=str.lower)
        for addon_name in addon_names:
            old_value = str(previous_snapshot.get(addon_name, "-") or "-")
            new_value = str(current_snapshot.get(addon_name, "-") or "-")
            if old_value == new_value:
                continue
            duplicate = conn.execute(
                """
                SELECT 1
                FROM host_config_changes
                WHERE host_uid = ?
                  AND field_key = ?
                  AND old_value = ?
                  AND new_value = ?
                  AND detected_at_utc >= ?
                LIMIT 1
                """,
                (host_key, f"sap_addon::{addon_name}", old_value, new_value, dedupe_cutoff),
            ).fetchone()
            if duplicate:
                continue
            _insert_sap_addon_change_row(
                conn,
                detected_at_utc=detected_at_utc,
                host_key=host_key,
                hostname=hostname,
                addon_name=addon_name,
                old_value=old_value,
                new_value=new_value,
                report_id=report_id,
                source="agent-report:addon",
            )
    else:
        for addon_name in sorted(current_snapshot.keys(), key=str.lower):
            new_value = str(current_snapshot.get(addon_name, "-") or "-")
            if new_value == "-":
                continue
            _insert_sap_addon_change_row(
                conn,
                detected_at_utc=detected_at_utc,
                host_key=host_key,
                hostname=hostname,
                addon_name=addon_name,
                old_value="-",
                new_value=new_value,
                report_id=report_id,
                source="agent-report:addon-init",
            )

    conn.execute(
        """
        INSERT INTO host_addon_snapshot (host_uid, hostname, snapshot_json, updated_at_utc)
        VALUES (?, ?, ?, ?)
        ON CONFLICT(host_uid) DO UPDATE SET
            hostname = excluded.hostname,
            snapshot_json = excluded.snapshot_json,
            updated_at_utc = excluded.updated_at_utc
        """,
        (host_key, hostname, json.dumps(current_snapshot, separators=(",", ":")), detected_at_utc),
    )


def _collect_sap_addon_change_items_for_host(conn: sqlite3.Connection, hostname: str, host_uid: str = "") -> list[dict]:
    host_uid_value = str(host_uid or "").strip()
    if host_uid_value:
        host_key_expr = reports_host_key_sql()
        rows = conn.execute(
            f"""
            SELECT id, received_at_utc, payload_json
            FROM reports
            WHERE {host_key_expr} = ?
            ORDER BY id ASC
            """,
            (host_uid_value,),
        ).fetchall()
    else:
        rows = conn.execute(
            """
            SELECT id, received_at_utc, payload_json
            FROM reports
            WHERE hostname = ?
            ORDER BY id ASC
            """,
            (hostname,),
        ).fetchall()

    previous_snapshot: dict[str, str] | None = None
    changes: list[dict] = []

    for row in rows:
        report_id = int(row[0] or 0)
        detected_at_utc = str(row[1] or "")
        payload = parse_payload_json(str(row[2] or "{}"))
        current_snapshot = _extract_sap_addon_snapshot(payload)

        if previous_snapshot is not None:
            addon_names = sorted(set(previous_snapshot.keys()) | set(current_snapshot.keys()), key=lambda x: x.lower())
            for addon_name in addon_names:
                old_version = str(previous_snapshot.get(addon_name, "-") or "-")
                new_version = str(current_snapshot.get(addon_name, "-") or "-")
                if old_version == new_version:
                    continue

                label_source, plain_name = _describe_sap_addon_key(addon_name)
                changes.append(
                    {
                        "id": report_id,
                        "detected_at_utc": detected_at_utc,
                        "field_key": f"sap_addon::{addon_name}",
                        "field_label": f"{label_source}: {plain_name}",
                        "old_value": old_version,
                        "new_value": new_version,
                        "source": "agent-report:addon",
                    }
                )

        previous_snapshot = current_snapshot

    changes.sort(key=lambda item: (str(item.get("detected_at_utc") or ""), int(item.get("id") or 0)), reverse=True)
    return changes


def _collect_sap_addon_change_items(conn: sqlite3.Connection, hours: int, limit: int) -> list[dict]:
    cutoff_iso = (datetime.now(timezone.utc) - timedelta(hours=hours)).strftime("%Y-%m-%dT%H:%M:%SZ")
    host_key_expr = reports_host_key_sql("r")
    rows = conn.execute(
        f"""
        SELECT r.id,
               r.received_at_utc,
               {host_key_expr} AS host_uid_value,
               r.hostname,
               r.payload_json,
               COALESCE(h.display_name_override, ''),
               COALESCE(h.country_code_override, ''),
               COALESCE(cust.customer_name, '')
        FROM reports r
        LEFT JOIN host_settings h ON h.hostname = r.hostname
        LEFT JOIN customers cust ON cust.id = h.customer_id
        WHERE r.received_at_utc >= ?
        ORDER BY {host_key_expr} COLLATE NOCASE ASC, r.id ASC
        """,
        (cutoff_iso,),
    ).fetchall()

    host_uids = sorted({str(row[2] or "").strip() for row in rows if str(row[2] or "").strip()})
    hostnames = sorted({str(row[3] or "").strip() for row in rows if str(row[3] or "").strip()})
    host_settings_by_hostname, host_uid_display_name_map = _load_host_metadata_maps(conn, hostnames, host_uids)

    # Pre-seed previous snapshots from the last report BEFORE the time window so that
    # the first report inside the window is diffed against a real baseline.  Without
    # this, every first-in-window report looks like a brand-new host and generates
    # spurious "old_value = '-'" entries that cycle as the window advances.
    previous_by_host: dict[str, dict[str, str]] = {}
    pre_rows = conn.execute(
        f"""
        SELECT r.payload_json,
               {host_key_expr} AS host_uid_value
        FROM reports r
        INNER JOIN (
            SELECT COALESCE(NULLIF(host_uid, ''), hostname) AS hkey, MAX(id) AS max_id
            FROM reports
            WHERE received_at_utc < ?
            GROUP BY hkey
        ) pre ON pre.max_id = r.id
        """,
        (cutoff_iso,),
    ).fetchall()
    for pre_row in pre_rows:
        host_key = str(pre_row[1] or "").strip()
        if host_key:
            payload = parse_payload_json(str(pre_row[0] or "{}"))
            previous_by_host[host_key] = _extract_sap_addon_snapshot(payload)
    changes: list[dict] = []

    for row in rows:
        report_id = int(row[0] or 0)
        detected_at_utc = str(row[1] or "")
        host_uid = str(row[2] or "").strip()
        hostname = str(row[3] or "").strip()
        if not hostname:
            continue
        host_key = host_uid or hostname

        payload = parse_payload_json(str(row[4] or "{}"))
        current_snapshot = _extract_sap_addon_snapshot(payload)
        previous_snapshot = previous_by_host.get(host_key)

        display_override = str(host_uid_display_name_map.get(host_key, "") or "").strip()
        if not display_override:
            display_override = str(row[5] or "").strip()
        country_code = normalize_country_code(str(row[6] or ""))
        customer_name = str(row[7] or "").strip()

        if previous_snapshot is not None:
            addon_names = sorted(set(previous_snapshot.keys()) | set(current_snapshot.keys()), key=lambda x: x.lower())
            for addon_name in addon_names:
                old_version = str(previous_snapshot.get(addon_name, "-") or "-")
                new_version = str(current_snapshot.get(addon_name, "-") or "-")
                if old_version == new_version:
                    continue

                label_source, plain_name = _describe_sap_addon_key(addon_name)
                changes.append(
                    {
                        "id": report_id,
                        "detected_at_utc": detected_at_utc,
                        "host_uid": host_key,
                        "hostname": hostname,
                        "display_name": display_override or hostname,
                        "customer_name": customer_name,
                        "field_key": f"sap_addon::{addon_name}",
                        "field_label": f"{label_source}: {plain_name}",
                        "old_value": old_version,
                        "new_value": new_version,
                        "source": "agent-report:addon",
                        "country_code": country_code,
                    }
                )
        else:
            # First snapshot for this host identity: emit baseline as Neu-only entries.
            for addon_name in sorted(current_snapshot.keys(), key=lambda x: x.lower()):
                new_version = str(current_snapshot.get(addon_name, "-") or "-")
                if new_version == "-":
                    continue
                label_source, plain_name = _describe_sap_addon_key(addon_name)
                changes.append(
                    {
                        "id": report_id,
                        "detected_at_utc": detected_at_utc,
                        "host_uid": host_key,
                        "hostname": hostname,
                        "display_name": display_override or hostname,
                        "customer_name": customer_name,
                        "field_key": f"sap_addon::{addon_name}",
                        "field_label": f"{label_source}: {plain_name}",
                        "old_value": "-",
                        "new_value": new_version,
                        "source": "agent-report:addon-init",
                        "country_code": country_code,
                    }
                )

        previous_by_host[host_key] = current_snapshot

    changes.sort(key=lambda item: (str(item.get("detected_at_utc") or ""), int(item.get("id") or 0)), reverse=True)
    return changes[:limit]


def collect_host_config_changes(conn: sqlite3.Connection, hours: int = 24, limit: int = 300) -> dict:
    window_hours = max(1, int(hours or 24))
    row_limit = max(1, min(int(limit or 300), 1000))
    cutoff_iso = (datetime.now(timezone.utc) - timedelta(hours=window_hours)).strftime("%Y-%m-%dT%H:%M:%SZ")

    rows = conn.execute(
        """
        SELECT chg.id,
               chg.detected_at_utc,
               COALESCE(NULLIF(chg.host_uid, ''), COALESCE(NULLIF(r.host_uid, ''), chg.hostname)) AS host_uid_value,
               chg.hostname,
               chg.field_key,
               chg.old_value,
               chg.new_value,
               COALESCE(chg.source, 'agent-report'),
               COALESCE(h.country_code_override, ''),
               COALESCE(cust.customer_name, '')
        FROM host_config_changes chg
        LEFT JOIN reports r ON r.id = chg.report_id
        LEFT JOIN host_settings h ON h.hostname = chg.hostname
        LEFT JOIN customers cust ON cust.id = h.customer_id
        WHERE chg.detected_at_utc >= ?
          AND chg.field_key NOT IN ('sap_services_ports')
        ORDER BY chg.detected_at_utc DESC, chg.id DESC
        LIMIT ?
        """,
        (cutoff_iso, row_limit),
    ).fetchall()

    host_uids = sorted({str(row[2] or "").strip() for row in rows if str(row[2] or "").strip()})
    hostnames = sorted({str(row[3] or "").strip() for row in rows if str(row[3] or "").strip()})
    host_settings_by_hostname, host_uid_display_name_map = _load_host_metadata_maps(conn, hostnames, host_uids)

    license_label_map = _build_sap_license_type_label_map()
    items = []
    for row in rows:
        host_uid = str(row[2] or "").strip()
        hostname = str(row[3] or "")
        display_override = str(host_uid_display_name_map.get(host_uid, "") or "").strip()
        if not display_override:
            display_override = str(host_settings_by_hostname.get(hostname, {}).get("display_name_override", "") or "").strip()
        country_code = normalize_country_code(str(row[8] or ""))
        customer_name = str(row[9] or "").strip()
        items.append(
            {
                "id": int(row[0] or 0),
                "detected_at_utc": str(row[1] or ""),
                "host_uid": host_uid or hostname,
                "hostname": hostname,
                "display_name": display_override or hostname,
                "customer_name": customer_name,
                "field_key": str(row[4] or ""),
                "field_label": _host_config_field_label(str(row[4] or ""), license_label_map=license_label_map),
                "old_value": str(row[5] or "-"),
                "new_value": str(row[6] or "-"),
                "source": str(row[7] or "agent-report"),
                "country_code": country_code,
            }
        )

    db_items = _collect_database_lifecycle_change_items(conn, window_hours, row_limit)
    if db_items:
        items.extend(db_items)

    if db_items:
        items.sort(key=lambda item: (str(item.get("detected_at_utc") or ""), int(item.get("id") or 0)), reverse=True)
        items = items[:row_limit]

    return {
        "hours": window_hours,
        "limit": row_limit,
        "count": len(items),
        "items": items,
    }


def _pulse_backfill_progress(progress_callback, state: dict, *, inserted_changes: int) -> None:
    if not callable(progress_callback):
        return
    try:
        progress_callback({
            "phase": "config_backfill",
            "phase_step": 2,
            "phase_steps_total": int(state.get("phase_steps_total") or 3),
            "reports_total": int(state.get("reports_total") or 0),
            "reports_scanned": int(state.get("reports_active") or state.get("reports_completed") or 0),
            "hosts_processed": int(state.get("hosts_processed") or 0),
            "hosts_total": int(state.get("hosts_total") or 0),
            "current_host": str(state.get("current_host") or ""),
            "inserted_changes": int(inserted_changes or 0),
            "message": str(state.get("pulse_message") or "Host-Config: OS, CPU, RAM, SAP/HANA, SQL, Lizenzen…"),
        })
    except Exception:
        pass


def _commit_backfill_progress_batch(
    conn: sqlite3.Connection,
    inserted_changes: int,
    *,
    progress_callback=None,
    progress_state: dict | None = None,
    inventory_greenfield: bool = False,
) -> None:
    """Release SQLite write locks during large per-report inventur inserts."""
    count = int(inserted_changes or 0)
    if count <= 0:
        return
    if inventory_greenfield:
        should_commit = True
        should_pulse = count <= 40 or count % 15 == 0
    else:
        should_commit = count % 10 == 0
        should_pulse = bool(progress_callback and progress_state) and (
            count % 25 == 0 or should_commit
        )
    if not should_commit and not should_pulse:
        return
    if should_commit:
        conn.commit()
    if should_pulse:
        _pulse_backfill_progress(progress_callback, progress_state, inserted_changes=count)


def backfill_host_config_changes(
    conn: sqlite3.Connection,
    days: int = 7,
    progress_callback=None,
    include_initial_snapshot_events: bool = False,
    job_id: int = 0,
    skip_pre_seed: bool = False,
    phase_steps_total: int = 3,
    inventory_greenfield: bool = False,
) -> dict:
    _ensure_host_config_snapshot_schema(conn)

    window_days = _changelog_window_days(days)
    cutoff_iso = _changelog_cutoff_iso(days)
    reports_total = _count_reports_for_changelog_days(conn, window_days)

    reports_sql = """
        SELECT id, received_at_utc, hostname, COALESCE(host_uid, ''), payload_json
        FROM reports
    """
    reports_params: tuple = ()
    if cutoff_iso is not None:
        reports_sql += " WHERE received_at_utc >= ?"
        reports_params = (cutoff_iso,)
    reports_sql += " ORDER BY COALESCE(NULLIF(host_uid, ''), hostname) COLLATE NOCASE ASC, id ASC"

    last_snapshot_by_host_key: dict[str, dict[str, str]] = {}
    last_license_counts_by_host_key: dict[str, dict[str, int]] = {}
    last_hostname_by_host_key: dict[str, str] = {}
    last_seen_at_by_host_key: dict[str, str] = {}
    license_label_map = _build_sap_license_type_label_map()

    if not skip_pre_seed and cutoff_iso is not None:
        pre_rows = conn.execute(
            """
            SELECT r.hostname, COALESCE(r.host_uid, ''), r.payload_json
            FROM reports r
            INNER JOIN (
                SELECT COALESCE(NULLIF(host_uid, ''), hostname) AS hkey, MAX(id) AS max_id
                FROM reports
                WHERE received_at_utc < ?
                GROUP BY hkey
            ) pre ON pre.max_id = r.id
            """,
            (cutoff_iso,),
        ).fetchall()
        for pre_row in pre_rows:
            pre_hostname = str(pre_row[0] or "").strip()
            pre_host_uid = str(pre_row[1] or "").strip()
            if not pre_hostname:
                continue
            pre_host_key = alert_host_key(pre_hostname, pre_host_uid)
            pre_payload = parse_payload_json(str(pre_row[2] or "{}"))
            last_snapshot_by_host_key[pre_host_key] = {
                key: _normalize_config_value(key, value)
                for key, value in _extract_host_config_snapshot(pre_payload).items()
            }
            last_license_counts_by_host_key[pre_host_key] = _extract_translated_sap_license_type_counts(
                pre_payload, license_label_map=license_label_map
            )

    report_count = 0
    inserted_changes = 0
    if inventory_greenfield:
        hosts_total = 0
    else:
        hosts_count_sql = """
            SELECT COUNT(DISTINCT COALESCE(NULLIF(host_uid, ''), hostname))
            FROM reports
        """
        if cutoff_iso is not None:
            hosts_count_sql += " WHERE received_at_utc >= ? AND hostname IS NOT NULL AND TRIM(hostname) <> ''"
            hosts_count_params: tuple = (cutoff_iso,)
        else:
            hosts_count_sql += " WHERE hostname IS NOT NULL AND TRIM(hostname) <> ''"
            hosts_count_params = ()
        hosts_total_row = conn.execute(hosts_count_sql, hosts_count_params).fetchone()
        hosts_total = int((hosts_total_row[0] or 0) if hosts_total_row else 0)
        conn.commit()
    hosts_processed = 0
    last_progress_host_key = ""
    last_progress_emit_mono = 0.0
    backfill_pulse_state = {
        "phase_steps_total": int(phase_steps_total or 3),
        "reports_total": reports_total,
        "reports_completed": 0,
        "reports_active": 0,
        "hosts_processed": 0,
        "hosts_total": hosts_total,
        "current_host": "",
        "pulse_message": "Host-Config: OS, CPU, RAM, SAP/HANA, SQL, Lizenzen…",
    }

    if callable(progress_callback):
        try:
            progress_callback({
                "phase": "config_backfill",
                "phase_step": 2,
                "phase_steps_total": int(phase_steps_total or 3),
                "reports_total": reports_total,
                "reports_scanned": 0,
                "hosts_processed": 0,
                "hosts_total": hosts_total,
                "inserted_changes": 0,
                "message": "Host-Config: OS, CPU, RAM, SAP/HANA, SQL, Lizenzen…",
            })
            last_progress_emit_mono = time.monotonic()
        except Exception:
            pass
    conn.commit()

    read_conn = _changelog_read_connect()
    try:
        for batch in _iter_changelog_report_batches(
            read_conn,
            reports_sql,
            reports_params,
            batch_size=_CHANGELOG_INVENTORY_FETCH_BATCH_SIZE if inventory_greenfield else _CHANGELOG_REPORT_FETCH_BATCH_SIZE,
        ):
            for row in batch:
                report_id = int(row[0] or 0)
                detected_at_utc = str(row[1] or "").strip()
                hostname = str(row[2] or "").strip()
                host_uid = str(row[3] or "").strip()
                if not hostname:
                    continue
                host_key = alert_host_key(hostname, host_uid)
                host_changed = host_key != last_progress_host_key
                if host_changed:
                    hosts_processed += 1
                    last_progress_host_key = host_key
                    if inventory_greenfield:
                        backfill_pulse_state["hosts_total"] = hosts_processed

                report_count += 1
                backfill_pulse_state["reports_active"] = report_count
                backfill_pulse_state["reports_completed"] = report_count
                backfill_pulse_state["hosts_processed"] = hosts_processed
                backfill_pulse_state["current_host"] = hostname
                backfill_pulse_state["pulse_message"] = (
                    f"Report {report_count}/{reports_total}: {hostname}…"
                )
                conn.commit()
                reports_remaining = max(0, int(reports_total or 0) - report_count)
                pulse_every = 10 if inventory_greenfield else 100
                if reports_remaining <= 1000:
                    pulse_every = 1 if inventory_greenfield else 5
                if report_count == 1 or report_count % pulse_every == 0 or reports_remaining <= 50:
                    _pulse_backfill_progress(
                        progress_callback,
                        backfill_pulse_state,
                        inserted_changes=inserted_changes,
                    )
                    if inventory_greenfield and report_count in {1, 10, 100, 500}:
                        print(
                            f"[inventur] job={job_id} config {report_count}/{reports_total} "
                            f"changes={inserted_changes} host={hostname}",
                            flush=True,
                        )

                payload = parse_payload_json(str(row[4] or "{}"))

                if _should_check_changelog_job_cancel(report_count, reports_total) or host_changed:
                    _ensure_changelog_job_running(conn, job_id)

                current_snapshot = {
                    key: _normalize_config_value(key, value)
                    for key, value in _extract_host_config_snapshot(payload).items()
                }
                current_license_counts = _extract_translated_sap_license_type_counts(
                    payload, license_label_map=license_label_map
                )
                previous_snapshot = last_snapshot_by_host_key.get(host_key)
                previous_license_counts = last_license_counts_by_host_key.get(host_key)
                skip_dup = bool(inventory_greenfield)

                if previous_snapshot is not None:
                    for field_key in HOST_CONFIG_TRACKED_FIELDS:
                        old_value = previous_snapshot.get(field_key, "-")
                        new_value = current_snapshot.get(field_key, "-")
                        if not _is_significant_config_change(field_key, old_value, new_value):
                            continue

                        if not skip_dup:
                            existing = conn.execute(
                                """
                                SELECT 1
                                FROM host_config_changes
                                WHERE host_uid = ?
                                  AND field_key = ?
                                  AND report_id = ?
                                  AND old_value = ?
                                  AND new_value = ?
                                LIMIT 1
                                """,
                                (host_key, field_key, report_id, old_value, new_value),
                            ).fetchone()
                            if existing:
                                continue

                        conn.execute(
                            """
                            INSERT INTO host_config_changes (
                                detected_at_utc,
                                host_uid,
                                hostname,
                                field_key,
                                old_value,
                                new_value,
                                report_id,
                                source
                            )
                            VALUES (?, ?, ?, ?, ?, ?, ?, 'backfill')
                            """,
                            (detected_at_utc or utc_now_iso(), host_key, hostname, field_key, old_value, new_value, report_id),
                        )
                        inserted_changes += 1
                        _commit_backfill_progress_batch(
                            conn,
                            inserted_changes,
                            progress_callback=progress_callback,
                            progress_state=backfill_pulse_state,
                            inventory_greenfield=inventory_greenfield,
                        )

                    if previous_license_counts is not None:
                        for match_text_upper in sorted(current_license_counts.keys()):
                            old_count = int(previous_license_counts.get(match_text_upper, 0) or 0)
                            new_count = int(current_license_counts.get(match_text_upper, 0) or 0)
                            if old_count == new_count:
                                continue
                            if old_count == 0 and new_count == 0:
                                continue

                            field_key = f"{SAP_LICENSE_TYPE_FIELD_PREFIX}{match_text_upper}"
                            old_value = str(old_count)
                            new_value = str(new_count)

                            if not skip_dup:
                                existing = conn.execute(
                                    """
                                    SELECT 1
                                    FROM host_config_changes
                                    WHERE host_uid = ?
                                      AND field_key = ?
                                      AND report_id = ?
                                      AND old_value = ?
                                      AND new_value = ?
                                    LIMIT 1
                                    """,
                                    (host_key, field_key, report_id, old_value, new_value),
                                ).fetchone()
                                if existing:
                                    continue

                            conn.execute(
                                """
                                INSERT INTO host_config_changes (
                                    detected_at_utc,
                                    host_uid,
                                    hostname,
                                    field_key,
                                    old_value,
                                    new_value,
                                    report_id,
                                    source
                                )
                                VALUES (?, ?, ?, ?, ?, ?, ?, 'backfill-license')
                                """,
                                (detected_at_utc or utc_now_iso(), host_key, hostname, field_key, old_value, new_value, report_id),
                            )
                            inserted_changes += 1
                            _commit_backfill_progress_batch(
                                conn,
                                inserted_changes,
                                progress_callback=progress_callback,
                                progress_state=backfill_pulse_state,
                                inventory_greenfield=inventory_greenfield,
                            )
                elif include_initial_snapshot_events:
                    for field_key in HOST_CONFIG_TRACKED_FIELDS:
                        old_value = "-"
                        new_value = current_snapshot.get(field_key, "-")
                        if not _is_significant_config_change(field_key, old_value, new_value):
                            continue

                        if not skip_dup:
                            existing = conn.execute(
                                """
                                SELECT 1
                                FROM host_config_changes
                                WHERE host_uid = ?
                                  AND field_key = ?
                                  AND report_id = ?
                                  AND old_value = ?
                                  AND new_value = ?
                                LIMIT 1
                                """,
                                (host_key, field_key, report_id, old_value, new_value),
                            ).fetchone()
                            if existing:
                                continue

                        conn.execute(
                            """
                            INSERT INTO host_config_changes (
                                detected_at_utc,
                                host_uid,
                                hostname,
                                field_key,
                                old_value,
                                new_value,
                                report_id,
                                source
                            )
                            VALUES (?, ?, ?, ?, ?, ?, ?, 'backfill-init')
                            """,
                            (detected_at_utc or utc_now_iso(), host_key, hostname, field_key, old_value, new_value, report_id),
                        )
                        inserted_changes += 1
                        _commit_backfill_progress_batch(
                            conn,
                            inserted_changes,
                            progress_callback=progress_callback,
                            progress_state=backfill_pulse_state,
                            inventory_greenfield=inventory_greenfield,
                        )

                    for match_text_upper in sorted(current_license_counts.keys()):
                        field_key = f"{SAP_LICENSE_TYPE_FIELD_PREFIX}{match_text_upper}"
                        old_value = "-"
                        init_count = int(current_license_counts.get(match_text_upper, 0) or 0)
                        if init_count == 0:
                            continue
                        new_value = str(init_count)

                        if not skip_dup:
                            existing = conn.execute(
                                """
                                SELECT 1
                                FROM host_config_changes
                                WHERE host_uid = ?
                                  AND field_key = ?
                                  AND report_id = ?
                                  AND old_value = ?
                                  AND new_value = ?
                                LIMIT 1
                                """,
                                (host_key, field_key, report_id, old_value, new_value),
                            ).fetchone()
                            if existing:
                                continue

                        conn.execute(
                            """
                            INSERT INTO host_config_changes (
                                detected_at_utc,
                                host_uid,
                                hostname,
                                field_key,
                                old_value,
                                new_value,
                                report_id,
                                source
                            )
                            VALUES (?, ?, ?, ?, ?, ?, ?, 'backfill-init-license')
                            """,
                            (detected_at_utc or utc_now_iso(), host_key, hostname, field_key, old_value, new_value, report_id),
                        )
                        inserted_changes += 1
                        _commit_backfill_progress_batch(
                            conn,
                            inserted_changes,
                            progress_callback=progress_callback,
                            progress_state=backfill_pulse_state,
                            inventory_greenfield=inventory_greenfield,
                        )

                last_snapshot_by_host_key[host_key] = current_snapshot
                last_license_counts_by_host_key[host_key] = current_license_counts
                last_hostname_by_host_key[host_key] = hostname
                last_seen_at_by_host_key[host_key] = detected_at_utc or utc_now_iso()
                backfill_pulse_state["reports_completed"] = report_count
                conn.commit()

                if callable(progress_callback):
                    now_mono = time.monotonic()
                    if (
                        host_changed
                        or _should_emit_changelog_progress(report_count, reports_total, host_changed=host_changed)
                        or (now_mono - last_progress_emit_mono) >= CHANGELOG_PROGRESS_FLUSH_INTERVAL_SEC
                    ):
                        try:
                            progress_callback({
                                "phase": "config_backfill",
                                "phase_step": 2,
                                "phase_steps_total": int(phase_steps_total or 3),
                                "reports_total": reports_total,
                                "reports_scanned": report_count,
                                "hosts_processed": hosts_processed,
                                "hosts_total": backfill_pulse_state.get("hosts_total", hosts_total),
                                "current_host": hostname,
                                "inserted_changes": inserted_changes,
                                "message": backfill_pulse_state["pulse_message"],
                            })
                            last_progress_emit_mono = now_mono
                        except Exception:
                            pass

    finally:
        read_conn.close()

    conn.commit()

    snapshot_hosts = list(last_snapshot_by_host_key.items())
    license_hosts = [
        (host_key, license_counts)
        for host_key, license_counts in last_license_counts_by_host_key.items()
        if license_counts
    ]

    def _emit_config_finalize_progress(message: str, *, current_host: str = "") -> None:
        if not callable(progress_callback):
            return
        try:
            progress_callback({
                "phase": "config_backfill",
                "phase_step": 2,
                "phase_steps_total": int(phase_steps_total or 3),
                "reports_total": reports_total,
                "reports_scanned": report_count,
                "hosts_processed": hosts_processed,
                "hosts_total": backfill_pulse_state.get("hosts_total", hosts_total),
                "current_host": current_host,
                "inserted_changes": inserted_changes,
                "message": message,
            })
        except Exception:
            pass

    _emit_config_finalize_progress(
        f"Host-Config: Reports fertig ({report_count}/{reports_total}), Speichere Snapshots…"
    )

    # Snapshots on a separate connection so the progress heartbeat can still UPDATE the job row.
    finalize_conn = sqlite_connect()
    try:
        finalize_conn.execute(f"PRAGMA busy_timeout = {_maintenance_sqlite_busy_timeout_ms()}")
        for snap_idx, (host_key, snapshot) in enumerate(snapshot_hosts, start=1):
            updated_at_utc = last_seen_at_by_host_key.get(host_key, utc_now_iso())
            hostname_value = str(last_hostname_by_host_key.get(host_key, host_key) or host_key)
            finalize_conn.execute(
                """
                INSERT INTO host_config_snapshot (
                    hostname,
                    os_release,
                    kernel_release,
                    cpu_cores,
                    cpu_model_name,
                    ram_gb,
                    sap_release,
                    hana_release,
                    hana_sid,
                    sql_release,
                    updated_at_utc
                )
                VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
                ON CONFLICT(hostname) DO UPDATE SET
                    os_release = excluded.os_release,
                    kernel_release = excluded.kernel_release,
                    cpu_cores = excluded.cpu_cores,
                    cpu_model_name = excluded.cpu_model_name,
                    ram_gb = excluded.ram_gb,
                    sap_release = excluded.sap_release,
                    hana_release = excluded.hana_release,
                    hana_sid = excluded.hana_sid,
                    sql_release = excluded.sql_release,
                    updated_at_utc = excluded.updated_at_utc
                """,
                (
                    host_key,
                    snapshot["os_release"],
                    snapshot["kernel_release"],
                    snapshot["cpu_cores"],
                    snapshot["cpu_model_name"],
                    snapshot["ram_gb"],
                    snapshot["sap_release"],
                    snapshot["hana_release"],
                    snapshot["hana_sid"],
                    snapshot["sql_release"],
                    updated_at_utc,
                ),
            )
            finalize_conn.commit()
            if inventory_greenfield or snap_idx == 1 or snap_idx == len(snapshot_hosts) or snap_idx % 5 == 0:
                _emit_config_finalize_progress(
                    f"Host-Config: Speichere Snapshots ({snap_idx}/{len(snapshot_hosts)})…",
                    current_host=hostname_value,
                )

        for lic_idx, (host_key, license_counts) in enumerate(license_hosts, start=1):
            updated_at_utc = last_seen_at_by_host_key.get(host_key, utc_now_iso())
            hostname_value = str(last_hostname_by_host_key.get(host_key, host_key) or host_key)
            finalize_conn.execute("DELETE FROM host_license_type_snapshot WHERE host_uid = ?", (host_key,))
            for match_text_upper in sorted(license_counts.keys()):
                finalize_conn.execute(
                    """
                    INSERT INTO host_license_type_snapshot (
                        host_uid,
                        hostname,
                        license_type_match_text,
                        count_value,
                        updated_at_utc
                    )
                    VALUES (?, ?, ?, ?, ?)
                    """,
                    (
                        host_key,
                        hostname_value,
                        match_text_upper,
                        int(license_counts.get(match_text_upper, 0) or 0),
                        updated_at_utc,
                    ),
                )
            finalize_conn.commit()
            if inventory_greenfield or lic_idx == 1 or lic_idx == len(license_hosts) or lic_idx % 5 == 0:
                _emit_config_finalize_progress(
                    f"Host-Config: Lizenz-Snapshots ({lic_idx}/{len(license_hosts)})…",
                    current_host=hostname_value,
                )
    finally:
        finalize_conn.close()

    _emit_config_finalize_progress("Host-Config abgeschlossen, weiter mit SAP-Add-ons…")
    conn.commit()

    return {
        "days": window_days,
        "reports_scanned": report_count,
        "hosts_touched": len(last_snapshot_by_host_key),
        "hosts_processed": hosts_processed,
        "hosts_total": hosts_total,
        "inserted_changes": inserted_changes,
    }


def collect_system_overview(conn: sqlite3.Connection, search_query: str = "") -> dict:
    latest_rows = _identity_report_rows(conn)
    if not latest_rows:
        return {"by_country": {}, "total": 0}

    hostnames = sorted({str(row[1] or "").strip() for row in latest_rows if str(row[1] or "").strip()})
    settings_rows = []
    if hostnames:
        placeholders = ",".join("?" for _ in hostnames)
        settings_rows = conn.execute(
            f"""
            SELECT h.hostname,
                   h.display_name_override,
                   COALESCE(h.country_code_override, ''),
                   COALESCE(c.customer_name, '')
            FROM host_settings h
            LEFT JOIN customers c ON c.id = h.customer_id
            WHERE hostname IN ({placeholders})
            """,
            tuple(hostnames),
        ).fetchall()
    override_names = {str(row[0] or ""): str(row[1] or "") for row in settings_rows}
    override_countries = {str(row[0] or ""): normalize_country_code(str(row[2] or "")) for row in settings_rows}
    customer_names = {str(row[0] or ""): str(row[3] or "").strip() for row in settings_rows}

    host_uid_keys = [str(row[0] or "").strip() for row in latest_rows if str(row[0] or "").strip()]
    host_uid_display_name_map: dict[str, str] = {}
    host_uid_settings_map: dict[str, dict[str, str]] = {}
    if host_uid_keys:
        placeholders = ",".join(["?"] * len(host_uid_keys))
        host_uid_rows = conn.execute(
            f"""
            SELECT hus.host_uid,
                   COALESCE(hus.display_name_override, ''),
                   COALESCE(hus.country_code_override, ''),
                   COALESCE(c.customer_name, '')
            FROM host_uid_settings hus
            LEFT JOIN customers c ON c.id = hus.customer_id
            WHERE host_uid IN ({placeholders})
            """,
            tuple(host_uid_keys),
        ).fetchall()
        host_uid_display_name_map = {
            str(row[0] or "").strip(): str(row[1] or "").strip()
            for row in host_uid_rows
            if str(row[0] or "").strip()
        }
        host_uid_settings_map = {
            str(row[0] or "").strip(): {
                "country_code_override": normalize_country_code(str(row[2] or "")),
                "customer_name": str(row[3] or "").strip(),
            }
            for row in host_uid_rows
            if str(row[0] or "").strip()
        }

    now_utc = datetime.now(timezone.utc)
    normalized_search = str(search_query or "").strip().lower()
    by_country: dict[str, dict[str, dict[str, list[dict]]]] = {}

    for row in latest_rows:
        host_uid = str(row[0] or "").strip()
        hostname = str(row[1] or "").strip()
        if not hostname:
            continue
        received_at_utc = str(row[2] or "").strip()
        payload_json_raw = str(row[3] or "{}")

        display_name_override = str(host_uid_display_name_map.get(host_uid, "") or "").strip()
        if not display_name_override:
            display_name_override = str(override_names.get(hostname, "") or "").strip()
        host_uid_settings = host_uid_settings_map.get(host_uid, {}) if host_uid else {}
        customer = (
            str(host_uid_settings.get("customer_name", "") or "").strip()
            or customer_names.get(hostname, "")
            or "Ohne Kunde"
        )

        if normalized_search:
            searchable_meta = " ".join([
                host_uid,
                hostname,
                display_name_override,
                customer,
            ]).lower()
            payload_text_lc = payload_json_raw.lower()
            if normalized_search not in searchable_meta and normalized_search not in payload_text_lc:
                continue

        payload = parse_payload_json(payload_json_raw)
        display_name = effective_display_name(payload, display_name_override, hostname)

        country = (
            normalize_country_code(str(host_uid_settings.get("country_code_override", "") or ""))
            or override_countries.get(hostname, "")
            or extract_country_code_from_payload(payload)
            or "XX"
        )
        os_family = normalize_os_family(payload.get("os", ""))

        release_info = _extract_sap_hana_ram(payload)
        cpu_info = _extract_cpu_overview(payload)

        sql_release = _extract_sql_release(payload)

        online = False
        if received_at_utc:
            try:
                last_dt = datetime.fromisoformat(received_at_utc.replace("Z", "+00:00"))
                online = (now_utc - last_dt) <= timedelta(minutes=SYSTEM_OVERVIEW_ONLINE_THRESHOLD_MINUTES)
            except (ValueError, TypeError):
                online = False

        country_bucket = by_country.setdefault(country, {})
        os_bucket = country_bucket.setdefault(os_family, {})
        customer_bucket = os_bucket.setdefault(customer, [])
        customer_bucket.append(
            {
                "host_uid": host_uid,
                "hostname": hostname,
                "display_name": display_name,
                "online": online,
                "sap_release": release_info["sap_release"],
                "hana_version": release_info["hana_version"],
                "hana_sid": release_info["hana_sid"],
                "sql_release": sql_release,
                "ram_gb": release_info["ram_gb"],
                "cpu_cores": cpu_info["cpu_cores"],
                "cpu_model_name": cpu_info["cpu_model_name"],
                "last_update": received_at_utc or "-",
                "payload": payload,
            }
        )

    return {
        "by_country": by_country,
        "total": sum(
            len(hosts)
            for os_bucket in by_country.values()
            for customer_bucket in os_bucket.values()
            for hosts in customer_bucket.values()
        ),
    }


def collect_backup_status_overview(conn: sqlite3.Connection, hours: int = 24) -> dict:
    latest_rows = _identity_report_rows(conn)
    if not latest_rows:
        return {"generated_at": utc_now_iso(), "hours": max(1, int(hours or 24)), "total": 0, "missing_count": 0, "items": []}

    hostnames = sorted({str(row[1] or "").strip() for row in latest_rows if str(row[1] or "").strip()})
    settings_map: dict[str, dict] = {}
    if hostnames:
        placeholders = ",".join("?" for _ in hostnames)
        settings_rows = conn.execute(
            f"""
            SELECT h.hostname,
                   COALESCE(h.display_name_override, ''),
                   COALESCE(h.country_code_override, ''),
                   h.customer_id,
                   COALESCE(c.customer_name, ''),
                   COALESCE(c.maringo_project_number, '')
            FROM host_settings h
            LEFT JOIN customers c ON c.id = h.customer_id
            WHERE h.hostname IN ({placeholders})
            """,
            tuple(hostnames),
        ).fetchall()
        settings_map = {
            str(row[0] or "").strip(): {
                "display_name_override": str(row[1] or "").strip(),
                "country_code_override": normalize_country_code(str(row[2] or "")),
                "customer_id": int(row[3]) if row[3] is not None else None,
                "customer_name": str(row[4] or "").strip(),
                "customer_project": str(row[5] or "").strip(),
            }
            for row in settings_rows
            if str(row[0] or "").strip()
        }

    host_uid_keys = [str(row[0] or "").strip() for row in latest_rows if str(row[0] or "").strip()]
    host_uid_display_name_map: dict[str, str] = {}
    if host_uid_keys:
        placeholders = ",".join(["?"] * len(host_uid_keys))
        host_uid_rows = conn.execute(
            f"""
            SELECT host_uid, COALESCE(display_name_override, '')
            FROM host_uid_settings
            WHERE host_uid IN ({placeholders})
            """,
            tuple(host_uid_keys),
        ).fetchall()
        host_uid_display_name_map = {
            str(row[0] or "").strip(): str(row[1] or "").strip()
            for row in host_uid_rows
            if str(row[0] or "").strip()
        }

    now_utc = datetime.now(timezone.utc)
    age_limit = timedelta(hours=max(1, int(hours or 24)))
    items: list[dict] = []

    for row in latest_rows:
        host_uid = str(row[0] or "").strip()
        hostname = str(row[1] or "").strip()
        if not hostname:
            continue
        received_at = str(row[2] or "").strip()
        payload = parse_payload_json(str(row[3] or "{}"))
        host_settings = settings_map.get(hostname, {})
        display_name_override = str(host_uid_display_name_map.get(host_uid, "") or "").strip()
        if not display_name_override:
            display_name_override = str(host_settings.get("display_name_override", "") or "").strip()
        display_name = effective_display_name(payload, display_name_override, hostname)
        country_override = normalize_country_code(str(host_settings.get("country_code_override", "") or ""))
        customer_id = host_settings.get("customer_id")
        customer_name = str(host_settings.get("customer_name", "") or "").strip()
        customer_project = str(host_settings.get("customer_project", "") or "").strip()
        country_code = country_override or extract_country_code_from_payload(payload) or ""
        country_code = normalize_country_code(country_code)

        last_dt = None
        if received_at:
            try:
                last_dt = datetime.fromisoformat(received_at.replace("Z", "+00:00"))
            except ValueError:
                last_dt = None
        is_recent_report = bool(last_dt and ((now_utc - last_dt) <= age_limit))

        dir_block = payload.get("dir_deep_listings") if isinstance(payload.get("dir_deep_listings"), dict) else {}
        directories = dir_block.get("entries") if isinstance(dir_block.get("entries"), list) else []
        if not directories:
            # Backward compatibility with older payload shape.
            directories = dir_block.get("directories") if isinstance(dir_block.get("directories"), list) else []

        directory_items: list[dict] = []
        for directory in directories:
            if not isinstance(directory, dict):
                continue
            subdirs = directory.get("subdirs") if isinstance(directory.get("subdirs"), list) else []
            for subdir in subdirs:
                if not isinstance(subdir, dict):
                    continue
                subdir_name = str(subdir.get("name") or "").strip()
                subdir_path = str(subdir.get("path") or "").strip() or subdir_name or "-"
                latest_mod = str(subdir.get("zip_latest_modified_utc") or "").strip()
                latest_dt = None
                if latest_mod:
                    try:
                        latest_dt = datetime.fromisoformat(latest_mod.replace("Z", "+00:00"))
                    except ValueError:
                        latest_dt = None
                has_today_backup = bool(latest_dt and ((now_utc - latest_dt) <= age_limit))

                newest_name = ""
                newest_modified = ""
                newest_size_bytes = 0
                newest_dt = None
                entries = subdir.get("items") if isinstance(subdir.get("items"), list) else []
                for entry in entries:
                    if not isinstance(entry, dict):
                        continue
                    mod = str(entry.get("modified_utc") or "").strip()
                    mod_dt = None
                    if mod:
                        try:
                            mod_dt = datetime.fromisoformat(mod.replace("Z", "+00:00"))
                        except ValueError:
                            mod_dt = None
                    if newest_dt is None or (mod_dt is not None and mod_dt > newest_dt):
                        newest_dt = mod_dt
                        newest_name = str(entry.get("name") or entry.get("path") or "").strip()
                        newest_modified = mod
                        try:
                            newest_size_bytes = int(entry.get("size_bytes") or 0)
                        except (TypeError, ValueError):
                            newest_size_bytes = 0

                directory_items.append(
                    {
                        "subdir_name": subdir_name or "-",
                        "subdir_path": subdir_path,
                        "has_today_backup": has_today_backup,
                        "newest_item_name": newest_name,
                        "newest_item_modified": newest_modified,
                        "newest_item_size_bytes": max(0, newest_size_bytes),
                        "source_type": "filesystem",
                    }
                )

        # Include SQL database backup status for non-system databases.
        sql_info = payload.get("sql_server_info") if isinstance(payload.get("sql_server_info"), dict) else {}
        sql_instances = sql_info.get("instances") if isinstance(sql_info.get("instances"), list) else []
        system_db_names = {"master", "model", "msdb", "tempdb"}
        sql_user_db_count = 0

        for instance in sql_instances:
            if not isinstance(instance, dict):
                continue
            instance_name = str(instance.get("name") or "").strip() or "MSSQLSERVER"
            databases = instance.get("databases") if isinstance(instance.get("databases"), list) else []

            for db in databases:
                if not isinstance(db, dict):
                    continue
                db_name = str(db.get("name") or "").strip()
                if not db_name:
                    continue
                if bool(db.get("system_db")) or db_name.lower() in system_db_names:
                    continue
                sql_user_db_count += 1

                backup_candidates = [
                    str(db.get("last_full_backup") or "").strip(),
                    str(db.get("last_diff_backup") or "").strip(),
                    str(db.get("last_log_backup") or "").strip(),
                    str(db.get("last_full_backup_utc") or "").strip(),
                    str(db.get("last_diff_backup_utc") or "").strip(),
                    str(db.get("last_log_backup_utc") or "").strip(),
                ]
                latest_backup_text = ""
                latest_backup_dt = None
                for candidate in backup_candidates:
                    if not candidate:
                        continue
                    try:
                        candidate_dt = datetime.fromisoformat(candidate.replace("Z", "+00:00"))
                    except ValueError:
                        continue
                    if latest_backup_dt is None or candidate_dt > latest_backup_dt:
                        latest_backup_dt = candidate_dt
                        latest_backup_text = candidate

                has_today_backup = bool(latest_backup_dt and ((now_utc - latest_backup_dt) <= age_limit))

                data_mb = int(db.get("data_mb") or 0)
                log_mb = int(db.get("log_mb") or 0)
                db_size_bytes = max(0, (data_mb + log_mb) * 1024 * 1024)
                recovery_model = str(db.get("recovery_model") or "").strip()
                db_state = str(db.get("state") or "").strip()

                directory_items.append(
                    {
                        "subdir_name": f"SQL DB: {db_name}",
                        "subdir_path": f"{instance_name}/{db_name}",
                        "has_today_backup": has_today_backup,
                        "newest_item_name": f"{instance_name} · {db_state or '-'} · {recovery_model or '-'}",
                        "newest_item_modified": latest_backup_text,
                        "newest_item_size_bytes": db_size_bytes,
                        "source_type": "sql",
                    }
                )

        hana_info = payload.get("hana_info") if isinstance(payload.get("hana_info"), dict) else {}
        has_hana = bool(hana_info.get("available")) or bool(str(hana_info.get("sid") or "").strip())

        has_missing_backup = bool(directory_items) and any(not bool(item.get("has_today_backup")) for item in directory_items)
        items.append(
            {
                "host_uid": host_uid,
                "hostname": hostname,
                "display_name": display_name,
                "country_code": country_code,
                "customer_id": customer_id,
                "customer_name": customer_name,
                "customer_maringo_project_number": customer_project,
                "has_hana": has_hana,
                "has_sql": sql_user_db_count > 0,
                "sql_user_db_count": sql_user_db_count,
                "report_time_utc": received_at,
                "is_today_report": is_recent_report,
                "dirs": directory_items,
                "has_missing_backup": has_missing_backup,
            }
        )

    missing_count = sum(1 for item in items if bool(item.get("has_missing_backup")))
    return {
        "generated_at": utc_now_iso(),
        "hours": max(1, int(hours or 24)),
        "total": len(items),
        "missing_count": missing_count,
        "hosts": items,
    }


def collect_customer_overview(conn: sqlite3.Connection) -> dict:
    latest_rows = _identity_report_rows(conn)
    if not latest_rows:
        return {
            "generated_at": utc_now_iso(),
            "total_customers": 0,
            "total_hosts": 0,
            "customers": [],
        }

    hostnames = sorted({str(row[1] or "").strip() for row in latest_rows if str(row[1] or "").strip()})
    settings_map: dict[str, dict] = {}
    if hostnames:
        placeholders = ",".join("?" for _ in hostnames)
        settings_rows = conn.execute(
            f"""
            SELECT h.hostname,
                   COALESCE(h.display_name_override, ''),
                   COALESCE(h.country_code_override, ''),
                   COALESCE(h.is_hidden, 0),
                   h.customer_id,
                   COALESCE(c.customer_name, ''),
                   COALESCE(c.maringo_project_number, '')
            FROM host_settings h
            LEFT JOIN customers c ON c.id = h.customer_id
            WHERE h.hostname IN ({placeholders})
            """,
            tuple(hostnames),
        ).fetchall()
        settings_map = {
            str(row[0] or "").strip(): {
                "display_name_override": str(row[1] or "").strip(),
                "country_code_override": normalize_country_code(str(row[2] or "")),
                "is_hidden": bool(int(row[3] or 0)),
                "customer_id": int(row[4]) if row[4] is not None else None,
                "customer_name": str(row[5] or "").strip(),
                "customer_project": str(row[6] or "").strip(),
            }
            for row in settings_rows
            if str(row[0] or "").strip()
        }

    host_uid_keys = [str(row[0] or "").strip() for row in latest_rows if str(row[0] or "").strip()]
    host_uid_display_name_map: dict[str, str] = {}
    if host_uid_keys:
        placeholders = ",".join(["?"] * len(host_uid_keys))
        host_uid_rows = conn.execute(
            f"""
            SELECT host_uid, COALESCE(display_name_override, '')
            FROM host_uid_settings
            WHERE host_uid IN ({placeholders})
            """,
            tuple(host_uid_keys),
        ).fetchall()
        host_uid_display_name_map = {
            str(row[0] or "").strip(): str(row[1] or "").strip()
            for row in host_uid_rows
            if str(row[0] or "").strip()
        }

    alert_counts_rows = conn.execute(
        """
                SELECT COALESCE(NULLIF(a.host_uid, ''), a.hostname) AS host_key,
               SUM(CASE WHEN a.status = 'open' THEN 1 ELSE 0 END) AS open_count,
               SUM(CASE WHEN a.status = 'open' AND a.severity = 'critical' THEN 1 ELSE 0 END) AS critical_count
        FROM alerts a
        WHERE NOT EXISTS (
          SELECT 1 FROM muted_alert_rules m
                    WHERE m.host_uid = COALESCE(NULLIF(a.host_uid, ''), a.hostname)
                        AND m.mountpoint = a.mountpoint
        )
                GROUP BY COALESCE(NULLIF(a.host_uid, ''), a.hostname)
        """
    ).fetchall()
    alert_counts_by_host = {
        str(row[0] or ""): {
            "open": int(row[1] or 0),
            "critical": int(row[2] or 0),
        }
        for row in alert_counts_rows
        if str(row[0] or "").strip()
    }

    backup_overview = collect_backup_status_overview(conn, 24)
    backup_missing_by_host = {
        str(item.get("host_uid") or item.get("hostname") or ""): bool(item.get("has_missing_backup", False))
        for item in backup_overview.get("hosts", [])
        if isinstance(item, dict) and str(item.get("hostname") or "").strip()
    }

    grouped: dict[str, dict] = {}
    for row in latest_rows:
        host_uid = str(row[0] or "").strip()
        hostname = str(row[1] or "").strip()
        if not hostname:
            continue

        host_settings = settings_map.get(hostname, {})
        if bool(host_settings.get("is_hidden", False)):
            continue

        payload = parse_payload_json(str(row[3] or "{}"))
        display_name_override = str(host_uid_display_name_map.get(host_uid, "") or "").strip()
        if not display_name_override:
            display_name_override = str(host_settings.get("display_name_override", "") or "").strip()
        display_name = effective_display_name(payload, display_name_override, hostname)
        country_override = normalize_country_code(str(host_settings.get("country_code_override", "") or ""))
        country_code = country_override or extract_country_code_from_payload(payload)
        country_code = normalize_country_code(country_code)

        customer_name = str(host_settings.get("customer_name", "") or "").strip() or "Ohne Kunde"
        customer_key = customer_name.lower()
        customer_project = str(host_settings.get("customer_project", "") or "").strip()

        if customer_key not in grouped:
            grouped[customer_key] = {
                "customer_id": host_settings.get("customer_id"),
                "customer_name": customer_name,
                "maringo_project_number": customer_project,
                "hosts": [],
                "hosts_count": 0,
                "open_alert_count": 0,
                "critical_alert_count": 0,
                "missing_backup_count": 0,
            }
        elif customer_project and not grouped[customer_key].get("maringo_project_number"):
            grouped[customer_key]["maringo_project_number"] = customer_project
        elif grouped[customer_key].get("customer_id") is None and host_settings.get("customer_id") is not None:
            grouped[customer_key]["customer_id"] = host_settings.get("customer_id")

        alert_counts = alert_counts_by_host.get(host_uid or hostname, {"open": 0, "critical": 0})
        has_missing_backup = bool(backup_missing_by_host.get(host_uid or hostname, False))

        grouped[customer_key]["hosts"].append(
            {
                "host_uid": host_uid,
                "hostname": hostname,
                "display_name": display_name,
                "country_code": country_code,
                "report_time_utc": str(row[2] or ""),
                "open_alert_count": int(alert_counts.get("open", 0)),
                "critical_alert_count": int(alert_counts.get("critical", 0)),
                "has_missing_backup": has_missing_backup,
            }
        )
        grouped[customer_key]["hosts_count"] += 1
        grouped[customer_key]["open_alert_count"] += int(alert_counts.get("open", 0))
        grouped[customer_key]["critical_alert_count"] += int(alert_counts.get("critical", 0))
        if has_missing_backup:
            grouped[customer_key]["missing_backup_count"] += 1

    customers = sorted(
        grouped.values(),
        key=lambda item: str(item.get("customer_name", "")).lower(),
    )
    for customer in customers:
        customer["hosts"] = sorted(
            customer.get("hosts", []),
            key=lambda host: (
                str(host.get("display_name", "")).lower(),
                str(host.get("hostname", "")).lower(),
            ),
        )

    return {
        "generated_at": utc_now_iso(),
        "total_customers": len(customers),
        "total_hosts": sum(int(item.get("hosts_count", 0)) for item in customers),
        "customers": customers,
    }


def export_alerts_rows(
    conn: sqlite3.Connection,
    *,
    status: str | None = None,
    severity: str | None = None,
    allowed_tokens: set[str] | None = None,
) -> list[dict]:
    status_filter = str(status or "").strip().lower()
    if status_filter not in {"active", "resolved", "all"}:
        status_filter = "active"
    severity_filter = str(severity or "").strip().lower()
    if severity_filter not in {"warning", "critical", "all"}:
        severity_filter = "all"

    clauses = []
    params: list[object] = []
    if status_filter == "active":
        clauses.append("a.resolved_at_utc IS NULL")
    elif status_filter == "resolved":
        clauses.append("a.resolved_at_utc IS NOT NULL")
    if severity_filter != "all":
        clauses.append("a.severity = ?")
        params.append(severity_filter)

    where_sql = ""
    if clauses:
        where_sql = "WHERE " + " AND ".join(clauses)

    rows = conn.execute(
        f"""
        SELECT a.id,
               a.hostname,
               COALESCE(a.host_uid, ''),
               a.mountpoint,
               a.severity,
               a.used_percent,
               a.created_at_utc,
               COALESCE(a.last_seen_at_utc, ''),
               COALESCE(a.resolved_at_utc, '')
        FROM alerts a
        {where_sql}
        ORDER BY a.created_at_utc DESC, a.id DESC
        """,
        tuple(params),
    ).fetchall()
    blacklist_patterns = get_filesystem_blacklist_pattern_strings(conn)
    if allowed_tokens is not None:
        rows = [
            row
            for row in rows
            if host_matches_alert_visibility_tokens(str(row[1] or ""), str(row[2] or ""), allowed_tokens)
        ]
    hostnames = sorted({str(row[1] or "") for row in rows if str(row[1] or "")})
    latest_usage_by_host = _collect_latest_report_usage_by_host(conn, hostnames)

    result: list[dict] = []
    for row in rows:
        hostname = str(row[1] or "")
        mountpoint = str(row[3] or "")
        if is_filesystem_blacklisted_by_patterns(mountpoint, blacklist_patterns):
            continue
        current_used_percent = None
        host_snapshot = latest_usage_by_host.get(hostname, {})
        host_usage = host_snapshot.get("usage_by_mountpoint", {}) if isinstance(host_snapshot, dict) else {}
        current_report_at_utc = str(host_snapshot.get("received_at_utc", "") or "") if isinstance(host_snapshot, dict) else ""
        if mountpoint:
            current_used_percent = host_usage.get(normalize_mountpoint_key(mountpoint))
        delta_used_percent = None
        if current_used_percent is not None:
            delta_used_percent = float(current_used_percent) - float(row[5] or 0.0)
        result.append(
            {
                "id": int(row[0] or 0),
                "hostname": hostname,
                "mountpoint": mountpoint,
                "severity": str(row[4] or "warning"),
                "used_percent": float(row[5] or 0.0),
                "current_used_percent": current_used_percent,
                "current_report_at_utc": current_report_at_utc,
                "delta_used_percent": delta_used_percent,
                "created_at_utc": str(row[6] or ""),
                "last_seen_at_utc": str(row[7] or ""),
                "resolved_at_utc": str(row[8] or ""),
            }
        )
    return result


def export_reports_rows(conn: sqlite3.Connection, hostname: str = "", host_uid: str = "", limit: int = 500) -> list[dict]:
    host = str(hostname or "").strip()
    host_key = str(host_uid or "").strip()
    limited = max(1, min(int(limit or 500), 2000))
    host_key_expr = reports_host_key_sql()
    if host_key:
        rows = conn.execute(
            f"""
            SELECT id, hostname, received_at_utc, payload_json, {host_key_expr}
            FROM reports
            WHERE {host_key_expr} = ?
            ORDER BY id DESC
            LIMIT ?
            """,
            (host_key, limited),
        ).fetchall()
    elif host:
        rows = conn.execute(
            """
            SELECT id, hostname, received_at_utc, payload_json, COALESCE(host_uid, '')
            FROM reports
            WHERE hostname = ?
            ORDER BY id DESC
            LIMIT ?
            """,
            (host, limited),
        ).fetchall()
    else:
        rows = conn.execute(
            f"""
            SELECT id, hostname, received_at_utc, payload_json, {host_key_expr}
            FROM reports
            ORDER BY id DESC
            LIMIT ?
            """,
            (limited,),
        ).fetchall()
    data: list[dict] = []
    for row in rows:
        data.append(
            {
                "id": int(row[0] or 0),
                "hostname": str(row[1] or ""),
                "received_at_utc": str(row[2] or ""),
                "payload": parse_payload_json(str(row[3] or "{}")),
                "host_uid": str(row[4] or ""),
            }
        )
    return data


def build_ai_troubleshoot_response(conn: sqlite3.Connection, hostname: str, metric: str, hours: int) -> dict:
    host = str(hostname or "").strip()
    metric_key = str(metric or "").strip().lower()
    window_hours = max(1, min(int(hours or 24), 168))

    def build_analysis_payload(
        *,
        severity: str,
        confidence: str,
        summary: str,
        probable_causes: list[str] | None = None,
        recommended_steps: list[str] | None = None,
        quick_checks: list[str] | None = None,
        code_snippets: list[dict] | None = None,
    ) -> dict:
        return {
            "severity": severity,
            "confidence": confidence,
            "summary": summary,
            "probable_causes": probable_causes or [],
            "recommended_steps": recommended_steps or [],
            "quick_checks": quick_checks or [],
            "code_snippets": code_snippets or [],
        }

    if not host:
        return {
            "context": {"hostname": host, "metric": metric_key, "window_hours": window_hours, "samples": 0},
            "analysis": build_analysis_payload(
                severity="info",
                confidence="hoch",
                summary="Kein Hostname angegeben.",
            ),
            "model": "local-rules-v1",
            "cached": False,
        }

    cutoff_iso = utc_hours_ago_iso(window_hours)
    rows = conn.execute(
        """
        SELECT payload_json
        FROM reports
        WHERE hostname = ? AND received_at_utc >= ?
        ORDER BY id ASC
        """,
        (host, cutoff_iso),
    ).fetchall()

    values: list[float] = []
    last_payload: dict = {}
    latest_report_time_utc = ""
    for row in rows:
        payload = parse_payload_json(str(row[0] or "{}"))
        last_payload = payload
        value = None
        if metric_key == "cpu_usage_percent":
            value = extract_cpu_usage(payload)
        elif metric_key == "load_avg_1":
            value = extract_load1(payload)
        elif metric_key == "memory_used_percent":
            value = extract_memory_used_percent(payload)
        elif metric_key == "swap_used_percent":
            value = extract_swap_used_percent(payload)
        elif metric_key == "filesystem":
            fs_values: list[float] = []
            for item in payload.get("filesystems", []):
                if not isinstance(item, dict):
                    continue
                try:
                    fs_values.append(float(item.get("used_percent")))
                except (TypeError, ValueError):
                    continue
            if fs_values:
                value = max(fs_values)
        if value is None:
            continue
        values.append(max(0.0, min(float(value), 100.0 if metric_key != "load_avg_1" else float(value))))

    last_row = conn.execute(
        """
        SELECT received_at_utc, payload_json
        FROM reports
        WHERE hostname = ?
        ORDER BY id DESC
        LIMIT 1
        """,
        (host,),
    ).fetchone()
    if last_row:
        latest_report_time_utc = str(last_row[0] or "")
        if not last_payload:
            last_payload = parse_payload_json(str(last_row[1] or "{}"))

    os_family = normalize_os_family(last_payload.get("os", "linux"))
    process_names = []
    for proc in last_payload.get("processes", []):
        if isinstance(proc, dict):
            process_names.append(str(proc.get("name") or proc.get("process_name") or ""))
        else:
            process_names.append(str(proc or ""))
    has_hana_processes = any(re.search(r"\bhdb(indexserver|nameserver|scriptserver|xsengine|daemon|webdispatcher)\b", name, re.IGNORECASE) for name in process_names)

    if not values:
        return {
            "context": {
                "hostname": host,
                "metric": metric_key,
                "window_hours": window_hours,
                "samples": 0,
                "latest_report_time_utc": latest_report_time_utc,
                "os_family": os_family,
                "has_hana_processes": has_hana_processes,
            },
            "analysis": build_analysis_payload(
                severity="info",
                confidence="hoch",
                summary="Keine ausreichenden Messdaten im gewählten Zeitraum.",
                probable_causes=["Im gewählten Zeitfenster liegen keine verwertbaren Werte für diese Kennzahl vor."],
                recommended_steps=["Zeitraum vergroessern oder pruefen, ob der Agent aktuelle Reports liefert."],
            ),
            "model": "local-rules-v1",
            "cached": False,
        }

    latest = values[-1]
    avg = sum(values) / len(values)
    peak = max(values)
    if len(values) >= 4:
        recent = values[-max(2, len(values) // 3):]
        baseline = values[: max(2, len(values) // 3)]
        trend = (sum(recent) / len(recent)) - (sum(baseline) / len(baseline))
    else:
        trend = 0.0

    severity = "info"
    confidence = "mittel"
    summary = ""
    probable_causes: list[str] = []
    recommended_steps: list[str] = []
    quick_checks: list[str] = []
    code_snippets: list[dict] = []

    if metric_key == "filesystem":
        severity = "critical" if peak >= CRITICAL_THRESHOLD_PERCENT else ("warning" if peak >= WARNING_THRESHOLD_PERCENT else "info")
        confidence = "hoch" if len(values) >= 12 else "mittel"
        summary = (
            f"Filesystem-Analyse für {host}: aktuell {latest:.1f}%, Mittelwert {avg:.1f}%, Spitze {peak:.1f}%."
        )
        probable_causes = [
            "Ein oder mehrere Mountpoints laufen in eine hohe Belegung hinein.",
            "Alte Logs, Backups oder Snapshots belegen mehr Platz als erwartet.",
        ]
        if trend > 3.0:
            probable_causes.append("Die Auslastung steigt im betrachteten Zeitraum sichtbar an.")
        recommended_steps = [
            "Betroffene Mountpoints in der Filesystem-Ansicht nach aktueller Auslastung und Delta sortieren.",
            "Groesste Verzeichnisse/Dateien pruefen und mit den Backup- bzw. Snapshot-Routinen abgleichen.",
        ]
        quick_checks = [
            f"Aktuell: {latest:.1f}% | Peak: {peak:.1f}% | Samples: {len(values)}",
            "Pruefen, ob hohe Werte von Snapshot- oder Backup-Mountpoints stammen.",
        ]
        code_snippets = [
            {
                "shell": "bash",
                "title": "Groesste Verzeichnisse finden",
                "command": "du -xhd1 / | sort -h | tail -20",
                "description": "Zeigt die groessten Verzeichnisse auf dem betroffenen Mountpoint.",
            }
        ]
    elif metric_key == "load_avg_1":
        severity = "critical" if peak >= 4.0 else ("warning" if peak >= 2.0 else "info")
        confidence = "mittel"
        summary = f"Load-Analyse für {host}: aktuell {latest:.2f}, Mittelwert {avg:.2f}, Spitze {peak:.2f}."
        probable_causes = [
            "CPU-intensive Prozesse oder I/O-Wartezeiten treiben den Load Average hoch.",
            "Kurzfristige Jobs oder Backups koennen Lastspitzen ausloesen.",
        ]
        recommended_steps = [
            "Top CPU/IO Prozesse im gleichen Zeitfenster pruefen.",
            "Mit CPU-, Memory- und Filesystem-Trends gegenpruefen.",
        ]
        quick_checks = [f"Aktuell: {latest:.2f} | Peak: {peak:.2f} | Samples: {len(values)}"]
        code_snippets = [
            {
                "shell": "bash",
                "title": "Last live pruefen",
                "command": "uptime && top -b -n1 | head -30",
                "description": "Zeigt aktuellen Load Average und die aktivsten Prozesse.",
            }
        ]
    else:
        severity = "critical" if peak >= CRITICAL_THRESHOLD_PERCENT else ("warning" if peak >= WARNING_THRESHOLD_PERCENT else "info")
        confidence = "hoch" if len(values) >= 12 else "mittel"
        direction = "steigend" if trend > 3.0 else ("fallend" if trend < -3.0 else "seitwaerts")
        summary = (
            f"Trend-Analyse für {host}: aktuell {latest:.1f}%, Mittelwert {avg:.1f}%, Spitze {peak:.1f}%. Trend: {direction}."
        )
        probable_causes = [
            "Die Kennzahl zeigt über das Zeitfenster eine anhaltende Last oder wiederkehrende Peaks.",
            "Parallele Jobs, Speicherdruck oder Hintergrundprozesse koennen den Verlauf erklaeren.",
        ]
        recommended_steps = [
            "Benachbarte Metriken im gleichen Zeitraum vergleichen, um CPU/Memory/FS-Korrelationen zu sehen.",
            "Bei wiederkehrenden Peaks geplante Jobs oder Backups zeitlich abgleichen.",
        ]
        quick_checks = [f"Aktuell: {latest:.1f}% | Peak: {peak:.1f}% | Trend: {direction}"]

    return {
        "context": {
            "hostname": host,
            "metric": metric_key,
            "window_hours": window_hours,
            "samples": len(values),
            "latest": round(latest, 2),
            "average": round(avg, 2),
            "peak": round(peak, 2),
            "latest_report_time_utc": latest_report_time_utc,
            "os_family": os_family,
            "has_hana_processes": has_hana_processes,
        },
        "analysis": build_analysis_payload(
            severity=severity,
            confidence=confidence,
            summary=summary,
            probable_causes=probable_causes,
            recommended_steps=recommended_steps,
            quick_checks=quick_checks,
            code_snippets=code_snippets,
        ),
        "model": "local-rules-v1",
        "cached": False,
    }


def _filesystem_usage_from_payload(payload: dict, mountpoint: str) -> float | None:
    mount = str(mountpoint or "").strip()
    if not mount:
        return None
    for item in payload.get("filesystems", []):
        if not isinstance(item, dict):
            continue
        if str(item.get("mountpoint", "")).strip() != mount:
            continue
        try:
            value = float(item.get("used_percent"))
        except (TypeError, ValueError):
            return None
        return max(0.0, min(value, 100.0))
    return None


def collect_filesystem_usage_series(
    conn: sqlite3.Connection,
    hostname: str,
    mountpoint: str,
    host_uid: str = "",
    *,
    hours: int = 24,
    max_points: int = 72,
) -> list[float]:
    host = str(hostname or "").strip()
    mount = str(mountpoint or "").strip()
    host_key = alert_host_key(host, host_uid)
    if not host_key or not mount:
        return []

    cutoff_iso = utc_hours_ago_iso(hours)
    host_key_expr = reports_host_key_sql()
    rows = conn.execute(
        f"""
        SELECT payload_json
        FROM reports
        WHERE {host_key_expr} = ? AND received_at_utc >= ?
        ORDER BY id ASC
        """,
        (host_key, cutoff_iso),
    ).fetchall()

    values: list[float] = []
    for row in rows:
        payload = parse_payload_json(str(row[0] or "{}"))
        used = _filesystem_usage_from_payload(payload, mount)
        if used is not None:
            values.append(used)

    if len(values) <= max_points:
        return values

    step = max(1, len(values) // max_points)
    compact = [values[i] for i in range(0, len(values), step)]
    if compact and compact[-1] != values[-1]:
        compact.append(values[-1])
    return compact[-max_points:]


def render_usage_series_svg(
    values: list[float],
    *,
    warning_threshold: float = WARNING_THRESHOLD_PERCENT,
    critical_threshold: float = CRITICAL_THRESHOLD_PERCENT,
    severity: str = "warning",
    title: str = "Auslastung letzte 24h",
) -> str | None:
    if len(values) < 3:
        return None

    width = 640
    height = 220
    left = 44
    right = 16
    top = 16
    bottom = 32
    plot_width = width - left - right
    plot_height = height - top - bottom

    cleaned = [max(0.0, min(float(v), 100.0)) for v in values]
    n = len(cleaned)

    def x_at(index: int) -> float:
        if n <= 1:
            return float(left)
        return left + (plot_width * index / (n - 1))

    def y_at(percent: float) -> float:
        return top + (100.0 - percent) * plot_height / 100.0

    points = " ".join(f"{x_at(idx):.2f},{y_at(value):.2f}" for idx, value in enumerate(cleaned))
    fill_points = f"{left:.2f},{top + plot_height:.2f} {points} {left + plot_width:.2f},{top + plot_height:.2f}"

    warning_y = y_at(max(0.0, min(float(warning_threshold), 100.0)))
    critical_y = y_at(max(0.0, min(float(critical_threshold), 100.0)))
    last_value = cleaned[-1]
    line_color = "#dc2626" if severity == "critical" else "#d97706"
    if severity not in {"critical", "warning"}:
        line_color = "#2563eb"

    svg_title = html.escape(title)
    return (
        f"<svg xmlns='http://www.w3.org/2000/svg' width='{width}' height='{height}' viewBox='0 0 {width} {height}' role='img' aria-label='{svg_title}'>"
        "<defs>"
        "<linearGradient id='usageFill' x1='0' y1='0' x2='0' y2='1'>"
        "<stop offset='0%' stop-color='#93c5fd' stop-opacity='0.45'/>"
        "<stop offset='100%' stop-color='#93c5fd' stop-opacity='0.02'/>"
        "</linearGradient>"
        "</defs>"
        "<rect x='0' y='0' width='640' height='220' rx='12' fill='#ffffff'/>"
        f"<rect x='{left}' y='{top}' width='{plot_width}' height='{plot_height}' rx='10' fill='#f8fbff' stroke='#dbe4f0'/>"
        f"<line x1='{left}' y1='{warning_y:.2f}' x2='{left + plot_width}' y2='{warning_y:.2f}' stroke='#f59e0b' stroke-dasharray='5 4' stroke-width='1'/>"
        f"<line x1='{left}' y1='{critical_y:.2f}' x2='{left + plot_width}' y2='{critical_y:.2f}' stroke='#ef4444' stroke-dasharray='5 4' stroke-width='1'/>"
        f"<polyline points='{fill_points}' fill='url(#usageFill)' stroke='none'/>"
        f"<polyline points='{points}' fill='none' stroke='{line_color}' stroke-width='3' stroke-linecap='round' stroke-linejoin='round'/>"
        f"<circle cx='{x_at(n - 1):.2f}' cy='{y_at(last_value):.2f}' r='5' fill='{line_color}' stroke='#ffffff' stroke-width='2'/>"
        f"<text x='12' y='{y_at(100):.2f}' fill='#64748b' font-family='Segoe UI,Arial,sans-serif' font-size='11'>100%</text>"
        f"<text x='18' y='{y_at(50):.2f}' fill='#64748b' font-family='Segoe UI,Arial,sans-serif' font-size='11'>50%</text>"
        f"<text x='24' y='{y_at(0):.2f}' fill='#64748b' font-family='Segoe UI,Arial,sans-serif' font-size='11'>0%</text>"
        f"<text x='{left}' y='{height - 10}' fill='#64748b' font-family='Segoe UI,Arial,sans-serif' font-size='11'>letzte {n} Messpunkte</text>"
        f"<text x='{left + plot_width}' y='{height - 10}' text-anchor='end' fill='#0f172a' font-family='Segoe UI,Arial,sans-serif' font-size='12' font-weight='700'>aktuell {last_value:.1f}%</text>"
        "</svg>"
    )


def make_inline_svg_attachment(svg_content: str, *, cid: str, name: str) -> dict:
    return {
        "@odata.type": "#microsoft.graph.fileAttachment",
        "name": name,
        "contentType": "image/svg+xml",
        "isInline": True,
        "contentId": cid,
        "contentBytes": base64.b64encode(svg_content.encode("utf-8")).decode("ascii"),
    }


def svg_to_png_bytes(svg_content: str, *, scale: float = 1.5) -> bytes | None:
    """Convert SVG string to PNG bytes using cairosvg, returns None if unavailable."""
    if not _CAIROSVG_AVAILABLE or _cairosvg is None:
        return None
    try:
        return _cairosvg.svg2png(bytestring=svg_content.encode("utf-8"), scale=scale)
    except Exception:
        return None


def make_inline_png_attachment(png_bytes: bytes, *, cid: str, name: str) -> dict:
    return {
        "@odata.type": "#microsoft.graph.fileAttachment",
        "name": name,
        "contentType": "image/png",
        "isInline": True,
        "contentId": cid,
        "contentBytes": base64.b64encode(png_bytes).decode("ascii"),
    }


def build_alert_usage_graph_attachment(
    conn: sqlite3.Connection,
    hostname: str,
    mountpoint: str,
    host_uid: str = "",
    *,
    severity: str,
    hours: int = 24,
) -> tuple[str | None, dict | None]:
    series = collect_filesystem_usage_series(conn, hostname, mountpoint, host_uid=host_uid, hours=hours)
    if len(series) < 3:
        return None, None

    graph_title = f"{hostname} {mountpoint} Auslastung (letzte {hours}h)"
    svg = render_usage_series_svg(series, severity=severity, title=graph_title)
    if not svg:
        return None, None

    safe_host = _safe_attachment_token(hostname, "host")
    safe_mount = _safe_attachment_token(mountpoint.replace("/", "-"), "mount")
    cid = f"graph-{safe_host}-{safe_mount}-{secrets.token_hex(4)}@monitoring"

    # Prefer PNG (works in Outlook); fall back to SVG if cairosvg unavailable
    png_bytes = svg_to_png_bytes(svg)
    if png_bytes:
        filename = f"graph-{safe_host}-{safe_mount}.png"
        return cid, make_inline_png_attachment(png_bytes, cid=cid, name=filename)

    filename = f"graph-{safe_host}-{safe_mount}.svg"
    return cid, make_inline_svg_attachment(svg, cid=cid, name=filename)


def build_alert_digest_graph_bundle(
    conn: sqlite3.Connection,
    alerts: list[dict],
    *,
    hours: int = 24,
    max_graphs: int = 8,
) -> tuple[dict[int, str], list[dict]]:
    graph_cids: dict[int, str] = {}
    attachments: list[dict] = []

    for item in alerts[:max_graphs]:
        alert_id = int(item.get("id") or 0)
        hostname = str(item.get("hostname") or "").strip()
        host_uid = str(item.get("host_uid") or "").strip()
        mountpoint = str(item.get("mountpoint") or "").strip()
        severity = str(item.get("severity") or "warning").strip().lower()
        if alert_id <= 0 or not hostname or not mountpoint or severity not in {"critical", "warning"}:
            continue

        cid, attachment = build_alert_usage_graph_attachment(
            conn,
            hostname,
            mountpoint,
            host_uid=host_uid,
            severity=severity,
            hours=hours,
        )
        if not cid or not attachment:
            continue
        graph_cids[alert_id] = cid
        attachments.append(attachment)

    return graph_cids, attachments


def host_badges_html(country_code: object, os_family: object) -> str:
    normalized_country_code = normalize_country_code(country_code)
    country_badge = normalized_country_code if normalized_country_code else "--"
    normalized_os_family = normalize_os_family(os_family)
    os_label = os_family_label(normalized_os_family)
    os_logo_uri = os_logo_data_uri(normalized_os_family)
    country_flag_uri = country_flag_data_uri(normalized_country_code)
    os_icon_html = (
        f"<img src='{html.escape(os_logo_uri)}' alt='{html.escape(os_label)}' width='13' height='13' style='display:block;'>"
        if os_logo_uri
        else ""
    )
    country_icon_html = (
        f"<img src='{html.escape(country_flag_uri)}' alt='{html.escape(country_badge)}' width='13' height='13' style='display:block;'>"
        if country_flag_uri
        else ""
    )
    os_badge = (
        f"<span style='display:inline-flex;align-items:center;padding:3px 6px;border-radius:999px;background:transparent;'>{os_icon_html}</span>"
        if os_icon_html else ""
    )
    country_badge_html = (
        f"<span style='display:inline-flex;align-items:center;padding:3px 6px;border-radius:999px;background:transparent;'>{country_icon_html}</span>"
        if country_icon_html else ""
    )
    return (
        "<div style='margin-top:4px;display:flex;gap:6px;flex-wrap:wrap;'>"
        f"{os_badge}{country_badge_html}"
        "</div>"
    )


