def _load_host_metadata_maps(
    conn: sqlite3.Connection,
    hostnames: list[str] | None = None,
    host_uids: list[str] | None = None,
) -> tuple[dict[str, dict], dict[str, str]]:
    host_settings_by_hostname: dict[str, dict] = {}
    display_name_by_host_uid: dict[str, str] = {}

    normalized_hostnames = sorted({str(item or "").strip() for item in (hostnames or []) if str(item or "").strip()})
    if normalized_hostnames:
        placeholders = ",".join("?" for _ in normalized_hostnames)
        settings_rows = conn.execute(
            f"""
            SELECT h.hostname,
                   COALESCE(h.display_name_override, ''),
                   COALESCE(h.country_code_override, ''),
                   COALESCE(c.customer_name, '')
            FROM host_settings h
            LEFT JOIN customers c ON c.id = h.customer_id
            WHERE h.hostname IN ({placeholders})
            """,
            tuple(normalized_hostnames),
        ).fetchall()
        for row in settings_rows:
            hostname = str(row[0] or "").strip()
            if not hostname:
                continue
            host_settings_by_hostname[hostname] = {
                "display_name_override": str(row[1] or "").strip(),
                "country_code_override": normalize_country_code(row[2]),
                "customer_name": str(row[3] or "").strip(),
            }

    normalized_host_uids = sorted({str(item or "").strip() for item in (host_uids or []) if str(item or "").strip()})
    if normalized_host_uids:
        placeholders = ",".join("?" for _ in normalized_host_uids)
        uid_rows = conn.execute(
            f"""
            SELECT host_uid, COALESCE(display_name_override, '')
            FROM host_uid_settings
            WHERE host_uid IN ({placeholders})
            """,
            tuple(normalized_host_uids),
        ).fetchall()
        for row in uid_rows:
            host_uid = str(row[0] or "").strip()
            if not host_uid:
                continue
            display_name_by_host_uid[host_uid] = str(row[1] or "").strip()

    return host_settings_by_hostname, display_name_by_host_uid


def _load_alert_mobile_context_map(
    conn: sqlite3.Connection,
    host_pairs: list[tuple[str, str]],
) -> dict[str, dict[str, str]]:
    ensure_customers_extended_columns(conn)
    unique_pairs: list[tuple[str, str, str]] = []
    seen_keys: set[str] = set()
    for hostname_raw, host_uid_raw in host_pairs:
        hostname = str(hostname_raw or "").strip()
        host_uid = str(host_uid_raw or "").strip()
        host_key = alert_host_key(hostname, host_uid)
        if not host_key or host_key in seen_keys:
            continue
        seen_keys.add(host_key)
        unique_pairs.append((hostname, host_uid, host_key))

    if not unique_pairs:
        return {}

    hostnames = sorted({hostname for hostname, _, _ in unique_pairs if hostname})
    host_keys = sorted({host_key for _, _, host_key in unique_pairs})
    hostname_settings: dict[str, dict[str, object]] = {}
    if hostnames:
        placeholders = ",".join("?" for _ in hostnames)
        settings_rows = conn.execute(
            f"""
            SELECT
                h.hostname,
                COALESCE(h.country_code_override, ''),
                COALESCE(h.environment_type, ''),
                COALESCE(c.customer_name, ''),
                COALESCE(c.logo_filename, ''),
                COALESCE(c.updated_at_utc, ''),
                h.customer_id,
                COALESCE(c.it_provider_name, ''),
                COALESCE(c.it_provider_contact, ''),
                COALESCE(c.it_provider_email, ''),
                COALESCE(c.it_provider_phone, '')
            FROM host_settings h
            LEFT JOIN customers c ON c.id = h.customer_id
            WHERE h.hostname IN ({placeholders})
            """,
            tuple(hostnames),
        ).fetchall()
        for row in settings_rows:
            hostname = str(row[0] or "").strip()
            if not hostname:
                continue
            environment_type = str(row[2] or "").strip().lower()
            if environment_type not in {"prod", "test"}:
                environment_type = ""
            hostname_settings[hostname] = {
                "country_code_override": normalize_country_code(row[1]),
                "environment_type": environment_type,
                "customer_name": str(row[3] or "").strip(),
                "customer_logo_url": build_customer_logo_url(row[6], row[4], row[5]),
                "it_provider_contact_line": str(row[8] or "").strip() or str(row[7] or "").strip() or str(row[9] or "").strip(),
                "it_provider_email": str(row[9] or "").strip(),
                "it_provider_phone": str(row[10] or "").strip(),
            }

    uid_settings: dict[str, dict[str, object]] = {}
    if host_keys:
        placeholders = ",".join("?" for _ in host_keys)
        uid_rows = conn.execute(
            f"""
            SELECT
                hus.host_uid,
                COALESCE(hus.country_code_override, ''),
                COALESCE(hus.environment_type, ''),
                hus.customer_id,
                COALESCE(c.customer_name, ''),
                COALESCE(c.logo_filename, ''),
                COALESCE(c.updated_at_utc, ''),
                COALESCE(c.it_provider_name, ''),
                COALESCE(c.it_provider_contact, ''),
                COALESCE(c.it_provider_email, ''),
                COALESCE(c.it_provider_phone, '')
            FROM host_uid_settings hus
            LEFT JOIN customers c ON c.id = hus.customer_id
            WHERE hus.host_uid IN ({placeholders})
            """,
            tuple(host_keys),
        ).fetchall()
        for row in uid_rows:
            host_key = str(row[0] or "").strip()
            if not host_key:
                continue
            environment_type = str(row[2] or "").strip().lower()
            if environment_type not in {"prod", "test"}:
                environment_type = ""
            uid_settings[host_key] = {
                "country_code_override": normalize_country_code(row[1]),
                "environment_type": environment_type,
                "customer_name": str(row[4] or "").strip(),
                "customer_logo_url": build_customer_logo_url(row[3], row[5], row[6]),
                "it_provider_contact_line": str(row[8] or "").strip() or str(row[7] or "").strip() or str(row[9] or "").strip(),
                "it_provider_email": str(row[9] or "").strip(),
                "it_provider_phone": str(row[10] or "").strip(),
            }

    context_by_host_key: dict[str, dict[str, str]] = {}
    for hostname, _host_uid, host_key in unique_pairs:
        base = hostname_settings.get(hostname, {})
        override = uid_settings.get(host_key, {})
        customer_name = str(override.get("customer_name") or base.get("customer_name") or "").strip()
        customer_logo_url = str(override.get("customer_logo_url") or base.get("customer_logo_url") or "").strip()
        environment_type = str(override.get("environment_type") or base.get("environment_type") or "").strip().lower()
        if environment_type not in {"prod", "test"}:
            environment_type = ""
        country_override = normalize_country_code(
            str(override.get("country_code_override") or base.get("country_code_override") or "")
        )
        contact_line = str(override.get("it_provider_contact_line") or base.get("it_provider_contact_line") or "").strip()
        provider_email = str(override.get("it_provider_email") or base.get("it_provider_email") or "").strip()
        provider_phone = str(override.get("it_provider_phone") or base.get("it_provider_phone") or "").strip()
        context_by_host_key[host_key] = {
            "customer_name": customer_name,
            "customer_logo_url": customer_logo_url,
            "environment_type": environment_type,
            "country_code_override": country_override,
            "it_provider_contact_line": contact_line,
            "it_provider_email": provider_email,
            "it_provider_phone": provider_phone,
        }
    return context_by_host_key


def _bulk_alert_country_codes(
    conn: sqlite3.Connection,
    rows: list[tuple],
) -> dict[str, str]:
    country_by_host_key: dict[str, str] = {}
    if not rows:
        return country_by_host_key

    identity_row_by_key: dict[str, tuple] = {}
    identity_rows, _, _, _ = _peek_identity_maps_cache()
    if identity_rows is not None:
        identity_row_by_key = {str(row[0] or "").strip(): row for row in identity_rows if str(row[0] or "").strip()}

    hostnames = sorted({str(row[1] or "").strip() for row in rows if str(row[1] or "").strip()})
    host_keys = sorted(
        {
            alert_host_key(str(row[1] or ""), str(row[6] or ""))
            for row in rows
            if alert_host_key(str(row[1] or ""), str(row[6] or ""))
        }
    )
    host_settings_by_hostname, _ = _load_host_metadata_maps(conn, hostnames, host_keys)

    uid_country_overrides: dict[str, str] = {}
    if host_keys:
        placeholders = ",".join("?" for _ in host_keys)
        for uid_row in conn.execute(
            f"""
            SELECT host_uid, COALESCE(country_code_override, '')
            FROM host_uid_settings
            WHERE host_uid IN ({placeholders})
            """,
            tuple(host_keys),
        ).fetchall():
            host_uid = str(uid_row[0] or "").strip()
            if host_uid:
                uid_country_overrides[host_uid] = normalize_country_code(uid_row[1])

    for row in rows:
        host_key = alert_host_key(str(row[1] or ""), str(row[6] or ""))
        if not host_key or host_key in country_by_host_key:
            continue
        country_code = uid_country_overrides.get(host_key, "")
        if not country_code:
            country_code = host_settings_by_hostname.get(str(row[1] or "").strip(), {}).get("country_code_override", "")
            country_code = normalize_country_code(country_code)
        if not country_code:
            identity_row = identity_row_by_key.get(host_key)
            if identity_row is not None:
                payload = parse_payload_json(str(identity_row[3] or "{}"))
                country_code = extract_country_code_from_payload(payload)
        country_by_host_key[host_key] = country_code
    return country_by_host_key


def _resolve_alert_country_code(
    mobile_context: dict[str, str],
    host_details: dict | None,
) -> str:
    country_override = normalize_country_code(str(mobile_context.get("country_code_override", "") or ""))
    if country_override:
        return country_override
    if isinstance(host_details, dict):
        return normalize_country_code(str(host_details.get("country_code", "") or ""))
    return ""


def is_alert_muted(conn: sqlite3.Connection, host_key: str, mountpoint: str) -> bool:
    row = conn.execute(
        "SELECT 1 FROM muted_alert_rules WHERE host_uid = ? AND mountpoint = ?",
        (host_key, mountpoint),
    ).fetchone()
    return row is not None


def is_alert_heads_up_suppressed(conn: sqlite3.Connection, host_key: str, mountpoint: str) -> bool:
    row = conn.execute(
        "SELECT 1 FROM heads_up_suppression_rules WHERE host_uid = ? AND mountpoint = ?",
        (host_key, mountpoint),
    ).fetchone()
    return row is not None


def resolve_open_alerts_for_host(conn: sqlite3.Connection, hostname: str, host_uid: str, report_id: int | None) -> None:
    now_utc = utc_now_iso()
    host_key = alert_host_key(hostname, host_uid)
    conn.execute(
        """
        UPDATE alerts
        SET status = 'resolved', resolved_at_utc = ?, last_seen_at_utc = ?, report_id = ?
        WHERE COALESCE(NULLIF(host_uid, ''), hostname) = ? AND status = 'open'
        """,
        (now_utc, now_utc, report_id, host_key),
    )
    conn.execute("DELETE FROM alert_debounce WHERE host_uid = ?", (host_key,))


def prune_reports_for_host(conn: sqlite3.Connection, hostname: str, host_uid: str, keep_count: int) -> None:
    keep_count = max(0, int(keep_count))
    retention_days = max(1, int(REPORT_RETENTION_DAYS))
    cutoff_iso = (datetime.now(timezone.utc) - timedelta(days=retention_days)).strftime("%Y-%m-%dT%H:%M:%SZ")

    host_uid_value = str(host_uid or "").strip()
    prune_where_clause = "hostname = ?"
    prune_where_args: tuple[object, ...] = (hostname,)
    if host_uid_value:
        # Keep retention/count pruning aligned with host identity where host_uid is available.
        prune_where_clause = "COALESCE(NULLIF(host_uid, ''), hostname) = ?"
        prune_where_args = (host_uid_value,)

    conn.execute(
        """
        UPDATE alerts
        SET report_id = NULL
        WHERE report_id IN (
            SELECT id
            FROM reports
            WHERE {prune_where_clause} AND received_at_utc < ?
        )
        """.format(prune_where_clause=prune_where_clause),
        (*prune_where_args, cutoff_iso),
    )
    conn.execute(
        """
        DELETE FROM reports
        WHERE {prune_where_clause} AND received_at_utc < ?
        """.format(prune_where_clause=prune_where_clause),
        (*prune_where_args, cutoff_iso),
    )

    if keep_count <= 0:
        return

    conn.execute(
        """
        UPDATE alerts
        SET report_id = NULL
        WHERE report_id IN (
            SELECT id
            FROM reports
            WHERE {prune_where_clause}
            ORDER BY id DESC
            LIMIT -1 OFFSET ?
        )
        """.format(prune_where_clause=prune_where_clause),
        (*prune_where_args, keep_count),
    )
    conn.execute(
        """
        DELETE FROM reports
        WHERE id IN (
            SELECT id
            FROM reports
            WHERE {prune_where_clause}
            ORDER BY id DESC
            LIMIT -1 OFFSET ?
        )
        """.format(prune_where_clause=prune_where_clause),
        (*prune_where_args, keep_count),
    )


def _process_agent_report_payload(conn: sqlite3.Connection, payload: dict, report_received_at_utc: str) -> int:
    hostname = str(payload.get("hostname", "")).strip()
    if not hostname:
        raise ValueError("hostname missing")

    filesystems = payload.get("filesystems", [])
    if not isinstance(filesystems, list):
        raise ValueError("filesystems must be an array")

    incoming_agent_id = str(payload.get("agent_id", "") or "")
    incoming_primary_ip = str(payload.get("primary_ip", "") or "")
    incoming_host_uid = _resolve_incoming_host_uid(
        conn,
        payload,
        hostname,
        agent_id=incoming_agent_id,
        primary_ip=incoming_primary_ip,
    )
    payload["host_uid"] = incoming_host_uid
    _reconcile_legacy_host_uids(
        conn,
        payload,
        hostname,
        incoming_host_uid,
        agent_id=incoming_agent_id,
        primary_ip=incoming_primary_ip,
    )

    payload_json = json.dumps(payload, separators=(",", ":"))
    host_lookup_key = incoming_host_uid if incoming_host_uid else hostname
    existing_row = conn.execute(
        """
        SELECT id
        FROM reports
        WHERE COALESCE(NULLIF(host_uid, ''), hostname) = ?
          AND received_at_utc = ?
          AND payload_json = ?
        ORDER BY id ASC
        LIMIT 1
        """,
        (host_lookup_key, report_received_at_utc, payload_json),
    ).fetchone()
    if existing_row:
        return int(existing_row[0] or 0)

    cursor = conn.execute(
        """
        INSERT INTO reports (received_at_utc, agent_id, hostname, host_uid, primary_ip, payload_json)
        VALUES (?, ?, ?, ?, ?, ?)
        """,
        (
            report_received_at_utc,
            incoming_agent_id,
            hostname,
            incoming_host_uid,
            incoming_primary_ip,
            payload_json,
        ),
    )
    report_id = int(cursor.lastrowid)
    ensure_linux_mountpoint_defaults_for_host(
        conn,
        hostname,
        incoming_host_uid,
        payload,
        force=False,
    )
    _track_host_config_changes(conn, hostname, incoming_host_uid, payload, report_id, report_received_at_utc)
    _track_sap_addon_changes(conn, hostname, incoming_host_uid, payload, report_id, report_received_at_utc)
    _track_database_lifecycle(conn, hostname, payload, report_id, report_received_at_utc)
    prune_reports_for_host(conn, hostname, incoming_host_uid, MAX_REPORTS_PER_HOST)
    alarm_settings = get_alarm_settings(conn)
    host_settings = get_host_settings(conn, hostname)
    if bool(host_settings.get("is_hidden", False)):
        resolve_open_alerts_for_host(conn, hostname, incoming_host_uid, report_id)
    else:
        update_alerts_for_report(conn, hostname, incoming_host_uid, report_id, filesystems, alarm_settings)
    maybe_send_alert_reminders(conn)
    maybe_send_inactive_host_notifications(conn)
    maybe_send_scheduled_user_mails(conn)
    try:
        maybe_send_live_report_web_push(
            conn,
            report_id=report_id,
            hostname=hostname,
            host_uid=incoming_host_uid,
            payload=payload,
            received_at_utc=report_received_at_utc,
        )
    except Exception as exc:
        print(f"[live-report-push] report_id={report_id} hostname={hostname}: {exc}")

    _schedule_identity_maps_cache_invalidation()
    _schedule_read_cache_invalidation("hosts:")
    _schedule_read_cache_invalidation("inactive-hosts:")
    _schedule_read_cache_invalidation("alerts-summary:")
    _schedule_read_cache_invalidation("alerts-list:")
    _schedule_read_cache_invalidation("system-overview:")
    _schedule_read_cache_invalidation("backup-status-overview:")
    _schedule_read_cache_invalidation("customer-overview:")
    _schedule_read_cache_invalidation("critical-trends:")
    _schedule_read_cache_invalidation("host-config-changes:")
    _schedule_read_cache_invalidation("agent-source-status:")
    _schedule_read_cache_invalidation("host-reports:")
    _schedule_read_cache_invalidation("host-reports-meta:")
    _schedule_read_cache_invalidation("analysis:")

    # Keep behavior identical to direct-ingest: non-blocking best effort.
    auto_sync_discovered_license_types(payload)
    return report_id


def _run_sqlite_with_busy_retry(
    operation,
    *,
    attempts: int = 12,
    label: str = "sqlite-write",
):
    last_exc: sqlite3.OperationalError | None = None
    safe_attempts = max(1, min(int(attempts or 1), 30))
    for attempt in range(safe_attempts):
        try:
            with sqlite_connect() as conn:
                return operation(conn)
        except sqlite3.OperationalError as exc:
            error_text = str(exc).lower()
            if "locked" not in error_text and "busy" not in error_text:
                raise
            last_exc = exc
            sleep_seconds = min(2.5, 0.12 * (attempt + 1))
            print(
                f"[sqlite-retry] {label}: database busy "
                f"(attempt {attempt + 1}/{safe_attempts}, sleep {sleep_seconds:.2f}s)"
            )
            time.sleep(sleep_seconds)
    if last_exc is not None:
        raise last_exc
    raise sqlite3.OperationalError("database is locked")


def enqueue_agent_report(payload: dict, report_received_at_utc: str) -> int:
    hostname = str(payload.get("hostname", "")).strip()
    host_uid = str(payload.get("host_uid", "") or "").strip()
    payload_json = json.dumps(payload, separators=(",", ":"))
    payload_bytes = len(payload_json.encode("utf-8"))
    now_utc = utc_now_iso()

    def _enqueue(conn: sqlite3.Connection) -> int:
        cursor = conn.execute(
            """
            INSERT INTO agent_ingest_queue (
                enqueued_at_utc,
                report_received_at_utc,
                hostname,
                host_uid,
                payload_json,
                attempt_count,
                next_attempt_at_utc,
                processing_started_at_utc,
                last_error,
                updated_at_utc
            ) VALUES (?, ?, ?, ?, ?, 0, ?, '', '', ?)
            """,
            (
                now_utc,
                report_received_at_utc,
                hostname,
                host_uid,
                payload_json,
                now_utc,
                now_utc,
            ),
        )
        queue_id = int(cursor.lastrowid)
        payload_file_path = _write_agent_ingest_audit_payload_file(
            queue_id=queue_id,
            hostname=hostname,
            report_received_at_utc=report_received_at_utc,
            payload_json=payload_json,
        )
        _insert_agent_ingest_audit_log_row(
            conn,
            queue_id=queue_id,
            hostname=hostname,
            host_uid=host_uid,
            report_received_at_utc=report_received_at_utc,
            enqueued_at_utc=now_utc,
            payload_bytes=payload_bytes,
            payload_file_path=payload_file_path,
        )
        conn.commit()
        return queue_id

    queue_id = int(
        _run_sqlite_with_busy_retry(_enqueue, label="enqueue_agent_report")
    )
    _agent_ingest_queue_wakeup.set()
    return queue_id


def _agent_ingest_retry_backoff_seconds(attempt_count: int) -> int:
    safe_attempt = max(1, int(attempt_count))
    return min(AGENT_INGEST_RETRY_MAX_BACKOFF_SECONDS, 2 ** min(safe_attempt, 10))


def _agent_ingest_schedule_retry(
    conn: sqlite3.Connection,
    *,
    queue_id: int,
    attempt_count: int,
    error_message: str,
) -> None:
    backoff = _agent_ingest_retry_backoff_seconds(attempt_count)
    retry_at = (datetime.now(timezone.utc) + timedelta(seconds=backoff)).strftime("%Y-%m-%dT%H:%M:%SZ")
    failure_at_utc = utc_now_iso()
    conn.execute(
        """
        UPDATE agent_ingest_queue
        SET next_attempt_at_utc = ?,
            processing_started_at_utc = '',
            last_error = ?,
            updated_at_utc = ?,
            attempt_count = ?
        WHERE id = ?
        """,
        (retry_at, error_message, failure_at_utc, attempt_count, queue_id),
    )
    _update_agent_ingest_audit_log_row(
        conn,
        queue_id=queue_id,
        status="retrying",
        updated_at_utc=failure_at_utc,
        attempt_count=attempt_count,
        error_message=error_message,
    )
    conn.commit()


def _agent_ingest_worker_loop() -> None:
    while True:
        had_work = False
        try:
            with sqlite_connect() as conn:
                now_utc = utc_now_iso()
                rows = conn.execute(
                    """
                    SELECT id, payload_json, report_received_at_utc, enqueued_at_utc, attempt_count
                    FROM agent_ingest_queue
                    WHERE next_attempt_at_utc <= ?
                    ORDER BY id ASC
                    LIMIT ?
                    """,
                    (now_utc, AGENT_INGEST_BATCH_SIZE),
                ).fetchall()

                if not rows:
                    conn.commit()
                else:
                    had_work = True
                    for row in rows:
                        queue_id = int(row[0] or 0)
                        payload_json = str(row[1] or "{}")
                        report_received_at_utc = str(row[2] or "") or now_utc
                        enqueued_at_utc = str(row[3] or "") or report_received_at_utc
                        attempt_count = int(row[4] or 0) + 1
                        processing_started_at_utc = utc_now_iso()

                        if attempt_count > AGENT_INGEST_MAX_ATTEMPTS:
                            failure_at_utc = utc_now_iso()
                            error_message = f"max attempts ({AGENT_INGEST_MAX_ATTEMPTS}) exceeded"
                            _update_agent_ingest_audit_log_row(
                                conn,
                                queue_id=queue_id,
                                status="failed",
                                updated_at_utc=failure_at_utc,
                                attempt_count=attempt_count,
                                error_message=error_message,
                            )
                            conn.execute("DELETE FROM agent_ingest_queue WHERE id = ?", (queue_id,))
                            conn.commit()
                            print(f"[agent-ingest-worker] queue_id={queue_id} dropped: {error_message}")
                            continue

                        conn.execute("BEGIN IMMEDIATE")
                        try:
                            conn.execute(
                                """
                                UPDATE agent_ingest_queue
                                SET attempt_count = ?,
                                    processing_started_at_utc = ?,
                                    updated_at_utc = ?
                                WHERE id = ?
                                """,
                                (attempt_count, processing_started_at_utc, processing_started_at_utc, queue_id),
                            )
                            _update_agent_ingest_audit_log_row(
                                conn,
                                queue_id=queue_id,
                                status="processing",
                                updated_at_utc=processing_started_at_utc,
                                attempt_count=attempt_count,
                            )

                            payload = json.loads(payload_json)
                            if not isinstance(payload, dict):
                                raise ValueError("queued payload must be a JSON object")

                            _process_agent_report_payload(conn, payload, report_received_at_utc)
                            written_at_utc = utc_now_iso()
                            queue_wait_ms = _agent_ingest_duration_ms(enqueued_at_utc, processing_started_at_utc)
                            processing_ms = _agent_ingest_duration_ms(processing_started_at_utc, written_at_utc)
                            end_to_end_ms = _agent_ingest_duration_ms(report_received_at_utc, written_at_utc)
                            _update_agent_ingest_audit_log_row(
                                conn,
                                queue_id=queue_id,
                                status="written",
                                updated_at_utc=written_at_utc,
                                attempt_count=attempt_count,
                                db_written_at_utc=written_at_utc,
                                queue_wait_ms=queue_wait_ms,
                                processing_ms=processing_ms,
                                end_to_end_ms=end_to_end_ms,
                                error_message="",
                            )
                            conn.execute("DELETE FROM agent_ingest_queue WHERE id = ?", (queue_id,))
                            conn.commit()
                            _read_cache_invalidate_prefix("dashboard-db-kpis")
                        except Exception as exc:
                            conn.rollback()
                            _agent_ingest_schedule_retry(
                                conn,
                                queue_id=queue_id,
                                attempt_count=attempt_count,
                                error_message=str(exc),
                            )
                            print(f"[agent-ingest-worker] queue_id={queue_id} failed (attempt={attempt_count}): {exc}")
        except Exception as exc:
            print(f"[agent-ingest-worker] loop failure: {exc}")

        if had_work:
            continue

        _agent_ingest_queue_wakeup.wait(AGENT_INGEST_WORKER_IDLE_SECONDS)
        _agent_ingest_queue_wakeup.clear()


def delete_host_card_data(conn: sqlite3.Connection, hostname: str, host_uid: str = "") -> dict[str, int]:
    deleted: dict[str, int] = {
        "muted_alert_rules": 0,
        "heads_up_suppression_rules": 0,
        "alert_debounce": 0,
        "alerts": 0,
        "host_license_type_snapshot": 0,
        "agent_commands": 0,
        "host_settings": 0,
        "host_uid_settings": 0,
        "reports": 0,
    }

    normalized_hostname = str(hostname or "").strip()
    normalized_host_uid = str(host_uid or "").strip()

    if normalized_host_uid:
        host_key_expr = reports_host_key_sql()
        touched_hostnames = {
            str(row[0] or "").strip()
            for row in conn.execute(
                f"SELECT DISTINCT COALESCE(hostname, '') FROM reports WHERE {host_key_expr} = ?",
                (normalized_host_uid,),
            ).fetchall()
            if str(row[0] or "").strip()
        }

        conn.execute(
            f"DELETE FROM reports WHERE {host_key_expr} = ?",
            (normalized_host_uid,),
        )
        row = conn.execute("SELECT changes()").fetchone()
        deleted["reports"] = int(row[0] or 0) if row else 0

        conn.execute("DELETE FROM host_uid_settings WHERE host_uid = ?", (normalized_host_uid,))
        row = conn.execute("SELECT changes()").fetchone()
        deleted["host_uid_settings"] = int(row[0] or 0) if row else 0

        conn.execute("DELETE FROM host_license_type_snapshot WHERE host_uid = ?", (normalized_host_uid,))
        row = conn.execute("SELECT changes()").fetchone()
        deleted["host_license_type_snapshot"] = int(row[0] or 0) if row else 0

        conn.execute("DELETE FROM muted_alert_rules WHERE host_uid = ?", (normalized_host_uid,))
        row = conn.execute("SELECT changes()").fetchone()
        deleted["muted_alert_rules"] += int(row[0] or 0) if row else 0

        conn.execute("DELETE FROM heads_up_suppression_rules WHERE host_uid = ?", (normalized_host_uid,))
        row = conn.execute("SELECT changes()").fetchone()
        deleted["heads_up_suppression_rules"] += int(row[0] or 0) if row else 0

        conn.execute("DELETE FROM alert_debounce WHERE host_uid = ?", (normalized_host_uid,))
        row = conn.execute("SELECT changes()").fetchone()
        deleted["alert_debounce"] += int(row[0] or 0) if row else 0

        conn.execute(
            "DELETE FROM alerts WHERE COALESCE(NULLIF(host_uid, ''), hostname) = ?",
            (normalized_host_uid,),
        )
        row = conn.execute("SELECT changes()").fetchone()
        deleted["alerts"] += int(row[0] or 0) if row else 0

        # Only clear hostname-scoped data when no reports for that hostname remain.
        for touched_hostname in touched_hostnames:
            remaining = conn.execute(
                "SELECT COUNT(*) FROM reports WHERE hostname = ?",
                (touched_hostname,),
            ).fetchone()
            remaining_count = int((remaining[0] if remaining else 0) or 0)
            if remaining_count > 0:
                continue

            for table_name in ("muted_alert_rules", "heads_up_suppression_rules", "alert_debounce", "alerts", "host_license_type_snapshot", "agent_commands", "host_settings"):
                conn.execute(f"DELETE FROM {table_name} WHERE hostname = ?", (touched_hostname,))
                row = conn.execute("SELECT changes()").fetchone()
                deleted[table_name] += int(row[0] or 0) if row else 0

        return deleted

    cleanup_plan = [
        ("muted_alert_rules", "hostname = ?"),
        ("heads_up_suppression_rules", "hostname = ?"),
        ("alert_debounce", "hostname = ?"),
        ("alerts", "hostname = ?"),
        ("host_license_type_snapshot", "hostname = ?"),
        ("agent_commands", "hostname = ?"),
        ("host_settings", "hostname = ?"),
        ("reports", "hostname = ?"),
    ]

    for table_name, where_clause in cleanup_plan:
        conn.execute(
            f"DELETE FROM {table_name} WHERE {where_clause}",
            (normalized_hostname,),
        )
        row = conn.execute("SELECT changes()").fetchone()
        deleted[table_name] = int(row[0] or 0) if row else 0

    return deleted


def effective_display_name(payload: dict, override_value: str, hostname: str) -> str:
    if override_value:
        return override_value

    payload_value = str(payload.get("display_name", "")).strip()
    if payload_value:
        return payload_value
    return hostname


def evaluate_severity(used_percent: float) -> str:
    if used_percent >= CRITICAL_THRESHOLD_PERCENT:
        return "critical"
    if used_percent >= WARNING_THRESHOLD_PERCENT:
        return "warning"
    return "ok"


def update_alerts_for_report(conn: sqlite3.Connection, hostname: str, host_uid: str, report_id: int, filesystems: list, alarm_settings: dict) -> None:
    now_utc = utc_now_iso()
    alert_key = alert_host_key(hostname, host_uid)
    _resolve_cross_identity_open_alerts(
        conn,
        hostname=hostname,
        canonical_host_uid=host_uid,
        now_utc=now_utc,
        report_id=report_id,
    )
    mountpoints_seen = set()
    blacklist_patterns = get_filesystem_blacklist_pattern_strings(conn)
    hidden_mountpoint_keys = {
        normalize_mountpoint_key(str(row[0] or ""))
        for row in conn.execute(
            """
            SELECT DISTINCT mountpoint
            FROM filesystem_visibility
                        WHERE host_uid = ?
              AND section IN ('analysis', 'fs-focus', 'critical-trends')
            """,
                        (alert_key,),
        ).fetchall()
        if str(row[0] or "").strip()
    }
    warning_hits_required = max(1, int(alarm_settings.get("warning_consecutive_hits", 2)))
    warning_window_minutes = max(1, int(alarm_settings.get("warning_window_minutes", 15)))
    critical_trigger_immediate = bool(alarm_settings.get("critical_trigger_immediate", True))
    display_name = get_display_name_override(conn, hostname, host_uid) or hostname

    for fs in filesystems:
        if not isinstance(fs, dict):
            continue

        mountpoint = str(fs.get("mountpoint", "")).strip()
        if not mountpoint:
            continue

        mountpoint_key = normalize_mountpoint_key(mountpoint)
        if mountpoint_key in hidden_mountpoint_keys:
            suppressed_open = conn.execute(
                "SELECT id FROM alerts WHERE COALESCE(NULLIF(host_uid, ''), hostname) = ? AND mountpoint = ? AND status = 'open'",
                (alert_key, mountpoint),
            ).fetchone()
            if suppressed_open:
                conn.execute(
                    "UPDATE alerts SET status = 'resolved', resolved_at_utc = ?, last_seen_at_utc = ? WHERE id = ?",
                    (now_utc, now_utc, suppressed_open[0]),
                )
            conn.execute("DELETE FROM alert_debounce WHERE host_uid = ? AND mountpoint = ?", (alert_key, mountpoint))
            continue

        if is_filesystem_blacklisted_by_patterns(mountpoint, blacklist_patterns):
            blacklisted_open = conn.execute(
                "SELECT id FROM alerts WHERE COALESCE(NULLIF(host_uid, ''), hostname) = ? AND mountpoint = ? AND status = 'open'",
                (alert_key, mountpoint),
            ).fetchone()
            if blacklisted_open:
                conn.execute(
                    "UPDATE alerts SET status = 'resolved', resolved_at_utc = ?, last_seen_at_utc = ? WHERE id = ?",
                    (now_utc, now_utc, blacklisted_open[0]),
                )
            conn.execute("DELETE FROM alert_debounce WHERE host_uid = ? AND mountpoint = ?", (alert_key, mountpoint))
            continue

        mountpoints_seen.add(mountpoint)
        if is_alert_muted(conn, alert_key, mountpoint):
            muted_open = conn.execute(
                "SELECT id FROM alerts WHERE COALESCE(NULLIF(host_uid, ''), hostname) = ? AND mountpoint = ? AND status = 'open'",
                (alert_key, mountpoint),
            ).fetchone()
            if muted_open:
                conn.execute(
                    "UPDATE alerts SET status = 'resolved', resolved_at_utc = ?, last_seen_at_utc = ? WHERE id = ?",
                    (now_utc, now_utc, muted_open[0]),
                )
            conn.execute("DELETE FROM alert_debounce WHERE host_uid = ? AND mountpoint = ?", (alert_key, mountpoint))
            continue
        try:
            used_percent = float(fs.get("used_percent"))
        except (TypeError, ValueError):
            continue

        warning_threshold = float(alarm_settings.get("warning_threshold_percent", WARNING_THRESHOLD_PERCENT))
        critical_threshold = float(alarm_settings.get("critical_threshold_percent", CRITICAL_THRESHOLD_PERCENT))
        severity = evaluate_severity_for_thresholds(used_percent, warning_threshold, critical_threshold)
        alert_started = False

        if severity == "critical" and critical_trigger_immediate:
            alert_started = True
        elif severity in {"warning", "critical"}:
            debounce_row = conn.execute(
                """
                SELECT first_seen_at_utc, last_seen_at_utc, hit_count
                FROM alert_debounce
                WHERE host_uid = ? AND mountpoint = ?
                """,
                (alert_key, mountpoint),
            ).fetchone()

            if debounce_row:
                try:
                    last_seen_dt = datetime.strptime(str(debounce_row[1]), "%Y-%m-%dT%H:%M:%SZ").replace(tzinfo=timezone.utc)
                    now_dt = datetime.strptime(now_utc, "%Y-%m-%dT%H:%M:%SZ").replace(tzinfo=timezone.utc)
                    within_window = (now_dt - last_seen_dt) <= timedelta(minutes=warning_window_minutes)
                except ValueError:
                    within_window = False

                next_hit_count = int(debounce_row[2] or 0) + 1 if within_window else 1
                first_seen = str(debounce_row[0]) if within_window else now_utc
            else:
                next_hit_count = 1
                first_seen = now_utc

            conn.execute(
                """
                INSERT INTO alert_debounce (
                    host_uid, hostname, mountpoint, first_seen_at_utc, last_seen_at_utc,
                    hit_count, last_used_percent, last_severity
                )
                VALUES (?, ?, ?, ?, ?, ?, ?, ?)
                ON CONFLICT(host_uid, mountpoint) DO UPDATE SET
                    hostname = excluded.hostname,
                    first_seen_at_utc = excluded.first_seen_at_utc,
                    last_seen_at_utc = excluded.last_seen_at_utc,
                    hit_count = excluded.hit_count,
                    last_used_percent = excluded.last_used_percent,
                    last_severity = excluded.last_severity
                """,
                (alert_key, hostname, mountpoint, first_seen, now_utc, next_hit_count, used_percent, severity),
            )

            alert_started = next_hit_count >= warning_hits_required

        open_alert = conn.execute(
            """
            SELECT id, severity, created_at_utc
            FROM alerts
            WHERE COALESCE(NULLIF(host_uid, ''), hostname) = ? AND mountpoint = ? AND status = 'open'
            ORDER BY id DESC
            LIMIT 1
            """,
            (alert_key, mountpoint),
        ).fetchone()

        if severity == "ok":
            if not _should_resolve_alert_for_usage(used_percent, warning_threshold, critical_threshold):
                continue
            conn.execute(
                "DELETE FROM alert_debounce WHERE host_uid = ? AND mountpoint = ?",
                (alert_key, mountpoint),
            )
            if open_alert:
                conn.execute(
                    """
                    UPDATE alerts
                    SET status = 'resolved', resolved_at_utc = ?, last_seen_at_utc = ?, report_id = ?
                    WHERE id = ?
                    """,
                    (now_utc, now_utc, report_id, open_alert[0]),
                )
                open_minutes = _alert_open_duration_minutes(str(open_alert[2] or ""), now_utc)
                should_send_resolve_mail = (
                    ALERT_RESOLVE_MAIL_MIN_OPEN_MINUTES <= 0
                    or open_minutes is None
                    or open_minutes >= ALERT_RESOLVE_MAIL_MIN_OPEN_MINUTES
                )
                if should_send_resolve_mail:
                    resolve_severity = str(open_alert[1] or "warning")
                    maybe_send_alert_message(
                        alarm_settings,
                        "resolved",
                        hostname,
                        alert_key,
                        mountpoint,
                        resolve_severity,
                        used_percent,
                        conn=conn,
                        display_name=display_name,
                        alert_id=int(open_alert[0] or 0),
                    )
            continue

        if not open_alert and not alert_started:
            continue

        conn.execute(
            "DELETE FROM alert_debounce WHERE host_uid = ? AND mountpoint = ?",
            (alert_key, mountpoint),
        )

        if not open_alert:
            conn.execute(
                """
                INSERT INTO alerts (
                    hostname, host_uid, mountpoint, severity, used_percent, status,
                    created_at_utc, last_seen_at_utc, resolved_at_utc, report_id
                )
                VALUES (?, ?, ?, ?, ?, 'open', ?, ?, NULL, ?)
                """,
                (hostname, alert_key, mountpoint, severity, used_percent, now_utc, now_utc, report_id),
            )
            new_alert_id = int(conn.execute("SELECT last_insert_rowid()").fetchone()[0] or 0)
            maybe_send_alert_message(
                alarm_settings,
                "opened",
                hostname,
                alert_key,
                mountpoint,
                severity,
                used_percent,
                conn=conn,
                display_name=display_name,
                alert_id=new_alert_id,
            )
            continue

        previous_severity = str(open_alert[1] or "warning")

        conn.execute(
            """
            UPDATE alerts
            SET severity = ?, last_seen_at_utc = ?, report_id = ?
            WHERE id = ?
            """,
            (severity, now_utc, report_id, open_alert[0]),
        )

        if previous_severity != "critical" and severity == "critical":
            maybe_send_alert_message(
                alarm_settings,
                "escalated",
                hostname,
                alert_key,
                mountpoint,
                severity,
                used_percent,
                conn=conn,
                display_name=display_name,
                alert_id=int(open_alert[0] or 0),
            )

    if mountpoints_seen:
        placeholders = ",".join("?" for _ in mountpoints_seen)
        conn.execute(
            f"DELETE FROM alert_debounce WHERE host_uid = ? AND mountpoint NOT IN ({placeholders})",
            (alert_key, *sorted(mountpoints_seen)),
        )
        if not _report_filesystems_look_incomplete(conn, hostname, host_uid, report_id, mountpoints_seen):
            conn.execute(
                f"""
                UPDATE alerts
                SET status = 'resolved', resolved_at_utc = ?, last_seen_at_utc = ?, report_id = ?
                WHERE COALESCE(NULLIF(host_uid, ''), hostname) = ?
                  AND status = 'open'
                  AND mountpoint NOT IN ({placeholders})
                """,
                (now_utc, now_utc, report_id, alert_key, *sorted(mountpoints_seen)),
            )
    else:
        conn.execute("DELETE FROM alert_debounce WHERE host_uid = ?", (alert_key,))


class MonitoringHandler(BaseHTTPRequestHandler):
    server_version = "MonitoringReceiver/0.1"

    def _swagger_ui_html(self) -> str:
        return """<!doctype html>
<html lang=\"en\">
    <head>
        <meta charset=\"utf-8\">
        <meta name=\"viewport\" content=\"width=device-width, initial-scale=1\">
        <title>Monitoring API Docs</title>
        <link rel=\"stylesheet\" href=\"https://unpkg.com/swagger-ui-dist@5/swagger-ui.css\">
        <style>
            html, body {
                margin: 0;
                padding: 0;
                background: #f8fafc;
            }
            #swagger-ui {
                max-width: 1200px;
                margin: 0 auto;
            }
        </style>
    </head>
    <body>
        <div id=\"swagger-ui\"></div>
        <script src=\"https://unpkg.com/swagger-ui-dist@5/swagger-ui-bundle.js\"></script>
        <script>
            window.ui = SwaggerUIBundle({
                url: '/openapi.yaml',
                dom_id: '#swagger-ui',
                deepLinking: true,
                presets: [SwaggerUIBundle.presets.apis],
                layout: 'BaseLayout'
            });
        </script>
    </body>
</html>
"""

    def _send_json(self, status: int, payload: dict, extra_headers: dict[str, str] | None = None) -> None:
        body = json.dumps(payload).encode("utf-8")
        self.send_response(status)
        self.send_header("Content-Type", "application/json")
        self.send_header("Content-Length", str(len(body)))
        if extra_headers:
            for key, value in extra_headers.items():
                self.send_header(key, value)
        self.end_headers()
        self.wfile.write(body)

    def _send_html(self, status: int, html: str, extra_headers: dict[str, str] | None = None) -> None:
        body = html.encode("utf-8")
        self.send_response(status)
        self.send_header("Content-Type", "text/html; charset=utf-8")
        self.send_header("Content-Length", str(len(body)))
        if extra_headers:
            for key, value in extra_headers.items():
                self.send_header(key, value)
        self.end_headers()
        self.wfile.write(body)

    def _send_file(
        self,
        path: Path,
        content_type: str,
        extra_headers: dict[str, str] | None = None,
    ) -> bool:
        if not path.exists() or not path.is_file():
            self.send_error(HTTPStatus.NOT_FOUND, "File not found")
            return False

        try:
            content_length = path.stat().st_size
            self.send_response(HTTPStatus.OK)
            self.send_header("Content-Type", content_type)
            self.send_header("Content-Length", str(content_length))
            if extra_headers:
                for key, value in extra_headers.items():
                    self.send_header(key, value)
            self.end_headers()

            with path.open("rb") as handle:
                while True:
                    chunk = handle.read(1024 * 1024)
                    if not chunk:
                        break
                    self.wfile.write(chunk)
            return True
        except OSError:
            return False

    @staticmethod
    def _docs_content_type(path: Path) -> str:
        suffix = path.suffix.lower()
        return {
            ".html": "text/html; charset=utf-8",
            ".css": "text/css; charset=utf-8",
            ".js": "application/javascript; charset=utf-8",
            ".json": "application/json; charset=utf-8",
            ".png": "image/png",
            ".jpg": "image/jpeg",
            ".jpeg": "image/jpeg",
            ".svg": "image/svg+xml",
            ".md": "text/markdown; charset=utf-8",
            ".yaml": "application/yaml; charset=utf-8",
            ".yml": "application/yaml; charset=utf-8",
        }.get(suffix, "application/octet-stream")

    def _try_send_docs(self, request_path: str) -> bool:
        """Serve repository documentation under /docs/. Returns True if handled."""
        normalized = request_path.rstrip("/") or "/"
        doc_aliases = {
            "/docs/onboarding-handbuch": DOCS_DIR / "onboarding-kollegen-handbuch.html",
            "/docs/onboarding-kollegen-handbuch": DOCS_DIR / "onboarding-kollegen-handbuch.html",
            "/docs/handbuch-agent-notizbuch": DOCS_DIR / "handbuch-agent-notizbuch.html",
            "/docs/agent-notizbuch": DOCS_DIR / "handbuch-agent-notizbuch.html",
            "/docs/agent-deployment-guide": REPO_ROOT / "agent-deployment-guide.html",
        }
        if normalized in doc_aliases:
            self._send_file(
                doc_aliases[normalized],
                self._docs_content_type(doc_aliases[normalized]),
                extra_headers={"Cache-Control": "no-store"},
            )
            return True

        if normalized in {"/docs/processes", "/docs/processes/index.html"}:
            index_path = DOCS_PROCESSES_DIR / "index.html"
            if index_path.is_file():
                self._send_file(index_path, "text/html; charset=utf-8", extra_headers={"Cache-Control": "no-store"})
                return True
            self.send_error(HTTPStatus.NOT_FOUND, "Not found")
            return True

        rel_raw = ""
        base_dir: Path | None = None
        if normalized.startswith("/docs/assets/"):
            rel_raw = normalized[len("/docs/assets/") :].strip("/")
            base_dir = DOCS_ASSETS_DIR
        elif normalized.startswith("/docs/processes/"):
            rel_raw = normalized[len("/docs/processes/") :].strip("/")
            base_dir = DOCS_PROCESSES_DIR

        if not base_dir or not rel_raw:
            return False

        rel_path = Path(rel_raw)
        if rel_path.is_absolute() or ".." in rel_path.parts:
            self.send_error(HTTPStatus.BAD_REQUEST, "Invalid path")
            return True

        file_path = base_dir / rel_path
        if not (file_path.exists() and file_path.is_file()):
            self.send_error(HTTPStatus.NOT_FOUND, "Not found")
            return True

        self._send_file(
            file_path,
            self._docs_content_type(file_path),
            extra_headers={"Cache-Control": "no-store"},
        )
        return True

    def _send_index_with_asset_version(self) -> None:
        path = STATIC_DIR / "index.html"
        if not path.exists() or not path.is_file():
            self.send_error(HTTPStatus.NOT_FOUND, "File not found")
            return

        html = path.read_text(encoding="utf-8")
        html = html.replace("__ASSET_VERSION__", read_build_version())
        content = html.encode("utf-8")
        self.send_response(HTTPStatus.OK)
        self.send_header("Content-Type", "text/html; charset=utf-8")
        self.send_header("Content-Length", str(len(content)))
        self.send_header("Cache-Control", "no-store, no-cache, must-revalidate, max-age=0")
        self.send_header("Pragma", "no-cache")
        self.send_header("Expires", "0")
        self.end_headers()
        self.wfile.write(content)

    def _send_html_with_asset_version(self, path: Path) -> None:
        if not path.exists() or not path.is_file():
            self.send_error(HTTPStatus.NOT_FOUND, "File not found")
            return

        html = path.read_text(encoding="utf-8")
        html = html.replace("__ASSET_VERSION__", read_build_version())
        content = html.encode("utf-8")
        self.send_response(HTTPStatus.OK)
        self.send_header("Content-Type", "text/html; charset=utf-8")
        self.send_header("Content-Length", str(len(content)))
        self.send_header("Cache-Control", "no-store, no-cache, must-revalidate, max-age=0")
        self.send_header("Pragma", "no-cache")
        self.send_header("Expires", "0")
        self.end_headers()
        self.wfile.write(content)

    def _unauthorized_if_needed(self, hostname: str = "") -> bool:
        if not API_KEY:
            return False

        request_key = self.headers.get("X-Api-Key", "")
        if request_key == API_KEY:
            return False

        if not request_key and hostname and API_KEY_GRACE_ALLOW_KNOWN_HOSTS:
            with sqlite3.connect(DB_PATH) as conn:
                if is_known_hostname(conn, hostname):
                    return False

        if request_key != API_KEY:
            self._send_json(HTTPStatus.UNAUTHORIZED, {"error": "invalid api key"})
            return True
        return False

    def _request_is_https(self) -> bool:
        scheme = (self.headers.get("X-Forwarded-Proto", "") or "").split(",")[0].strip().lower()
        if scheme == "https":
            return True
        if self.headers.get("X-Forwarded-Ssl", "").lower() in {"on", "1", "true", "yes"}:
            return True
        return False

    def _web_session_set_cookie_header(self, token: str) -> str:
        parts = [f"{WEB_SESSION_COOKIE}={token}", "Path=/", "HttpOnly", "SameSite=Lax"]
        if self._request_is_https():
            parts.append("Secure")
        return "; ".join(parts)

    def _web_session_clear_cookie_header(self) -> str:
        parts = [f"{WEB_SESSION_COOKIE}=", "Path=/", "HttpOnly", "SameSite=Lax", "Max-Age=0"]
        if self._request_is_https():
            parts.append("Secure")
        return "; ".join(parts)

    def _cookie_value(self, cookie_name: str) -> str:
        cookie_header = self.headers.get("Cookie", "")
        for part in cookie_header.split(";"):
            name, _, value = part.strip().partition("=")
            if name == cookie_name:
                return value
        return ""

    def _web_session_username(self) -> str:
        token = self._cookie_value(WEB_SESSION_COOKIE)
        if not token:
            return ""

        row = None
        try:
            with sqlite_connect_interactive() as conn:
                _purge_expired_web_sessions(conn)
                row = conn.execute(
                    """
                    SELECT s.username
                    FROM web_sessions s
                    JOIN web_users u ON u.username = s.username
                    WHERE s.session_token = ? AND COALESCE(u.is_disabled, 0) = 0
                    """,
                    (token,),
                ).fetchone()
                if row:
                    now_iso = utc_now_iso()
                    expires_iso = web_session_expires_iso()
                    conn.execute(
                        "UPDATE web_sessions SET last_activity_at_utc = ?, expires_at_utc = ? WHERE session_token = ?",
                        (now_iso, expires_iso, token),
                    )
                conn.commit()
        except sqlite3.OperationalError:
            return ""

        if not row:
            return ""
        return str(row[0] or "")

    def _require_web_session(self) -> str:
        username = self._web_session_username()
        if not username:
            self._send_json(HTTPStatus.UNAUTHORIZED, {"error": "login required"})
            return ""
        return username

    def _require_admin_session(self) -> str:
        username = self._require_web_session()
        if not username:
            return ""
        try:
            with sqlite_connect_interactive() as conn:
                user = get_web_user(conn, username)
        except sqlite3.OperationalError as exc:
            if _sqlite_operational_error_is_lock(exc):
                self._send_json(
                    HTTPStatus.SERVICE_UNAVAILABLE,
                    {"error": "Datenbank kurz gesperrt. Bitte in wenigen Sekunden erneut versuchen."},
                )
                return ""
            raise
        if not user or not user.get("is_admin"):
            self._send_json(HTTPStatus.FORBIDDEN, {"error": "admin required"})
            return ""
        return username

    def _external_base_url(self) -> str:
        scheme = (self.headers.get("X-Forwarded-Proto", "") or "").split(",")[0].strip()
        host = (self.headers.get("X-Forwarded-Host", "") or "").split(",")[0].strip()
        if not scheme:
            scheme = "https" if self.headers.get("X-Forwarded-Ssl", "").lower() == "on" else "http"
        if not host:
            host = (self.headers.get("Host", "") or "").strip() or "localhost"
        return f"{scheme}://{host}"

    def _request_client_ip(self) -> str:
        forwarded_for = (self.headers.get("X-Forwarded-For", "") or "").split(",")[0].strip()
        if forwarded_for:
            return forwarded_for
        real_ip = (self.headers.get("X-Real-IP", "") or "").strip()
        if real_ip:
            return real_ip
        return str((self.client_address or [""])[0] or "")

    def _absolute_url(self, path: str) -> str:
        return f"{self._external_base_url()}{path}"

    def _oauth_callback_html(self, redirect_path: str) -> str:
        target = json.dumps(redirect_path)
        return (
            "<!doctype html><html lang=\"de\"><head><meta charset=\"utf-8\">"
            "<meta name=\"viewport\" content=\"width=device-width, initial-scale=1\">"
            "<title>OAuth Verbindung</title></head><body>"
            "<p>Weiterleitung...</p>"
            f"<script>window.location.replace({target});</script>"
            f"<noscript><meta http-equiv=\"refresh\" content=\"0;url={parse.quote(redirect_path, safe='/:?=&%')}\"></noscript>"
            "</body></html>"
        )

    def do_GET(self) -> None:
        _flush_due_read_cache_invalidations()
        _flush_due_identity_maps_cache_invalidation()
        parsed = urlparse(self.path)

        if parsed.path == "/oauth/microsoft/callback":
            query = parse_qs(parsed.query)
            state_token = str(query.get("state", [""])[0] or "").strip()
            code = str(query.get("code", [""])[0] or "").strip()
            remote_error = str(query.get("error", [""])[0] or "").strip()
            remote_error_description = str(query.get("error_description", [""])[0] or "").strip()

            if not state_token:
                self._send_html(HTTPStatus.BAD_REQUEST, self._oauth_callback_html("/?oauth_status=error&oauth_message=missing_state"))
                return

            with sqlite3.connect(DB_PATH) as conn:
                state_row = consume_oauth_state(conn, state_token, MICROSOFT_PROVIDER)
                conn.commit()

            if not state_row:
                self._send_html(HTTPStatus.BAD_REQUEST, self._oauth_callback_html("/?oauth_status=error&oauth_message=invalid_state"))
                return

            redirect_path = state_row["redirect_path"]
            if remote_error:
                message = remote_error_description or remote_error
                target = append_query_param(append_query_param(redirect_path, "oauth_status", "error"), "oauth_message", message)
                self._send_html(HTTPStatus.OK, self._oauth_callback_html(target))
                return

            if not code:
                target = append_query_param(append_query_param(redirect_path, "oauth_status", "error"), "oauth_message", "missing_code")
                self._send_html(HTTPStatus.BAD_REQUEST, self._oauth_callback_html(target))
                return

            with sqlite3.connect(DB_PATH) as conn:
                oauth_settings = get_oauth_settings(conn)

            redirect_uri = self._absolute_url("/oauth/microsoft/callback")
            ok, token_payload, raw = exchange_microsoft_code_for_tokens(oauth_settings, code, redirect_uri)
            if not ok:
                target = append_query_param(append_query_param(redirect_path, "oauth_status", "error"), "oauth_message", raw or token_payload.get("error_description", "oauth_exchange_failed"))
                self._send_html(HTTPStatus.OK, self._oauth_callback_html(target))
                return

            with sqlite3.connect(DB_PATH) as conn:
                upsert_oauth_connection(conn, state_row["username"], MICROSOFT_PROVIDER, token_payload)
                conn.commit()

            target = append_query_param(redirect_path, "oauth_status", "success")
            self._send_html(HTTPStatus.OK, self._oauth_callback_html(target))
            return

        if parsed.path == "/health":
            self._send_json(HTTPStatus.OK, {"status": "ok", "time_utc": utc_now_iso()})
            return

        if parsed.path == "/api/v1/session":
            token = self._cookie_value(WEB_SESSION_COOKIE)
            username = ""
            is_admin = False
            display_name = ""
            expires_at_utc = ""
            try:
                with sqlite_connect_interactive() as conn:
                    _purge_expired_web_sessions(conn)
                    if token:
                        row = conn.execute(
                            """
                            SELECT s.username, COALESCE(u.is_disabled, 0), COALESCE(u.display_name, ''), s.expires_at_utc
                            FROM web_sessions s
                            JOIN web_users u ON u.username = s.username
                            WHERE s.session_token = ? AND COALESCE(u.is_disabled, 0) = 0
                            """,
                            (token,),
                        ).fetchone()
                        if row:
                            username = str(row[0] or "")
                            display_name = str(row[2] or "")
                            expires_at_utc = str(row[3] or "")
                            user = get_web_user(conn, username)
                            is_admin = bool(user and user.get("is_admin"))
                            now_iso = utc_now_iso()
                            expires_iso = web_session_expires_iso()
                            conn.execute(
                                "UPDATE web_sessions SET last_activity_at_utc = ?, expires_at_utc = ? WHERE session_token = ?",
                                (now_iso, expires_iso, token),
                            )
                            expires_at_utc = expires_iso
                    conn.commit()
            except sqlite3.OperationalError:
                username = ""
            self._send_json(
                HTTPStatus.OK,
                {
                    "authenticated": bool(username),
                    "username": username,
                    "display_name": display_name,
                    "is_admin": is_admin,
                    "expires_at_utc": expires_at_utc,
                    "inactivity_timeout_minutes": WEB_SESSION_INACTIVITY_MINUTES,
                },
            )
            return

        if parsed.path == "/api/v1/agent-commands":
            query = parse_qs(parsed.query)
            hostname = query.get("hostname", [""])[0].strip()
            agent_id = query.get("agent_id", [""])[0].strip()
            limit = parse_int(query, "limit", default=10, min_value=1, max_value=100)

            if not hostname:
                self._send_json(HTTPStatus.BAD_REQUEST, {"error": "hostname query parameter is required"})
                return

            if self._unauthorized_if_needed(hostname):
                return

            with sqlite3.connect(DB_PATH) as conn:
                expire_old_agent_commands(conn)
                rows = conn.execute(
                    """
                    SELECT id, created_at_utc, command_type, command_payload_json, expires_at_utc
                    FROM agent_commands
                    WHERE hostname = ? AND status = 'pending' AND expires_at_utc > ?
                    ORDER BY id ASC
                    LIMIT ?
                    """,
                    (hostname, utc_now_iso(), limit),
                ).fetchall()
                conn.commit()

            commands = []
            for row in rows:
                payload = parse_payload_json(str(row[3] or "{}"))
                commands.append(
                    {
                        "id": int(row[0]),
                        "created_at_utc": str(row[1] or ""),
                        "command_type": str(row[2] or ""),
                        "command_payload": payload,
                        "expires_at_utc": str(row[4] or ""),
                    }
                )

            self._send_json(
                HTTPStatus.OK,
                {
                    "hostname": hostname,
                    "agent_id": agent_id,
                    "count": len(commands),
                    "commands": commands,
                },
            )
            return

        if parsed.path.startswith("/api/v1/"):
            if parsed.path != "/api/v1/agent-commands" and parsed.path != "/api/v1/host-update-log":
                if not self._require_web_session():
                    return

        if parsed.path == "/api/v1/user-profile":
            username = self._web_session_username()
            with sqlite3.connect(DB_PATH) as conn:
                payload = current_user_payload(conn, username)
            self._send_json(HTTPStatus.OK, payload)
            return

        if parsed.path == "/api/v1/user-preferences":
            username = self._web_session_username()
            with sqlite3.connect(DB_PATH) as conn:
                payload = get_user_preferences(conn, username)
            self._send_json(HTTPStatus.OK, payload)
            return

        if parsed.path == "/api/v1/host-interest-targets":
            endpoint_timer = _new_endpoint_timer("/api/v1/host-interest-targets")
            cache_key = "host-interest-targets:v1"
            cached_data = _read_cache_get(cache_key)
            if isinstance(cached_data, dict):
                self._send_json(HTTPStatus.OK, cached_data)
                _mark_endpoint_timer(endpoint_timer, "cache-hit+send")
                _finish_endpoint_timer(endpoint_timer, meta="cache=hit")
                return
            with sqlite_connect_read() as conn:
                hosts = get_host_interest_targets(conn)
            data = {"hosts": hosts, "total_hosts": len(hosts)}
            _read_cache_set(cache_key, data, ttl_seconds=300)
            self._send_json(HTTPStatus.OK, data)
            _mark_endpoint_timer(endpoint_timer, "db+send")
            _finish_endpoint_timer(endpoint_timer, meta=f"cache=miss total={len(hosts)}")
            return

        if parsed.path == "/api/v1/session/refresh":
            username = self._web_session_username()
            if not username:
                self._send_json(HTTPStatus.UNAUTHORIZED, {"error": "Not authenticated"})
                return
            session_token = self.headers.get("Authorization", "").replace("Bearer ", "").strip()
            if not session_token:
                session_token = self._cookie_value(WEB_SESSION_COOKIE)
            if not session_token:
                self._send_json(HTTPStatus.UNAUTHORIZED, {"error": "No session token"})
                return
            now_iso = utc_now_iso()
            expires_iso = web_session_expires_iso()
            with sqlite3.connect(DB_PATH) as conn:
                result = conn.execute(
                    "UPDATE web_sessions SET last_activity_at_utc = ?, expires_at_utc = ? WHERE session_token = ?",
                    (now_iso, expires_iso, session_token),
                )
                conn.commit()
            if result.rowcount <= 0:
                self._send_json(HTTPStatus.UNAUTHORIZED, {"error": "Session not found"})
                return
            display_name = ""
            with sqlite3.connect(DB_PATH) as conn:
                user = get_web_user(conn, username)
                display_name = str((user or {}).get("display_name", "") or "")
            self._send_json(
                HTTPStatus.OK,
                {
                    "username": username,
                    "display_name": display_name,
                    "expires_at_utc": expires_iso,
                    "inactivity_timeout_minutes": WEB_SESSION_INACTIVITY_MINUTES,
                },
            )
            return

