        if path == "/api/v1/push-test":
            username = self._web_session_username()
            if not web_push_is_configured():
                self._send_json(
                    HTTPStatus.BAD_REQUEST,
                    {
                        "error": "web push not configured",
                        "supported": bool(_WEB_PUSH_AVAILABLE),
                        "configured": web_push_is_configured(),
                    },
                )
                return

            content_length = int(self.headers.get("Content-Length", "0"))
            raw_body = self.rfile.read(content_length) if content_length > 0 else b"{}"
            try:
                payload = json.loads(raw_body)
            except json.JSONDecodeError:
                self._send_json(HTTPStatus.BAD_REQUEST, {"error": "invalid json"})
                return

            custom_title = ""
            custom_body = ""
            custom_url = "/mobile/alerts"
            if isinstance(payload, dict):
                custom_title = str(payload.get("title", "") or "").strip()
                custom_body = str(payload.get("body", "") or "").strip()
                custom_url = str(payload.get("url", "") or "").strip() or custom_url

            if custom_title or custom_body:
                title = custom_title or "🚨 ALERT OPEN"
                body = custom_body or ""
            else:
                title, body = build_instant_alert_push_title_body(
                    event_type="opened",
                    severity="warning",
                    used_percent=87.4,
                    customer_label="CT-X Rail Service AG",
                    host_title="CT-X Rail Service",
                    hostname="ctx-rail-prod",
                    mountpoint="/hana/data",
                    username=username,
                )
            push_payload = {
                "title": title,
                "body": body,
                "icon": "/icons/logo.png",
                "badge": "/icons/logo.png",
                "image": "/icons/pwa-icon-512.png",
                "tag": f"push-test:{username}",
                "renotify": True,
                "vibrate": [90, 45, 90],
                "actions": [{"action": "open", "title": "Öffnen"}],
                "data": {"url": custom_url},
            }

            with sqlite3.connect(DB_PATH) as conn:
                rows = conn.execute(
                    """
                    SELECT id, endpoint, p256dh, auth
                    FROM web_push_subscriptions
                    WHERE username = ? AND is_active = 1
                    ORDER BY updated_at_utc DESC
                    """,
                    (username,),
                ).fetchall()
                if not rows:
                    self._send_json(HTTPStatus.BAD_REQUEST, {"error": "no active push subscriptions"})
                    return

                now_utc = utc_now_iso()
                success = 0
                failed = 0
                for row in rows:
                    sub_id = int(row[0] or 0)
                    ok, details, deactivate = _send_web_push_to_subscription(
                        str(row[1] or ""),
                        str(row[2] or ""),
                        str(row[3] or ""),
                        push_payload,
                    )
                    if ok:
                        success += 1
                        conn.execute(
                            """
                            UPDATE web_push_subscriptions
                            SET last_success_at_utc = ?, last_error = '', updated_at_utc = ?
                            WHERE id = ?
                            """,
                            (now_utc, now_utc, sub_id),
                        )
                    else:
                        failed += 1
                        if deactivate:
                            conn.execute(
                                """
                                UPDATE web_push_subscriptions
                                SET is_active = 0, last_error = ?, updated_at_utc = ?
                                WHERE id = ?
                                """,
                                (details[:500], now_utc, sub_id),
                            )
                        else:
                            conn.execute(
                                """
                                UPDATE web_push_subscriptions
                                SET last_error = ?, updated_at_utc = ?
                                WHERE id = ?
                                """,
                                (details[:500], now_utc, sub_id),
                            )
                conn.commit()

            self._send_json(HTTPStatus.OK, {"status": "sent", "success": success, "failed": failed})
            return

