        if path == "/api/v1/host-config-changes/backfill":
            if not self._require_admin_session():
                return
            content_length = int(self.headers.get("Content-Length", "0"))
            raw_body = self.rfile.read(content_length) if content_length > 0 else b"{}"
            try:
                payload = json.loads(raw_body)
            except json.JSONDecodeError:
                self._send_json(HTTPStatus.BAD_REQUEST, {"error": "invalid json"})
                return
            if not isinstance(payload, dict):
                payload = {}

            days = 7
            if "days" in payload:
                try:
                    days = max(1, min(int(payload.get("days", 7)), 30))
                except (TypeError, ValueError):
                    self._send_json(HTTPStatus.BAD_REQUEST, {"error": "days must be an integer between 1 and 30"})
                    return

            run_now = parse_bool(payload.get("run_now"), True)
            async_mode = parse_bool(payload.get("async"), True)
            requested_by = self._web_session_username() or "webclient"

            if async_mode:
                try:
                    with sqlite_connect() as conn:
                        scheduled = schedule_changelog_rebuild_job(
                            conn,
                            requested_by,
                            days=days,
                            scheduled_for_utc=utc_now_iso() if run_now else "",
                            force_rebuild=False,
                            job_mode="backfill",
                        )
                        if run_now:
                            _start_background_changelog_jobs(max_jobs=1)
                        jobs = list_changelog_rebuild_jobs(conn, limit=20)
                        conn.commit()
                except Exception as exc:
                    self._send_json(HTTPStatus.INTERNAL_SERVER_ERROR, {"error": str(exc)})
                    return

                self._send_json(
                    HTTPStatus.OK,
                    {
                        "status": "ok",
                        "message": "Backfill-Job im Hintergrund gestartet (niedrige Priorität)"
                        if run_now
                        else "Backfill-Job geplant",
                        "scheduled": scheduled,
                        "jobs": jobs,
                        "job_mode": "backfill",
                    },
                )
                return

            if not _db_maintenance_lock.acquire(blocking=False):
                self._send_json(
                    HTTPStatus.CONFLICT,
                    {
                        "error": "Wartungsoperation bereits aktiv (Rebuild/Backfill). Bitte nach Abschluss erneut versuchen.",
                        "code": "maintenance_busy",
                    },
                )
                return

            try:
                _apply_background_maintenance_priority()
                with sqlite_connect() as conn:
                    conn.execute(f"PRAGMA busy_timeout = {_maintenance_sqlite_busy_timeout_ms()}")
                    result = run_changelog_backfill_only(conn, days=days)
                    conn.commit()

                self._send_json(
                    HTTPStatus.OK,
                    {
                        "status": "ok",
                        "result": {
                            "config_changes": result.get("config_result", {}),
                            "database_lifecycle": result.get("database_result", {}),
                            "inserted_changes": result.get("inserted_changes", 0),
                            "reports_scanned": result.get("reports_scanned", 0),
                            "inserted_events": result.get("inserted_events", 0),
                        },
                    },
                )
            except sqlite3.OperationalError as e:
                error_text = str(e)
                if "locked" in error_text.lower() or "busy" in error_text.lower():
                    self._send_json(
                        HTTPStatus.CONFLICT,
                        {
                            "error": "Datenbank ist aktuell gesperrt (parallel laufende Schreiboperation). Bitte in 1-2 Minuten erneut versuchen.",
                            "details": error_text,
                            "code": "database_locked",
                        },
                    )
                else:
                    self._send_json(HTTPStatus.INTERNAL_SERVER_ERROR, {"error": f"OperationalError: {error_text}"})
            except Exception as e:
                import traceback
                error_msg = f"{type(e).__name__}: {str(e)}"
                traceback.print_exc()
                self._send_json(HTTPStatus.INTERNAL_SERVER_ERROR, {"error": error_msg})
            finally:
                _db_maintenance_lock.release()
            return



