            probe_token = extract_probe_token(self.headers, body=payload if isinstance(payload, dict) else None)
            if not probe_token:
                self._send_json(HTTPStatus.UNAUTHORIZED, {"error": "missing_probe_token"})
                return
            if isinstance(payload, dict) and ("results" in payload or "results_b64" in payload):
                try:
                    results = decode_probe_push_results(payload)
                except ValueError as exc:
                    self._send_json(HTTPStatus.BAD_REQUEST, {"error": str(exc)})
                    return
                try:
                    with sqlite3.connect(DB_PATH) as conn:
                        push_result = push_probe_results(conn, probe_token, results)
                        conn.commit()
                except Exception as exc:
                    self._send_json(HTTPStatus.INTERNAL_SERVER_ERROR, {"error": str(exc)})
                    return
                if push_result.get("error"):
                    self._send_json(HTTPStatus.UNAUTHORIZED, push_result)
                    return
                self._send_json(HTTPStatus.OK, push_result)
                return
            with sqlite3.connect(DB_PATH) as conn:
                status_code, response_payload = resolve_probe_config(conn, probe_token)
                conn.commit()
            self._send_json(status_code, response_payload)
            return

